/**
 * Speaker Note Generator - Generates speaker notes using OpenAI API based on slide content
 */

/**
 * Shows the Speaker Note sidebar
 */
function showSpeakerNoteSidebar() {
	try {
		const sidebar = createSpeakerNoteSidebar();
		SlidesApp.getUi().showSidebar(sidebar);
	} catch (e) {
		console.error("Error showing Speaker Note sidebar: " + e.message);
		SlidesApp.getUi().alert(
			"Error",
			"Could not open the Speaker Note sidebar: " + e.message,
		);
	}
}

/**
 * Creates the Speaker Note sidebar HTML
 */
function createSpeakerNoteSidebar() {
	return HtmlService.createHtmlOutputFromFile(
		"src/components/speakerNoteSidebar",
	)
		.setTitle("AI Speaker Notes Generator")
		.setWidth(400);
}

/**
 * Gets all text content from the current slide
 * @return {Object} Object containing slide text and metadata
 */
function getCurrentSlideContent() {
	try {
		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();
		const currentPage = selection.getCurrentPage();

		if (
			!currentPage ||
			currentPage.getPageType() !== SlidesApp.PageType.SLIDE
		) {
			throw new Error("Please select a slide first");
		}

		// Convert currentPage to a Slide object
		const currentSlide = currentPage.asSlide();
		const slides = presentation.getSlides();
		const slideNumber = slides.indexOf(currentSlide) + 1;
		const totalSlides = slides.length;

		// Get all shapes and their text content
		const shapes = currentSlide.getShapes();
		const textContent = [];

		shapes.forEach((shape) => {
			try {
				// Check if shape has text
				if (shape.getText && shape.getText().asString().trim() !== "") {
					const text = shape.getText().asString().trim();
					const shapeType = shape.getShapeType().toString();

					textContent.push({
						type: shapeType,
						text: text,
						length: text.length,
					});
				}
			} catch (e) {
				// Skip shapes that don't have text or cause errors
				console.log("Skipping shape due to error: " + e.message);
			}
		});

		// Get tables if any
		const tables = currentSlide.getTables();
		tables.forEach((table, tableIndex) => {
			try {
				const numRows = table.getNumRows();
				const numCols = table.getNumColumns();
				let tableText = `Table ${tableIndex + 1} (${numRows}x${numCols}): `;

				for (let row = 0; row < numRows; row++) {
					for (let col = 0; col < numCols; col++) {
						const cell = table.getCell(row, col);
						const cellText = cell.getText().asString().trim();
						if (cellText) {
							tableText += cellText + " | ";
						}
					}
					tableText += "\n";
				}

				if (tableText.length > 50) {
					// Only add if table has content
					textContent.push({
						type: "TABLE",
						text: tableText.trim(),
						length: tableText.length,
					});
				}
			} catch (e) {
				console.log("Error reading table: " + e.message);
			}
		});

		// Combine all text content
		const allText = textContent.map((item) => item.text).join("\n\n");

		return {
			slideNumber: slideNumber,
			totalSlides: totalSlides,
			textContent: textContent,
			allText: allText,
			hasContent: textContent.length > 0,
			title: currentSlide.getTitle
				? currentSlide.getTitle()
				: "Slide " + slideNumber,
		};
	} catch (e) {
		console.error("Error getting slide content: " + e.message);
		throw new Error("Failed to get slide content: " + e.message);
	}
}

/**
 * Gets the current speaker notes for the slide
 * @return {string} Current speaker notes
 */
function getCurrentSpeakerNotes() {
	try {
		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();
		const currentPage = selection.getCurrentPage();

		if (
			!currentPage ||
			currentPage.getPageType() !== SlidesApp.PageType.SLIDE
		) {
			return "";
		}

		// Convert currentPage to a Slide object
		const slide = currentPage.asSlide();
		const notesPage = slide.getNotesPage();
		const shape = notesPage.getSpeakerNotesShape();

		const notesText = shape ? shape.getText().asString() : "";
		return notesText.trim();
	} catch (e) {
		console.error(`Error getting speaker notes: ${e.message}`);
		return "";
	}
}

/**
 * Generates speaker notes via Groq for the given slide content.
 *
 * SECURITY: the API key is NOT a parameter. It is read server-side from the
 * current user's UserProperties inside callGroq_() (see src/util/aiKey.js).
 * The client never sends the key.
 *
 * @param {string} slideContent - Content from the slide.
 * @param {string} prompt - User prompt/instructions.
 * @return {Object} API response with generated content.
 */
function generateSpeakerNotesAI(slideContent, prompt) {
	if (!slideContent || slideContent.trim() === "") {
		return {
			success: false,
			error: "No slide content found to process",
			generatedText: "",
		};
	}

	const systemMessage =
		"You are a helpful assistant that creates speaker notes for presentations. Generate clear, concise, and helpful speaker notes based on the slide content provided.";

	const userMessage = `Please create speaker notes for this slide content:

SLIDE CONTENT:
${slideContent}

USER INSTRUCTIONS:
${prompt || "Create professional speaker notes that help explain and expand on the slide content."}

Please provide speaker notes that:
1. Explain the key points in more detail
2. Provide context and background information
3. Suggest transitions and speaking points
4. Are natural to read aloud
5. Help the presenter engage with the audience`;

	return callGroq_(systemMessage, userMessage, {
		maxTokens: 1000,
		temperature: 0.7,
	});
}

/**
 * Appends generated text to the speaker notes of the current slide
 * @param {string} textToAppend - Text to append to speaker notes
 * @return {Object} Success status and message
 */
function appendToSpeakerNotes(textToAppend) {
	try {
		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();
		const currentPage = selection.getCurrentPage();

		if (
			!currentPage ||
			currentPage.getPageType() !== SlidesApp.PageType.SLIDE
		) {
			throw new Error("Please select a slide first");
		}

		// Convert currentPage to a Slide object
		const slide = currentPage.asSlide();
		const notesPage = slide.getNotesPage();
		const shape = notesPage.getSpeakerNotesShape();

		if (!shape) {
			throw new Error("Could not access speaker notes shape");
		}

		// Get current notes and append new text
		const currentText = shape.getText().asString();

		// Create new text with proper spacing
		const newText = currentText.trim()
			? `${currentText.trim()}\n\n${textToAppend}`
			: textToAppend;

		// Update the speaker notes
		shape.getText().setText(newText);

		return {
			success: true,
			message: "Speaker notes updated successfully",
		};
	} catch (e) {
		console.error(`Error appending to speaker notes: ${e.message}`);
		return {
			success: false,
			message: `Failed to update speaker notes: ${e.message}`,
		};
	}
}

/**
 * Replaces the speaker notes of the current slide with new text
 * @param {string} newText - New text for speaker notes
 * @return {Object} Success status and message
 */
function replaceSpeakerNotes(newText) {
	try {
		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();
		const currentPage = selection.getCurrentPage();

		if (
			!currentPage ||
			currentPage.getPageType() !== SlidesApp.PageType.SLIDE
		) {
			throw new Error("Please select a slide first");
		}

		// Convert currentPage to a Slide object
		const slide = currentPage.asSlide();
		const notesPage = slide.getNotesPage();
		const shape = notesPage.getSpeakerNotesShape();

		if (!shape) {
			throw new Error("Could not access speaker notes shape");
		}

		// Replace the speaker notes with new text
		shape.getText().setText(newText || "");

		return {
			success: true,
			message: "Speaker notes replaced successfully",
		};
	} catch (e) {
		console.error(`Error replacing speaker notes: ${e.message}`);
		return {
			success: false,
			message: `Failed to replace speaker notes: ${e.message}`,
		};
	}
}

// 🚀 CACHE MANAGEMENT MODULE - Optimized resource caching
/**
 * Centralized cache management for ultra-performance batch processing
 * - Pre-calculated colors and transforms
 * - GUID pool management
 * - Slide property caching
 */

var ULTRA_CACHE = null;

/**
 * Initialize the ultra performance cache
 */
function initializeUltraCache() {
	if (ULTRA_CACHE) return ULTRA_CACHE;

	ULTRA_CACHE = {
		// Pre-calculated RGB colors (avoid repeated hexToRgb calls)
		colors: {
			main: hexToRgb(main_color),
			inactive: hexToRgb('#888888'),
			gray: hexToRgb('#E0E0E0'),
			white: hexToRgb('#FFFFFF'),
			bgColor: hexToRgb('#FFFFFF')
		},
		// Pre-generated GUIDs batch (avoid expensive UUID generation)
		guids: [],
		guidIndex: 0,
		// Reusable objects to reduce memory allocation
		transforms: {
			identity: { scaleX: 1, scaleY: 1, unit: 'PT' },
			rotation90: { scaleX: 0, shearX: -1, shearY: 1, scaleY: 0, unit: 'PT' }
		}
	};

	// Pre-generate 1000 GUIDs
	for (let i = 0; i < 1000; i++) {
		ULTRA_CACHE.guids.push(Utilities.getUuid().replace(/-/g, '').slice(0, 8));
	}

	return ULTRA_CACHE;
}

/**
 * Get next GUID from the pre-generated pool
 */
function getNextGuid() {
	const cache = initializeUltraCache();
	const guid = cache.guids[cache.guidIndex];
	cache.guidIndex = (cache.guidIndex + 1) % cache.guids.length;
	return guid;
}

/**
 * Create optimized slide cache with pre-calculated properties
 */
function createUltraSlideCache(presentation, slides) {
	const width = presentation.getPageWidth();
	const height = presentation.getPageHeight();

	return {
		width, height, totalSlides: slides.length,
		// Pre-calculated positions
		progressBarY: height - progressBarHeight,
		rightFooterX: width,
		centerX: width / 2,
		// Pre-calculated common sizes
		sizes: {
			pageNum: { width: { magnitude: 70, unit: 'PT' }, height: { magnitude: 30, unit: 'PT' } },
			progressBar: { height: { magnitude: progressBarHeight, unit: 'PT' } },
			tabBar: { height: { magnitude: 14, unit: 'PT' } },
			sectionBox: { width: { magnitude: 600, unit: 'PT' }, height: { magnitude: 150, unit: 'PT' } }
		},
		// Slide data with minimal API calls
		slideData: slides.map((slide, idx) => ({
			id: slide.getObjectId(),
			layoutName: idx === 0 ? null : slide.getLayout().getLayoutName(), // Skip first slide
			slide: idx < 2 ? slide : null // Only keep references we actually need
		}))
	};
}

/**
 * Clear cache (for memory management)
 */
function clearUltraCache() {
	ULTRA_CACHE = null;
}

// 🚀 OPTIMIZED INDEX GENERATOR - Ultra-fast batch processing
/**
 * Optimized index slide generation using batch requests
 * Performance: ~100 individual calls → ~4-8 batch requests per item in 1 API call
 * Expected: 3-5x faster for typical presentations
 */
function generateIndexSlide() {
	const presentation = SlidesApp.getActivePresentation();
	const presentationId = presentation.getId();
	let slides = presentation.getSlides();

	Logger.log("🚀 Starting optimized index generation...");
	const startTime = Date.now();

	// Step 0: Batch delete old index slides
	const deleteRequests = [];
	for (let i = slides.length - 1; i >= 0; i--) {
		const slide = slides[i];
		const layout = slide.getLayout();
		const layoutName = layout ? layout.getLayoutName() : "";

		if (layoutName === "TITLE_ONLY") {
			const shapes = slide.getShapes();
			if (shapes.length > 0) {
				const titleText = shapes[0].getText().asString().trim();
				if (titleText === "Index") {
					deleteRequests.push({
						deleteObject: { objectId: slide.getObjectId() },
					});
				}
			}
		}
	}

	// Execute deletion batch if needed
	if (deleteRequests.length > 0) {
		Logger.log(`Deleting ${deleteRequests.length} old index slides...`);
		Slides.Presentations.batchUpdate(
			{ requests: deleteRequests },
			presentationId,
		);
		slides = presentation.getSlides(); // Refresh slides list
	}

	// Step 1: Collect index items efficiently
	const indexItems = generateIndexItemsUltra(slides);

	if (indexItems.length === 0) {
		Logger.log("No slides found for index generation");
		return;
	}

	// Step 2: Create new index slide
	const newSlide = presentation.appendSlide(
		SlidesApp.PredefinedLayout.TITLE_ONLY,
	);
	const indexSlideId = newSlide.getObjectId();

	// Update title immediately (single operation)
	newSlide.getShapes()[0].getText().setText("Index");

	// Step 3: Generate all index items in single batch
	generateIndexItemsBatch(indexItems, indexSlideId, presentationId);

	const elapsed = Date.now() - startTime;
	Logger.log(
		`✅ Ultra-optimized index created in ${elapsed}ms with ${indexItems.length} items`,
	);
}

/**
 * 🚀 Ultra-efficient index items collection
 */
function generateIndexItemsUltra(slides) {
	const indexItems = [];

	slides.forEach((slide, index) => {
		const layout = slide.getLayout();
		const layoutName = layout ? layout.getLayoutName() : "";
		if (layoutName === "SECTION_HEADER") return;

		// Quick title extraction
		const titleText = extractSlideTitle(slide);

		indexItems.push({
			text: `${titleText || "[No title]"}, p${index + 1}`,
			slideId: slide.getObjectId(), // Store ID instead of slide object
			index: index,
		});
	});

	return indexItems;
}

/**
 * Extract slide title efficiently
 */
function extractSlideTitle(slide) {
	const pageElements = slide.getPageElements();

	for (const element of pageElements) {
		if (element.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
			const shape = element.asShape();
			const text = shape.getText().asString().trim();
			if (text.length > 0) {
				return text;
			}
		}
	}
	return "";
}

/**
 * 🚀 Ultra-efficient batch creation of index items
 * Consolidates ~100 individual API calls into 1 batch call
 */
function generateIndexItemsBatch(indexItems, indexSlideId, presentationId) {
	const requests = [];

	// Layout configuration
	const CONFIG = {
		initialLeft: 40,
		initialTop: 90,
		width: 230,
		height: 20,
		spacing: 0,
		itemsPerColumn: 12,
		fontSize: 9,
	};

	// Initialize cache for optimization
	const cache = initializeUltraCache();

	Logger.log(`Generating ${indexItems.length} index items in batch...`);

	indexItems.forEach((item, i) => {
		const column = Math.floor(i / CONFIG.itemsPerColumn);
		const row = i % CONFIG.itemsPerColumn;
		const left = CONFIG.initialLeft + column * CONFIG.width;
		const top = CONFIG.initialTop + row * (CONFIG.height + CONFIG.spacing);

		createIndexItemUltra(
			item,
			i,
			left,
			top,
			CONFIG,
			indexSlideId,
			requests,
			cache,
		);
	});

	// Single mega batch update
	if (requests.length > 0) {
		Logger.log(
			`Executing ultra batch: ${requests.length} operations in 1 API call`,
		);
		const batchStart = Date.now();
		Slides.Presentations.batchUpdate({ requests }, presentationId);
		Logger.log(`Batch completed in ${Date.now() - batchStart}ms`);
	}
}

/**
 * Create single index item with optimal batch requests
 * Consolidates 5+ individual calls into 4 batch requests
 */
function createIndexItemUltra(
	item,
	index,
	left,
	top,
	config,
	slideId,
	requests,
	cache,
) {
	const shapeId = `index_${index}_${getNextGuid()}`;

	// 1. Create text box shape
	requests.push({
		createShape: {
			objectId: shapeId,
			shapeType: "TEXT_BOX",
			elementProperties: {
				pageObjectId: slideId,
				size: {
					width: { magnitude: config.width, unit: "PT" },
					height: { magnitude: config.height, unit: "PT" },
				},
				transform: {
					...cache.transforms.identity,
					translateX: left,
					translateY: top,
				},
			},
		},
	});

	// 2. Insert text content
	requests.push({
		insertText: {
			objectId: shapeId,
			text: item.text,
		},
	});

	// 3. Apply text styling (consolidated)
	requests.push({
		updateTextStyle: {
			objectId: shapeId,
			textRange: { type: "ALL" },
			style: {
				fontSize: { magnitude: config.fontSize, unit: "PT" },
				fontFamily: main_font_family || "Arial",
				foregroundColor: { opaqueColor: { rgbColor: cache.colors.main } },
				link: { pageObjectId: item.slideId }, // Add link in text style
			},
			fields: "fontSize,fontFamily,foregroundColor,link",
		},
	});

	// 4. Apply shape properties (alignment)
	requests.push({
		updateShapeProperties: {
			objectId: shapeId,
			shapeProperties: {
				contentAlignment: "MIDDLE",
			},
			fields: "contentAlignment",
		},
	});
}

// 🚀 ELEMENT GENERATORS MODULE - Optimized slide element creation
/**
 * High-performance generators for slide elements
 * - Progress bars
 * - Page numbers  
 * - Title footnotes
 * - Tab navigation
 * - Section elements
 */

/**
 * Generate all elements for a single slide (consolidated)
 */
function generateSlideElementsUltra(slideId, slideData, slideIndex, slideCache, sectionsCache, currentSectionIdx, requests, cache) {
	// 1. Progress bar (2 consolidated requests instead of 6)
	addProgressBarUltra(slideId, slideIndex, slideCache, requests, cache);

	// 2. Page number (1 consolidated request instead of 4)
	addPageNumberUltra(slideId, slideIndex, slideCache, requests, cache);

	// 3. Title footnote — intentionally NOT part of the run-all batch. It is run
	// standalone via the "🦶 更新 Footer" menu item (runUpdateTitleFootnotes).
	// addTitleFootnoteUltra(slideId, slideCache, requests, cache);

	// 4. Tab navigation (only for non-section slides)
	if (slideData.layoutName !== "SECTION_HEADER" && sectionsCache.length > 0) {
		addTabNavigationUltra(slideId, sectionsCache, currentSectionIdx, requests, cache);
	}
}

/**
 * Ultra-efficient progress bar (2 requests instead of 6)
 */
function addProgressBarUltra(slideId, slideIndex, slideCache, requests, cache) {
	const progressRatio = slideIndex / (slideCache.totalSlides - 1);
	const barWidth = slideCache.width * progressRatio;
	const bgId = `progress_bg_${slideId}_${getNextGuid()}`;
	const progId = `progress_${slideId}_${getNextGuid()}`;

	// Background + Progress bar in optimized requests
	requests.push(
		{
			createShape: {
				objectId: bgId, shapeType: 'RECTANGLE',
				elementProperties: {
					pageObjectId: slideId,
					size: { height: slideCache.sizes.progressBar.height, width: { magnitude: slideCache.width, unit: 'PT' } },
					transform: { ...cache.transforms.identity, translateX: 0, translateY: slideCache.progressBarY }
				}
			}
		},
		{
			updateShapeProperties: {
				objectId: bgId,
				shapeProperties: {
					shapeBackgroundFill: { solidFill: { color: { rgbColor: cache.colors.gray } } },
					outline: { weight: { magnitude: 0.1, unit: 'PT' }, outlineFill: { solidFill: { color: { rgbColor: cache.colors.gray } } } }
				},
				fields: 'shapeBackgroundFill.solidFill.color,outline.weight,outline.outlineFill.solidFill.color'
			}
		},
		{
			createShape: {
				objectId: progId, shapeType: 'RECTANGLE',
				elementProperties: {
					pageObjectId: slideId,
					size: { height: slideCache.sizes.progressBar.height, width: { magnitude: barWidth, unit: 'PT' } },
					transform: { ...cache.transforms.identity, translateX: 0, translateY: slideCache.progressBarY }
				}
			}
		},
		{
			updateShapeProperties: {
				objectId: progId,
				shapeProperties: {
					shapeBackgroundFill: { solidFill: { color: { rgbColor: cache.colors.main } } },
					outline: { weight: { magnitude: 0.1, unit: 'PT' }, outlineFill: { solidFill: { color: { rgbColor: cache.colors.main } } } }
				},
				fields: 'shapeBackgroundFill.solidFill.color,outline.weight,outline.outlineFill.solidFill.color'
			}
		}
	);
}

/**
 * Ultra-efficient page number (1 consolidated request instead of 4)
 */
function addPageNumberUltra(slideId, slideIndex, slideCache, requests, cache) {
	const pageId = `page_num_${slideId}_${getNextGuid()}`;

	requests.push(
		{
			createShape: {
				objectId: pageId, shapeType: 'TEXT_BOX',
				elementProperties: {
					pageObjectId: slideId,
					size: slideCache.sizes.pageNum,
					transform: { ...cache.transforms.identity, translateX: 650, translateY: 370 }
				}
			}
		},
		{ insertText: { objectId: pageId, text: `${slideIndex + 1} / ${slideCache.totalSlides}` } },
		{
			updateTextStyle: {
				objectId: pageId, textRange: { type: 'ALL' },
				style: {
					bold: true, fontFamily: main_font_family, fontSize: { magnitude: 10, unit: 'PT' },
					foregroundColor: { opaqueColor: { rgbColor: cache.colors.inactive } }
				},
				fields: 'bold,fontFamily,fontSize,foregroundColor'
			}
		},
		{
			updateParagraphStyle: {
				objectId: pageId, textRange: { type: 'ALL' },
				style: { alignment: 'CENTER' }, fields: 'alignment'
			}
		}
	);
}

/**
 * Ultra-efficient title footnote (1 consolidated request instead of 7)
 */
function addTitleFootnoteUltra(slideId, slideCache, requests, cache) {
	// Get main title once and cache it
	if (!cache.mainTitle) {
		cache.mainTitle = getMainTitleFromFirstSlide(slideCache.slideData[0].slide || 
			SlidesApp.getActivePresentation().getSlides()[0]);
	}
	if (!cache.mainTitle) return;

	const footnoteId = `obj_${slideId}_${Date.now().toString(36)}_${getNextGuid()}`;
	const boxWidth = 360;
	const boxY = (slideCache.height - boxWidth) / 2;

	requests.push(
		{
			createShape: {
				objectId: footnoteId, shapeType: 'TEXT_BOX',
				elementProperties: {
					pageObjectId: slideId,
					size: { width: { magnitude: boxWidth, unit: 'PT' }, height: { magnitude: 30, unit: 'PT' } },
					transform: {
						...cache.transforms.rotation90,
						translateX: slideCache.width, translateY: boxY
					}
				}
			}
		},
		{ insertText: { objectId: footnoteId, text: cache.mainTitle } },
		{
			updateTextStyle: {
				objectId: footnoteId, textRange: { type: 'ALL' },
				style: {
					foregroundColor: { opaqueColor: { rgbColor: cache.colors.inactive } },
					fontSize: { magnitude: 10, unit: 'PT' }, fontFamily: main_font_family,
					underline: false, link: { pageObjectId: slideCache.slideData[0].id }
				},
				fields: 'foregroundColor,fontSize,fontFamily,underline,link'
			}
		},
		{
			updateParagraphStyle: {
				objectId: footnoteId, textRange: { type: 'ALL' },
				style: { alignment: 'CENTER' }, fields: 'alignment'
			}
		},
		{
			updateShapeProperties: {
				objectId: footnoteId, shapeProperties: { contentAlignment: 'MIDDLE' },
				fields: 'contentAlignment'
			}
		}
	);
}

/**
 * Ultra-efficient tab navigation
 */
function addTabNavigationUltra(slideId, sections, currentSection, requests, cache) {
	// Pre-calculate tab layout
	const estCharW = 8 * 0.75; // fontSize * 0.75
	const widths = sections.map(sec => Math.max(sec.title.length * estCharW, 50) + 5); // +5pt buffer
	const totalWidth = widths.reduce((a, b) => a + b, 0);
	const xStart = Math.max((720 - totalWidth) / 2, 0);

	// Background bar
	const bgId = `tab_bg_${slideId}_${getNextGuid()}`;
	requests.push(
		{
			createShape: {
				objectId: bgId, shapeType: 'RECTANGLE',
				elementProperties: {
					pageObjectId: slideId,
					size: { height: { magnitude: 14, unit: 'PT' }, width: { magnitude: 720, unit: 'PT' } },
					transform: { ...cache.transforms.identity, translateX: 0, translateY: 0 }
				}
			}
		},
		{
			updateShapeProperties: {
				objectId: bgId,
				shapeProperties: { 
					shapeBackgroundFill: { solidFill: { color: { rgbColor: cache.colors.white } } },
					outline: {
						weight: { magnitude: 0.1, unit: 'PT' },
						outlineFill: { solidFill: { color: { rgbColor: cache.colors.white } } }
					}
				},
				fields: 'shapeBackgroundFill.solidFill.color,outline.weight,outline.outlineFill.solidFill.color'
			}
		}
	);

	// Individual tabs
	let xPos = xStart;
	sections.forEach((sec, idx) => {
		const isActive = idx === currentSection;
		const tabId = `tab_${slideId}_${getNextGuid()}`;

		requests.push(
			{
				createShape: {
					objectId: tabId, shapeType: 'TEXT_BOX',
					elementProperties: {
						pageObjectId: slideId,
						size: { height: { magnitude: 14, unit: 'PT' }, width: { magnitude: widths[idx], unit: 'PT' } },
						transform: { ...cache.transforms.identity, translateX: xPos, translateY: 0 }
					}
				}
			},
			{ insertText: { objectId: tabId, text: sec.title } },
			{
				updateShapeProperties: {
					objectId: tabId,
					shapeProperties: {
						// No button: transparent background for every tab.
						shapeBackgroundFill: { propertyState: 'NOT_RENDERED' },
						contentAlignment: 'MIDDLE'
					},
					fields: 'shapeBackgroundFill,contentAlignment'
				}
			},
			{
				updateTextStyle: {
					objectId: tabId, textRange: { type: 'ALL' },
					style: {
						// Active: main color + bold. Others: gray, not bold.
						bold: isActive, fontFamily: main_font_family, fontSize: { magnitude: 8, unit: 'PT' },
						foregroundColor: { opaqueColor: { rgbColor: isActive ? cache.colors.main : cache.colors.inactive } },
						underline: false, link: { pageObjectId: sec.slideId }
					},
					fields: 'bold,fontFamily,fontSize,foregroundColor,underline,link'
				}
			},
			{
				updateParagraphStyle: {
					objectId: tabId, textRange: { type: 'ALL' },
					style: { alignment: 'CENTER' }, fields: 'alignment'
				}
			}
		);
		xPos += widths[idx];
	});
}

// 📝 EXPORT MARKDOWN MODULE - Extract slide content as clean markdown
/**
 * Extracts meaningful content from slides and exports as Marp-like markdown.
 * Filters out auto-generated elements: page numbers, tabs, sections labels,
 * progress bars, index items, outlines, watermarks, and footnotes.
 */

/**
 * ID prefixes used by auto-generated elements that should be excluded
 */
const GENERATED_ELEMENT_PREFIXES = [
	"progress_bg_", // Progress bar background
	"progress_", // Progress bar
	"page_num_", // Page numbers
	"tab_bg_", // Tab navigation background
	"tab_", // Tab navigation items
	"tab_line_", // Tab navigation line
	"label_", // Section labels
	"sections_", // Section boxes
	"outline_", // Outline content
	"index_", // Index items
	"obj_", // Title footnotes (obj_slideId_timestamp_guid)
	"watermark_", // Watermarks
];

/**
 * Text patterns that indicate auto-generated content
 */
const GENERATED_TEXT_PATTERNS = [
	/^\d+\s*\/\s*\d+$/, // Page numbers like "1 / 10"
	/^Section:\s*\d+$/, // Section labels like "Section: 1"
	/^ⓒ\s*/, // Copyright watermarks
];

/**
 * Check if an element ID indicates it's auto-generated
 * @param {string} elementId - The object ID of the element
 * @returns {boolean} True if the element is auto-generated
 */
function isGeneratedElementById(elementId) {
	if (!elementId) return false;
	return GENERATED_ELEMENT_PREFIXES.some((prefix) =>
		elementId.startsWith(prefix),
	);
}

/**
 * Check if text content matches auto-generated patterns
 * @param {string} text - The text content to check
 * @returns {boolean} True if the text matches generated patterns
 */
function isGeneratedTextContent(text) {
	if (!text) return false;
	const trimmed = text.trim();
	return GENERATED_TEXT_PATTERNS.some((pattern) => pattern.test(trimmed));
}

/**
 * Extract text from a shape with bullet list detection
 * Uses SlidesApp's ListStyle API to detect bulleted paragraphs
 * @param {GoogleAppsScript.Slides.Shape} shape - The shape to extract text from
 * @returns {string} Formatted text with markdown bullet prefixes where applicable
 */
function extractTextWithBullets(shape) {
	const textRange = shape.getText();
	const paragraphs = textRange.getParagraphs();
	const lines = [];

	for (const paragraph of paragraphs) {
		const paragraphRange = paragraph.getRange();
		const paragraphText = paragraphRange.asString().replace(/\n$/, ""); // Remove trailing newline

		// Skip empty paragraphs
		if (!paragraphText.trim()) {
			continue;
		}

		// Check if this paragraph is in a list
		const listStyle = paragraphRange.getListStyle();
		const isInList = listStyle.isInList();

		if (isInList === true) {
			// Get nesting level for indentation (0-based)
			const nestingLevel = listStyle.getNestingLevel() || 0;
			const indent = "  ".repeat(nestingLevel); // 2 spaces per level
			lines.push(`${indent}- ${paragraphText.trim()}`);
		} else {
			lines.push(paragraphText.trim());
		}
	}

	return lines.join("\n");
}

/**
 * Extract clean text content from a slide, excluding generated elements
 * @param {GoogleAppsScript.Slides.Slide} slide - The slide to extract from
 * @returns {Object} Object with title and body text arrays
 */
function extractSlideContent(slide) {
	const layout = slide.getLayout();
	const layoutName = layout ? layout.getLayoutName() : "";
	const pageElements = slide.getPageElements();

	const result = {
		layoutName: layoutName,
		title: "",
		body: [],
		images: [],
		speakerNotes: "",
	};

	// Get speaker notes if available
	const notesPage = slide.getNotesPage();
	if (notesPage) {
		const notesShapes = notesPage.getShapes();
		for (const shape of notesShapes) {
			const placeholderType = shape.getPlaceholderType();
			if (placeholderType === SlidesApp.PlaceholderType.BODY) {
				const notesText = shape.getText().asString().trim();
				if (notesText) {
					result.speakerNotes = notesText;
				}
			}
		}
	}

	// Process page elements
	for (const element of pageElements) {
		const elementId = element.getObjectId();

		// Skip if element ID indicates it's auto-generated
		if (isGeneratedElementById(elementId)) {
			continue;
		}

		if (element.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
			const shape = element.asShape();
			const rawText = shape.getText().asString().trim();

			// Skip empty text or auto-generated text patterns
			if (!rawText || isGeneratedTextContent(rawText)) {
				continue;
			}

			// Check if this is a placeholder (title, subtitle, body)
			const placeholderType = shape.getPlaceholderType();

			if (
				placeholderType === SlidesApp.PlaceholderType.TITLE ||
				placeholderType === SlidesApp.PlaceholderType.CENTERED_TITLE
			) {
				// Titles don't need bullet detection
				result.title = rawText;
			} else if (
				placeholderType === SlidesApp.PlaceholderType.SUBTITLE ||
				placeholderType === SlidesApp.PlaceholderType.BODY
			) {
				// Body content - extract with bullet detection
				const formattedText = extractTextWithBullets(shape);
				if (formattedText) {
					result.body.push(formattedText);
				}
			} else {
				// For non-placeholder shapes, check position to determine if it's likely content
				// Skip very small shapes or shapes at edges (likely UI elements)
				const transform = element.getTransform();
				const translateX = transform.getTranslateX();
				const translateY = transform.getTranslateY();

				// Skip elements at top edge (likely tabs) or bottom edge (likely page numbers)
				if (translateY < 20 || translateY > 360) {
					continue;
				}

				// Skip elements at right edge (likely footnotes)
				if (translateX > 680) {
					continue;
				}

				// Include other content shapes with bullet detection
				const formattedText = extractTextWithBullets(shape);
				if (formattedText) {
					result.body.push(formattedText);
				}
			}
		} else if (
			element.getPageElementType() === SlidesApp.PageElementType.TABLE
		) {
			// Extract table content
			const table = element.asTable();
			const tableText = extractTableContent(table);
			if (tableText) {
				result.body.push(tableText);
			}
		} else if (
			element.getPageElementType() === SlidesApp.PageElementType.IMAGE
		) {
			// Extract image
			const image = element.asImage();
			const imageUrl = image.getContentUrl();
			if (imageUrl) {
				const altText =
					image.getDescription() || image.getTitle() || "slide image";
				result.images.push({
					url: imageUrl,
					alt: altText,
				});
			}
		}
	}

	return result;
}

/**
 * Extract content from a table as markdown
 * @param {GoogleAppsScript.Slides.Table} table - The table to extract from
 * @returns {string} Markdown formatted table content
 */
function extractTableContent(table) {
	const numRows = table.getNumRows();
	const numCols = table.getNumColumns();

	if (numRows === 0 || numCols === 0) return "";

	const rows = [];

	for (let r = 0; r < numRows; r++) {
		const row = [];
		for (let c = 0; c < numCols; c++) {
			const cell = table.getCell(r, c);
			const cellText = cell.getText().asString().trim().replace(/\|/g, "\\|");
			row.push(cellText);
		}
		rows.push(`| ${row.join(" | ")} |`);

		// Add header separator after first row
		if (r === 0) {
			rows.push(`|${" --- |".repeat(numCols)}`);
		}
	}

	return rows.join("\n");
}

/**
 * Get or create a folder by name under a parent folder
 * @param {GoogleAppsScript.Drive.Folder} parentFolder - Parent folder
 * @param {string} folderName - Name of folder to get or create
 * @returns {GoogleAppsScript.Drive.Folder} The folder
 */
function getOrCreateFolder(parentFolder, folderName) {
	const folders = parentFolder.getFoldersByName(folderName);
	if (folders.hasNext()) {
		return folders.next();
	}
	return parentFolder.createFolder(folderName);
}

/**
 * Clear all files in a folder (move to trash)
 * @param {GoogleAppsScript.Drive.Folder} folder - The folder to clear
 */
function clearFolder(folder) {
	const files = folder.getFiles();
	while (files.hasNext()) {
		const file = files.next();
		file.setTrashed(true);
	}
}

/**
 * Convert a title string to a URL/filename-safe slug
 * @param {string} title - The title to convert
 * @returns {string} A slug-formatted string
 */
function slugify(title) {
	if (!title) return "";

	return (
		title
			.toLowerCase()
			.trim()
			// Replace Chinese/CJK characters with pinyin or keep as-is (just keep them for now)
			// Remove or replace problematic characters for filenames
			.replace(/[\/\\:*?"<>|]/g, "") // Remove: / \ : * ? " < > |
			.replace(/[&]/g, "-and-") // Replace & with -and-
			.replace(/[@]/g, "-at-") // Replace @ with -at-
			.replace(/[#]/g, "") // Remove #
			.replace(/[%]/g, "") // Remove %
			.replace(/\s+/g, "-") // Replace spaces with hyphens
			.replace(/[_]+/g, "-") // Replace underscores with hyphens
			.replace(/-+/g, "-") // Replace multiple hyphens with single
			.replace(/^-+|-+$/g, "")
	); // Remove leading/trailing hyphens
}

/**
 * Save image to Drive
 * @param {string} contentUrl - The image content URL from Slides
 * @param {GoogleAppsScript.Drive.Folder} folder - The folder to save to
 * @param {string} filename - The filename for the image
 * @returns {boolean} True if saved successfully, false otherwise
 */
function saveImageToDrive(contentUrl, folder, filename) {
	try {
		const response = UrlFetchApp.fetch(contentUrl, {
			muteHttpExceptions: true,
			followRedirects: true,
		});

		const responseCode = response.getResponseCode();
		if (responseCode !== 200) {
			Logger.log(`HTTP ${responseCode} for ${filename}`);
			return false;
		}

		const blob = response.getBlob().setName(filename);
		folder.createFile(blob);
		return true;
	} catch (e) {
		Logger.log(`Failed to save image ${filename}: ${e.message}`);
		return false;
	}
}

/**
 * Generate Quarto YAML front matter
 * @param {string} title - Presentation title
 * @returns {string} YAML front matter for Quarto
 */
function generateQuartoFrontMatter(title) {
	const today = Utilities.formatDate(
		new Date(),
		Session.getScriptTimeZone(),
		"yyyy-MM-dd",
	);

	return `---
title: "${title}"
author: "林協霆"
date: "${today}"
format: html
---`;
}

/**
 * Convert slides to Marp-like markdown format
 * @param {boolean} saveImagesToDrive - Whether to save images to Drive
 * @returns {Object} Object with markdown content and presentationFolder
 */
function exportSlidesToMarkdown(saveImagesToDrive) {
	const presentation = SlidesApp.getActivePresentation();
	const slides = presentation.getSlides();
	const presentationTitle = presentation.getName();
	const presentationId = presentation.getId();

	// Set up assets folder if saving images to Drive
	let assetsFolder = null;
	let presentationFolder = null;

	if (saveImagesToDrive) {
		// Get the presentation's parent folder
		const presentationFile = DriveApp.getFileById(presentationId);
		const parentFolders = presentationFile.getParents();
		const parentFolder = parentFolders.hasNext()
			? parentFolders.next()
			: DriveApp.getRootFolder();

		// Create presentation_name/assets/ folder structure
		presentationFolder = getOrCreateFolder(parentFolder, presentationTitle);
		assetsFolder = getOrCreateFolder(presentationFolder, "assets");

		// Clear existing files in assets folder
		clearFolder(assetsFolder);
	}

	const markdownParts = [];

	// Add YAML front matter (Marp style)
	markdownParts.push("---");
	markdownParts.push("marp: true");
	markdownParts.push(`title: ${presentationTitle}`);
	markdownParts.push("---");
	markdownParts.push("");

	for (let index = 0; index < slides.length; index++) {
		const slide = slides[index];
		const content = extractSlideContent(slide);

		// Add slide separator (except for first slide, and not needed if slide has title)
		if (index > 0) {
			markdownParts.push("");
			// Only add --- separator if slide has no title (headings act as separators)
			if (!content.title) {
				markdownParts.push("---");
				markdownParts.push("");
			}
		}

		// Determine heading level based on layout
		if (content.layoutName === "SECTION_HEADER") {
			// Section header slides get H1
			if (content.title) {
				markdownParts.push(`# ${content.title}`);
			}
			// Add body content if any
			for (const text of content.body) {
				markdownParts.push("");
				markdownParts.push(text);
			}
		} else if (content.layoutName === "TITLE") {
			// Title slide (first slide typically)
			if (content.title) {
				markdownParts.push(`# ${content.title}`);
			}
			for (const text of content.body) {
				markdownParts.push("");
				markdownParts.push(text);
			}
		} else {
			// Regular slides get H2
			if (content.title) {
				markdownParts.push(`## ${content.title}`);
			}

			// Add body content
			for (const text of content.body) {
				markdownParts.push("");
				markdownParts.push(text);
			}
		}

		// Add images at the end of slide content
		if (content.images.length > 0) {
			markdownParts.push("");
			for (let imgIndex = 0; imgIndex < content.images.length; imgIndex++) {
				const img = content.images[imgIndex];
				let imageUrl = img.url;

				// Save to Drive if enabled
				if (saveImagesToDrive && assetsFolder) {
					const slideNum = String(index + 1).padStart(2, "0");
					const titleSlug = slugify(content.title);
					const filename = titleSlug
						? `slide_${slideNum}_${titleSlug}_img_${imgIndex + 1}.png`
						: `slide_${slideNum}_img_${imgIndex + 1}.png`;
					const saved = saveImageToDrive(img.url, assetsFolder, filename);
					if (saved) {
						// Use relative path for markdown
						imageUrl = `./assets/${filename}`;
					}
				}

				markdownParts.push(`![${img.alt}](${imageUrl})`);
			}
		}

		// Add speaker notes as HTML comment if present
		if (content.speakerNotes) {
			markdownParts.push("");
			markdownParts.push("<!--");
			markdownParts.push("Speaker notes:");
			markdownParts.push(content.speakerNotes);
			markdownParts.push("-->");
		}
	}

	const marpMarkdown = markdownParts.join("\n");

	// Save .md and .qmd files if saving to Drive
	if (saveImagesToDrive && presentationFolder) {
		const fileSlug = slugify(presentationTitle) || "slides";

		// Generate Quarto markdown (replace Marp front matter with Quarto)
		const quartoFrontMatter = generateQuartoFrontMatter(presentationTitle);
		const contentWithoutFrontMatter = marpMarkdown.replace(
			/^---[\s\S]*?---\n*/,
			"",
		);
		const quartoMarkdown = `${quartoFrontMatter}\n\n${contentWithoutFrontMatter}`;

		// Remove old .md and .qmd files in presentation folder
		const existingFiles = presentationFolder.getFiles();
		while (existingFiles.hasNext()) {
			const file = existingFiles.next();
			const fileName = file.getName();
			if (fileName.endsWith(".md") || fileName.endsWith(".qmd")) {
				file.setTrashed(true);
			}
		}

		// Save .md file (Marp format)
		presentationFolder.createFile(`${fileSlug}.md`, marpMarkdown, "text/plain");

		// Save .qmd file (Quarto format)
		presentationFolder.createFile(
			`${fileSlug}.qmd`,
			quartoMarkdown,
			"text/plain",
		);

		// Return markdown and folder URL for Drive exports
		return {
			markdown: marpMarkdown,
			folderUrl: presentationFolder.getUrl(),
			folderName: presentationTitle,
		};
	}

	return marpMarkdown;
}

