// 🚀 SLIDE UTILITIES MODULE - Slide analysis and manipulation helpers
/**
 * Utility functions for slide analysis and content extraction
 * - Section detection
 * - Title extraction
 * - Element deletion patterns
 */

/**
 * Ultra-efficient section header detection
 */
function getSectionHeadersUltra(slides) {
	const sections = [];
	for (let i = 0; i < slides.length; i++) {
		const slide = slides[i];
		if (slide.getLayout().getLayoutName() === "SECTION_HEADER") {
			// Early exit on first text found
			const shapes = slide.getShapes();
			for (const shape of shapes) {
				if (shape.getShapeType() === SlidesApp.ShapeType.TEXT_BOX) {
					const text = shape.getText().asString().trim();
					if (text) {
						sections.push({
							title: text,
							index: i,
							slideId: slide.getObjectId(),
						});
						break; // Found text, stop searching this slide
					}
				}
			}
		}
	}
	return sections;
}

/**
 * Extract main title from first slide
 * Selection priority:
 * 1. Title placeholder
 * 2. Largest text (by font size)
 * 3. Text in upper half of slide
 * 4. First non-empty text (fallback)
 */
function getMainTitleFromFirstSlide(slide) {
	// Try to get title placeholder first
	const titlePlaceholder = slide.getPlaceholder(
		SlidesApp.PlaceholderType.TITLE,
	);
	if (titlePlaceholder && titlePlaceholder.asShape) {
		const titleText = titlePlaceholder.asShape().getText().asString().trim();
		if (titleText) return titleText;
	}

	// Collect all text elements with their properties
	const textElements = [];
	const elements = slide.getPageElements();

	for (const el of elements) {
		if (el.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
			const shape = el.asShape();
			const txt = shape.getText().asString().trim();
			if (txt) {
				// Get position and size info
				const transform = el.getTransform();
				const height = el.getHeight();
				const translateY = transform.getTranslateY();

				// Try to get font size (default to 0 if unable to get)
				let fontSize = 0;
				try {
					const textRange = shape.getText();
					if (textRange && textRange.getTextStyle) {
						const style = textRange.getTextStyle();
						if (style && style.getFontSize) {
							fontSize = style.getFontSize() || 0;
						}
					}
				} catch (e) {
					// Ignore errors when getting font size
				}

				textElements.push({
					text: txt,
					fontSize: fontSize,
					yPosition: translateY,
					height: height,
					element: el,
				});
			}
		}
	}

	if (textElements.length === 0) return "";

	// Sort by criteria:
	// 1. Larger font size first
	// 2. Higher position (smaller Y) first
	// 3. Larger height first
	textElements.sort((a, b) => {
		// Compare font size (larger is better)
		if (a.fontSize !== b.fontSize) {
			return b.fontSize - a.fontSize;
		}
		// Compare Y position (smaller Y = higher on slide = better)
		if (Math.abs(a.yPosition - b.yPosition) > 50) {
			// 50pt threshold
			return a.yPosition - b.yPosition;
		}
		// Compare height (larger is better)
		return b.height - a.height;
	});

	// Return the best candidate
	return textElements[0].text;
}

/**
 * Get title from outline slide (second slide if it exists)
 */
function getOutlineSlideTitle(slide) {
	let title = "";
	const placeholder = slide.getPlaceholder(SlidesApp.PlaceholderType.TITLE);
	if (placeholder && placeholder.asShape) {
		title = placeholder.asShape().getText().asString().trim();
	} else {
		// Quick text search
		const shapes = slide.getShapes();
		for (const shape of shapes) {
			if (shape.getShapeType() === SlidesApp.ShapeType.TEXT_BOX) {
				const txt = shape.getText().asString().trim();
				if (txt) {
					title = txt;
					break;
				}
			}
		}
	}
	return title;
}

/**
 * Ultra-efficient batch delete of old elements
 */
function batchDeleteAllElements(slides, requests) {
	const deletePatterns = [
		"tab_",
		"progress_",
		"sections_",
		"label_",
		"outline_",
		"obj_",
		"page_num_",
	];
	const deleteTargets = ["PROGRESS", "PROGRESS_BG", "MAIN_TITLE"];

	for (let i = 1; i < slides.length; i++) {
		// Skip first slide
		const shapes = slides[i].getShapes();
		for (const shape of shapes) {
			const id = shape.getObjectId();
			// Enhanced deletion check - also check for malformed IDs (in case newGuid failed)
			const shouldDelete =
				deletePatterns.some((p) => id.startsWith(p)) ||
				(id.includes("page_num") && id.includes("undefined")) || // Handle broken IDs from undefined newGuid
				(shape.getTitle && deleteTargets.includes(shape.getTitle()));

			if (shouldDelete) {
				requests.push({ deleteObject: { objectId: id } });
			}
		}
	}
}

/**
 * Convert hex color to RGB format for Google Slides API
 */
function hexToRgb(hex) {
	const m = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
	return m
		? {
				red: Number.parseInt(m[1], 16) / 255,
				green: Number.parseInt(m[2], 16) / 255,
				blue: Number.parseInt(m[3], 16) / 255,
			}
		: { red: 0, green: 0, blue: 0 };
}

// This file previously contained the onOpen function and theme-related functions
// These have been moved to config.gs to consolidate menu functionality
// This file is kept for backward compatibility


/**
 * Apply theme from a source presentation to the current presentation
 * This preserves the content of the current presentation while applying the theme/styles from the source
 */
function applyThemeToCurrentPresentation() {
    // Add debugging information
    Logger.log('Starting theme application process...');

    // Source presentation with the desired theme/styles
    Logger.log('Source presentation ID: ' + sourcePresentationId);

    // Get the current presentation ID from the script properties
    const currentPresentationId = PropertiesService.getScriptProperties().getProperty('presentationId') ||
                                SlidesApp.getActivePresentation().getId();
    Logger.log('Current presentation ID: ' + currentPresentationId);

    // Open both presentations
    const sourcePresentation = SlidesApp.openById(sourcePresentationId);
    const currentPresentation = SlidesApp.openById(currentPresentationId);

    // Apply the theme from source to current presentation
    applyTheme(sourcePresentation, currentPresentation);

    Logger.log('Theme applied to current presentation: ' + currentPresentationId);
  }

  /**
   * Apply theme from source presentation to target presentation
   * @param {SlidesApp.Presentation} sourcePresentation - The presentation to copy theme from
   * @param {SlidesApp.Presentation} targetPresentation - The presentation to apply theme to
   */
  function applyTheme(sourcePresentation, targetPresentation) {
    try {
      // According to the documentation, when we append a slide from another presentation,
      // the master slides and layouts are automatically copied if they don't exist in the target
      Logger.log('Starting applyTheme function...');

      // 1. Get a slide from the source presentation to copy
      const sourceSlides = sourcePresentation.getSlides();

      if (sourceSlides.length === 0) {
        Logger.log('Error: Source presentation has no slides');
        return false;
      }

      // 2. Append the first slide from the source to the target presentation
      // This will automatically copy the theme (master slides and layouts)
      const copiedFirstSlide = targetPresentation.appendSlide(sourceSlides[0]);

      // Also copy the last slide from the source presentation
      const lastSlideIndex = sourceSlides.length - 1;
      const copiedLastSlide = targetPresentation.appendSlide(sourceSlides[lastSlideIndex]);
      Logger.log('First and last slides copied successfully');

      Logger.log('Theme slide copied successfully');

      // 3. Update the title text box on the copied slides to match the current presentation's name
      try {
        // Get the current presentation name
        const presentationName = targetPresentation.getName();
        Logger.log('Current presentation name: ' + presentationName);

        // Find the title shape on the first copied slide
        const shapes = copiedFirstSlide.getShapes();
        for (let i = 0; i < shapes.length; i++) {
          const shape = shapes[i];

          // Check if this is a text box that might be the title
          if (shape.getShapeType() === SlidesApp.ShapeType.TEXT_BOX) {
            const textRange = shape.getText();
            const placeholder = shape.getPlaceholderType();

            // If it's a title placeholder or the first text box, update it
            if (placeholder === SlidesApp.PlaceholderType.TITLE || i === 0) {
              textRange.setText(presentationName);
              Logger.log('Updated title text to: ' + presentationName);
              break;
            }
          }
        }
      } catch (titleError) {
        Logger.log('Error updating title: ' + titleError.toString());
        // Continue even if updating the title fails
      }

      // For new presentations, this is sufficient - the theme is now available
      // Any new slides created will use the new theme

      // Delete the original slides (keeping only the newly copied theme slides)
      try {
        const allSlides = targetPresentation.getSlides();
        if (allSlides.length > 2) { // Make sure we have at least 3 slides before deleting
          // The first slide is at index 0
          allSlides[0].remove();
          Logger.log('First slide (original slide page 1) deleted successfully');
        } else {
          Logger.log('Not enough slides to delete the first slide');
        }
      } catch (deleteError) {
        Logger.log('Error deleting first slide: ' + deleteError.toString());
        // Continue even if deleting the slide fails
      }

      // If the presentation already has other slides, we'll keep the copied slide
      // at the end for reference, but we won't try to modify existing slides
      // since the setLayout method doesn't work on existing slides

      Logger.log('Theme imported successfully - new slides will use this theme');
      return true;
    } catch (error) {
      Logger.log('Error applying theme: ' + error.toString());
      return false;
    }
  }

// Toggle watermark module for Google Slides
/**
 * 切換浮水印：若頁面已有 title='WATERMARK' 的浮水印就刪除，
 * 否則就新增半透明、45° 旋轉、置中的文字浮水印。
 */
function toggleWaterMark(slides, requests) {
  const aColour = '#efefef';
  const slideWidth  = SlidesApp.getActivePresentation().getPageWidth();
  const slideHeight = SlidesApp.getActivePresentation().getPageHeight();
  const wmWidth  = 500;
  const wmHeight = 100;
  const dx = (slideWidth )  / 2;
  const dy = (slideHeight ) / 2 - 2 * wmHeight;
  const cos45 = Math.SQRT1_2;
  const sin45 = Math.SQRT1_2;

  slides.forEach(slide => {
    const slideId = slide.getObjectId();
    // 檢查該 slide 是否已有浮水印
    const existing = slide.getPageElements().filter(el => {
      return el.getPageElementType() === SlidesApp.PageElementType.SHAPE
          && el.asShape().getTitle && el.asShape().getTitle() === 'WATERMARK';
    });

    if (existing.length) {
      // 已有：刪除所有舊的 WATERMARK
      existing.forEach(shape => {
        requests.push({ deleteObject: { objectId: shape.getObjectId() } });
      });
    } else {
      // 不存在：新增浮水印
      const wmId = newObjectId(slideId);
      // 1) 建立文字框並旋轉 45°
      requests.push({
        createShape: {
          objectId: wmId,
          shapeType: 'TEXT_BOX',
          elementProperties: {
            pageObjectId: slideId,
            size: {
              width:  { magnitude: wmWidth,  unit: 'PT' },
              height: { magnitude: wmHeight, unit: 'PT' }
            },
            transform: {
              scaleX:     cos45,
              shearX:    -sin45,
              shearY:     sin45,
              scaleY:     cos45,
              translateX: dx,
              translateY: dy,
              unit:      'PT'
            }
          }
        }
      });
      // 3) 插入文字
      requests.push({
        insertText: {
          objectId:       wmId,
          insertionIndex: 0,
          text:           water_mark_text,
        }
      });
      // 4) 文字樣式：字型大小、顏色
      requests.push({
        updateTextStyle: {
          objectId: wmId,
          textRange: { type: 'ALL' },
          style: {
            fontSize: { magnitude: 56, unit: 'PT' },
            foregroundColor: { opaqueColor: { rgbColor: hexToRgb(aColour) } }
          },
          fields: 'fontSize,foregroundColor'
        }
      });
      // 5) 段落置中
      requests.push({
        updateParagraphStyle: {
          objectId:  wmId,
          textRange: { type: 'ALL' },
          style:     { alignment: 'CENTER' },
          fields:    'alignment'
        }
      });
      // 6) 垂直置中
      requests.push({
        updateShapeProperties: {
          objectId:       wmId,
          shapeProperties:{ contentAlignment: 'MIDDLE' },
          fields:         'contentAlignment'
        }
      });
      // 7) 打上 title 標記方便後續刪除
      requests.push({
        updatePageElementAltText: {
          objectId: wmId,
          title:    'WATERMARK'
        }
      });
    }
  });
}

// 🚀 ULTRA MEGA BATCH PROCESSOR - Maximum Performance Optimization
/**
 * MODULAR ARCHITECTURE: Clean separation of concerns with maximum performance
 * - Modularized into specialized components
 * - Cache management (cache_manager.js)
 * - Slide utilities (slide_utilities.js) 
 * - Element generators (element_generators.js)
 * - Section elements (section_elements.js)
 * - Expected: 1-2s → 0.5-1s for 20-slide presentation
 * 
 * DEPENDENCIES:
 * - cache_manager.js
 * - slide_utilities.js
 * - element_generators.js
 * - section_elements.js
 */

// ⚡ Cache management is now handled by cache_manager.js
// Functions available: initializeUltraCache(), getNextGuid(), createUltraSlideCache()

/**
 * 🚀 ULTRA MEGA BATCH: Maximum performance with consolidated operations
 */
function runAllFunctionsUltraMegaBatch() {
	const presentation = SlidesApp.getActivePresentation();
	const presentationId = presentation.getId();
	const slides = presentation.getSlides();
	const requests = [];

	// Initialize ultra cache
	const cache = initializeUltraCache();

	// Create optimized slide cache
	const slideCache = createUltraSlideCache(presentation, slides);
	const sectionsCache = getSectionHeadersUltra(slides);

	// Single batch delete
	batchDeleteAllElements(slides, requests);

	// Generate all elements with ultra optimization
	generateAllElementsUltra(slides, requests, slideCache, sectionsCache, cache);

	// Single mega batch update
	if (requests.length) {
		Logger.log(`Ultra batch: ${requests.length} operations in 1 API call`);
		const startTime = Date.now();
		Slides.Presentations.batchUpdate({ requests }, presentationId);
		Logger.log(`Ultra batch completed in ${Date.now() - startTime}ms`);
	}

	// Update date separately
	updateDateInFirstSlide();
}

