function drawArrowOnCurrentSlide() {
  const presentation = SlidesApp.getActivePresentation();
  const slide = presentation.getSelection().getCurrentPage();

  // Define the color blue
  const blueColor = main_color;

  // Box 1
  const box1 = slide.insertShape(SlidesApp.ShapeType.RECTANGLE, 360, 200, 20, 100);
  box1.getFill().setSolidFill(blueColor);
  box1.getBorder().getLineFill().setSolidFill(blueColor);

  // Box 2
  const box2 = slide.insertShape(SlidesApp.ShapeType.RECTANGLE, 360, 280, 100, 20);
  box2.getFill().setSolidFill(blueColor);
  box2.getBorder().getLineFill().setSolidFill(blueColor);

  // Box 3
  const box3 = slide.insertShape(SlidesApp.ShapeType.RECTANGLE, 404, 181, 20, 130);
  box3.setRotation(45);
  box3.getFill().setSolidFill(blueColor);
  box3.getBorder().getLineFill().setSolidFill(blueColor);

  // Group all three shapes together to form the arrow
  const pageElements = [box1, box2, box3];
  const groupedArrow = slide.group(pageElements);

  // Return the grouped arrow in case it needs to be used elsewhere
  return groupedArrow;
}

function logSelectedItemGeometry() {
  const presentation = SlidesApp.getActivePresentation();
  const selection = presentation.getSelection();
  const currentPage = selection.getCurrentPage();
  const pageElements = selection.getPageElementRange().getPageElements();

  if (pageElements.length === 0) {
    Logger.log('No page element selected.');
    return;
  }

  const element = pageElements[0]; // Just taking the first selected element
  const transform = element.getTransform();

  const x = transform.getTranslateX();
  const y = transform.getTranslateY();
  const width = element.getWidth();
  const height = element.getHeight();

  Logger.log(`Selected Element Geometry:
    X: ${x}
    Y: ${y}
    Width: ${width}
    Height: ${height}`);
}

function createOffsetBlueShape() {
  const presentation = SlidesApp.getActivePresentation();
  const selection = presentation.getSelection();
  const currentPage = selection.getCurrentPage();
  const ui = SlidesApp.getUi();

  const selectedElement = getSingleSelectedElement(selection, ui);
  if (!selectedElement) return;

  const offset = promptForOffset(ui);
  if (offset === null) return;

  const { x, y, width, height } = getElementDimensions(selectedElement);

  const blueShape = drawOffsetShape(currentPage, x, y, width, height, offset, main_color);

  const triangles = drawDecorativeTriangles(currentPage, x, y, width, height, offset, main_color);

  const overlay = applyBorderOrOverlay(currentPage, selectedElement, x, y, width, height, main_color);

  selectedElement.bringToFront();

  // Group all four shapes together
  const pageElements = [selectedElement, blueShape, ...triangles, overlay].filter(Boolean);
  currentPage.group(pageElements);
}

// Utility Functions

function getSingleSelectedElement(selection, ui) {
  const pageElementRange = selection.getPageElementRange();
  if (!pageElementRange) {
    ui.alert("Please select exactly one item.");
    return null;
  }

  const selectedElements = pageElementRange.getPageElements();
  if (selectedElements.length !== 1) {
    ui.alert("Please select exactly one item.");
    return null;
  }

  return selectedElements[0];
}

function promptForOffset(ui) {
  const response = ui.prompt('Enter offset (number of pixels to shift X and Y)', 'e.g. 10', ui.ButtonSet.OK_CANCEL);
  if (response.getSelectedButton() !== ui.Button.OK) return null;

  const offset = parseFloat(response.getResponseText().trim());
  if (isNaN(offset)) {
    ui.alert("Invalid number. Please enter a numeric value.");
    return null;
  }

  return offset;
}

function getElementDimensions(element) {
  return {
    x: element.getLeft(),
    y: element.getTop(),
    width: element.getWidth(),
    height: element.getHeight()
  };
}

function drawOffsetShape(page, x, y, width, height, offset, color) {
  const shape = page.insertShape(SlidesApp.ShapeType.RECTANGLE, x + offset, y + offset, width, height);
  shape.getFill().setSolidFill(color);
  shape.getBorder().getLineFill().setSolidFill(color);
  return shape;
}

function drawDecorativeTriangles(page, x, y, width, height, offset, color) {
  const triangle1 = insertTriangle(page, x + width, y, offset, color, false);       // Right side triangle
  const triangle2 = insertTriangle(page, x + offset, y + height, offset, color, true); // Bottom-left mirrored triangle
  return [triangle1, triangle2];
}

function insertTriangle(page, x, y, size, color, isLeft) {
  const triangle = page.insertShape(SlidesApp.ShapeType.RIGHT_TRIANGLE, x, y, size, size);

  if (isLeft) {
    triangle.scaleWidth(-1);
    triangle.setRotation(-90);
  }

  triangle.getFill().setSolidFill(color);
  triangle.getBorder().setWeight(1);
  triangle.getBorder().getLineFill().setSolidFill(color);

  return triangle;
}

function applyBorderOrOverlay(page, element, x, y, width, height, color) {
  try {
    const border = element.getBorder();
    if (border) {
      border.getLineFill().setSolidFill(color);
      return null;
    }
  } catch (e) {
    // Element may not support border
  }

  const overlay = page.insertShape(SlidesApp.ShapeType.RECTANGLE, x, y, width, height);
  overlay.getFill().setTransparent();
  overlay.getBorder().getLineFill().setSolidFill(color);
  overlay.bringToFront();

  return overlay;
}

/**
 * Server-side core for the Agenda / TOC Minter (目錄鑄造器) dialog.
 *
 * Builds an "Agenda" table-of-contents block on the current slide. The dialog
 * pre-fills its textarea with section titles auto-detected from the deck — slides
 * using a SECTION_HEADER layout (falling back to the first non-empty text of
 * each slide) — which the user can then edit before inserting.
 *
 * Mirrors the Callout / Grid Minter pattern:
 *  - Templates resolve their colors from the global palette (main_color, etc.)
 *    so they track the configured theme.
 *  - Insertion uses the SlidesApp service so the inserted text boxes can be
 *    grouped together afterwards.
 *
 * Exposes exactly three server functions to the dialog:
 *  - getAgendaItems()
 *  - getAgendaTemplates()
 *  - insertAgendaIntoSlide(payload)
 */

/**
 * Auto-detects section titles from the active deck for pre-filling the dialog.
 *
 * Detection strategy:
 *  1. Prefer slides whose layout is "SECTION_HEADER"; take each one's title
 *     placeholder text (or, failing that, the first non-empty text shape).
 *  2. If no section-header slides are found, fall back to the first non-empty
 *     title/text of every slide so the user still gets a useful starting list.
 *
 * Returns [] safely on any error so the dialog never breaks.
 *
 * @return {Array<string>} ordered, de-duplicated section titles
 */
function getAgendaItems() {
	// Cache briefly so repeat dialog opens don't re-scan every slide. The short
	// TTL keeps it fresh enough as the deck changes.
	try {
		const cache = CacheService.getDocumentCache();
		if (cache) {
			const hit = cache.get("agenda_items_v1");
			if (hit) return JSON.parse(hit);
		}
		const items = computeAgendaItems_();
		if (cache) cache.put("agenda_items_v1", JSON.stringify(items), 30);
		return items;
	} catch (e) {
		return computeAgendaItems_();
	}
}

/**
 * Computes agenda items by scanning the deck (uncached). See getAgendaItems().
 * @return {Array<string>} ordered, de-duplicated section titles
 */
function computeAgendaItems_() {
	try {
		const presentation = SlidesApp.getActivePresentation();
		const slides = presentation.getSlides();
		const items = [];

		// Pass 1: SECTION_HEADER layout slides.
		for (let i = 0; i < slides.length; i++) {
			const slide = slides[i];
			let layoutName = "";
			try {
				const layout = slide.getLayout();
				layoutName = layout ? layout.getLayoutName() : "";
			} catch (e) {
				layoutName = "";
			}
			if (layoutName === "SECTION_HEADER") {
				const title = agendaSlideTitle_(slide);
				if (title) items.push(title);
			}
		}

		if (items.length) return dedupeAgendaItems_(items);

		// Pass 2 (fallback): first non-empty title/text of each slide, skipping
		// the very first slide (usually the cover/title slide).
		for (let i = 1; i < slides.length; i++) {
			const title = agendaSlideTitle_(slides[i]);
			if (title) items.push(title);
		}

		return dedupeAgendaItems_(items);
	} catch (e) {
		console.error("Error detecting agenda items: " + e.message);
		return [];
	}
}

/**
 * Returns the first usable title text for a slide: the TITLE placeholder if it
 * has text, otherwise the first non-empty text shape on the slide.
 *
 * @param {Slide} slide
 * @return {string} trimmed title text, or "" if none
 */
function agendaSlideTitle_(slide) {
	try {
		const placeholder = slide.getPlaceholder(SlidesApp.PlaceholderType.TITLE);
		if (placeholder && placeholder.asShape) {
			const t = placeholder.asShape().getText().asString().trim();
			if (t) return t;
		}
	} catch (e) {
		// no title placeholder — fall through to the text-shape scan
	}
	try {
		const shapes = slide.getShapes();
		for (const shape of shapes) {
			const txt = shape.getText().asString().trim();
			if (txt) return txt;
		}
	} catch (e) {
		// ignore
	}
	return "";
}

/**
 * De-duplicates agenda items (case-insensitive) while preserving order and
 * dropping empty entries.
 *
 * @param {Array<string>} items
 * @return {Array<string>}
 */
function dedupeAgendaItems_(items) {
	const seen = {};
	const out = [];
	for (const raw of items || []) {
		const item = (raw || "").trim();
		if (!item) continue;
		const key = item.toLowerCase();
		if (seen[key]) continue;
		seen[key] = true;
		out.push(item);
	}
	return out;
}

/**
 * Single source of truth for agenda templates. Colors resolve from the global
 * palette so they track the configured theme.
 *
 * layout:
 *  - 'numbered'   = single-column numbered list
 *  - 'bulleted'   = single-column bulleted list
 *  - 'twoColumn'  = numbered list split across two columns
 *
 * @return {Array<{id,name,layout,heading,headingColor,itemColor,markerColor}>}
 */
function buildAgendaTemplates_() {
	const main = (typeof main_color !== "undefined" && main_color) || "#3D6869";
	const accent =
		(typeof accent_color !== "undefined" && accent_color) || "#f29424";
	const text = (typeof text_color !== "undefined" && text_color) || "#000000";
	// Readable mid-gray for subdued item text. NOT sub1_color — that's a
	// near-white background tint (#E7EAE7) and would be almost invisible.
	const sub1 = "#666666";
	return [
		{
			id: "numbered",
			name: "Numbered List",
			layout: "numbered",
			heading: "Agenda",
			headingColor: main,
			itemColor: text,
			markerColor: accent,
		},
		{
			id: "bulleted",
			name: "Bulleted List",
			layout: "bulleted",
			heading: "目錄",
			headingColor: main,
			itemColor: text,
			markerColor: main,
		},
		{
			id: "twoColumn",
			name: "Two Column",
			layout: "twoColumn",
			heading: "Agenda",
			headingColor: main,
			itemColor: sub1,
			markerColor: accent,
		},
	];
}

/**
 * Returns the agenda templates for client-side preview. Called from the dialog
 * through google.script.run.
 * @return {Array<Object>}
 */
function getAgendaTemplates() {
	return buildAgendaTemplates_();
}

/**
 * Resolves a template by id, defaulting to the first template.
 * @param {string} id
 * @return {Object}
 */
function resolveAgendaTemplate_(id) {
	const templates = buildAgendaTemplates_();
	for (let i = 0; i < templates.length; i++) {
		if (templates[i].id === id) return templates[i];
	}
	return templates[0];
}

/**
 * Parses the textarea payload (one item per line) into a clean array.
 * @param {Array<string>|string} items
 * @return {Array<string>}
 */
function parseAgendaItems_(items) {
	let list = [];
	if (Array.isArray(items)) {
		list = items;
	} else if (typeof items === "string") {
		list = items.split(/\r?\n/);
	}
	const out = [];
	for (const raw of list) {
		const item = (raw || "").trim();
		if (item) out.push(item);
	}
	return out;
}

/**
 * Inserts an agenda / TOC block onto the current slide: a heading text box plus
 * the items rendered as a numbered or bulleted list (or split into two columns
 * for the two-column template / when there are many items). Styled with theme
 * colors, left-aligned, positioned near the top-left. All inserted boxes are
 * grouped together.
 *
 * @param {{items: Array<string>|string, templateId: string}} payload
 * @return {{success: boolean, error?: string}}
 */
function insertAgendaIntoSlide(payload) {
	try {
		const p = payload || {};
		const items = parseAgendaItems_(p.items);
		if (!items.length) {
			return { success: false, error: "No agenda items to insert." };
		}

		const tpl = resolveAgendaTemplate_(p.templateId);
		const font =
			(typeof main_font_family !== "undefined" && main_font_family) ||
			"Source Sans Pro";

		const presentation = SlidesApp.getActivePresentation();

		// Resolve the target slide (fall back to the first slide).
		let slide = null;
		try {
			slide = presentation.getSelection().getCurrentPage().asSlide();
		} catch (e) {
			slide = presentation.getSlides()[0];
		}
		if (!slide) return { success: false, error: "No slide available." };

		const pageW = presentation.getPageWidth();

		// Layout constants.
		const LEFT = 50;
		const TOP = 110;
		const HEADING_H = 40;
		const GAP = 8; // gap between heading and list
		const itemH = 24; // per-item height estimate
		const usableW = Math.max(pageW - LEFT - 50, 200);

		const group = [];

		// Heading.
		const heading = slide.insertShape(
			SlidesApp.ShapeType.TEXT_BOX,
			LEFT,
			TOP,
			usableW,
			HEADING_H,
		);
		heading.getText().setText(tpl.heading || "Agenda");
		heading
			.getText()
			.getTextStyle()
			.setForegroundColor(tpl.headingColor)
			.setBold(true)
			.setFontSize(28)
			.setFontFamily(font);
		heading
			.getText()
			.getParagraphStyle()
			.setParagraphAlignment(SlidesApp.ParagraphAlignment.START);
		group.push(heading);

		const listTop = TOP + HEADING_H + GAP;
		const useTwoCol = tpl.layout === "twoColumn" || items.length > 8;

		if (useTwoCol) {
			// Split items as evenly as possible into two columns.
			const half = Math.ceil(items.length / 2);
			const colGap = 20;
			const colW = (usableW - colGap) / 2;
			const col1 = items.slice(0, half);
			const col2 = items.slice(half);

			const box1 = buildAgendaListBox_(
				slide,
				LEFT,
				listTop,
				colW,
				col1.length * itemH,
				col1,
				tpl,
				font,
				0,
			);
			group.push(box1);

			if (col2.length) {
				const box2 = buildAgendaListBox_(
					slide,
					LEFT + colW + colGap,
					listTop,
					colW,
					col2.length * itemH,
					col2,
					tpl,
					font,
					col1.length,
				);
				group.push(box2);
			}
		} else {
			const box = buildAgendaListBox_(
				slide,
				LEFT,
				listTop,
				usableW,
				items.length * itemH,
				items,
				tpl,
				font,
				0,
			);
			group.push(box);
		}

		if (group.length > 1) slide.group(group);

		return { success: true };
	} catch (e) {
		console.error("Error inserting agenda: " + e.message);
		return { success: false, error: e.message };
	}
}

/**
 * Creates and styles one list text box for the agenda. Numbered templates prefix
 * each item with "N. " (continuing from startNumber); bulleted templates use the
 * Slides bullet preset.
 *
 * @param {Slide} slide
 * @param {number} x
 * @param {number} y
 * @param {number} w
 * @param {number} h
 * @param {Array<string>} items
 * @param {Object} tpl - resolved template
 * @param {string} font
 * @param {number} startNumber - number of preceding items (for numbered offset)
 * @return {Shape} the created text box
 */
function buildAgendaListBox_(slide, x, y, w, h, items, tpl, font, startNumber) {
	const box = slide.insertShape(
		SlidesApp.ShapeType.TEXT_BOX,
		x,
		y,
		w,
		Math.max(h, 30),
	);

	const isNumbered = tpl.layout !== "bulleted";
	const lines = [];
	for (let i = 0; i < items.length; i++) {
		if (isNumbered) {
			lines.push(startNumber + i + 1 + ". " + items[i]);
		} else {
			lines.push(items[i]);
		}
	}
	const text = box.getText();
	text.setText(lines.join("\n"));

	text
		.getTextStyle()
		.setForegroundColor(tpl.itemColor)
		.setFontSize(16)
		.setFontFamily(font);
	text
		.getParagraphStyle()
		.setParagraphAlignment(SlidesApp.ParagraphAlignment.START);

	// Bulleted layout: apply a bullet preset and color the markers via the item
	// color (Slides has no separate marker color, so the whole line shares it).
	if (!isNumbered) {
		try {
			text.getListStyle().applyListPreset(SlidesApp.ListPreset.DISC_CIRCLE_SQUARE);
		} catch (e) {
			// ignore — fall back to plain lines
		}
	}

	// Numbered layout: color the "N. " marker at the start of each line with the
	// template's marker color so the numbers stand out.
	if (isNumbered) {
		let charIndex = 0;
		for (let i = 0; i < lines.length; i++) {
			const markerLen = (startNumber + i + 1 + ". ").length;
			try {
				text
					.getRange(charIndex, charIndex + markerLen)
					.getTextStyle()
					.setForegroundColor(tpl.markerColor)
					.setBold(true);
			} catch (e) {
				// ignore range errors
			}
			charIndex += lines[i].length + 1; // +1 for the newline
		}
	}

	return box;
}

/**
 * BYOK (Bring Your Own Key) management for AI features.
 *
 * SECURITY MODEL:
 * - Each user stores THEIR OWN key in PropertiesService.getUserProperties().
 *   This store is scoped to the individual Google account, lives server-side in
 *   Google's infrastructure, and is invisible to other users of the add-on.
 * - The key is NEVER sent back to the client, never stored in localStorage, and
 *   never passed as an argument across google.script.run. All provider calls
 *   happen here, server-side, via UrlFetchApp.
 *
 * We use Groq (https://console.groq.com/docs/overview): fast, free tier, and an
 * OpenAI-compatible Chat Completions API.
 */

const AI_KEY_PROPERTY = "GROQ_API_KEY";
const GROQ_API_URL = "https://api.groq.com/openai/v1/chat/completions";
const GROQ_DEFAULT_MODEL = "llama-3.3-70b-versatile";

/**
 * Saves the current user's Groq API key.
 * Called from the sidebar via google.script.run. Returns only a boolean —
 * never echoes the key back.
 *
 * @param {string} apiKey - The user's Groq API key (starts with "gsk_").
 * @return {boolean} true on success.
 */
function saveUserApiKey(apiKey) {
	const key = (apiKey || "").trim();
	if (!/^gsk_[A-Za-z0-9]+$/.test(key)) {
		throw new Error(
			"Invalid Groq key. Get one at https://console.groq.com/keys (starts with 'gsk_').",
		);
	}
	PropertiesService.getUserProperties().setProperty(AI_KEY_PROPERTY, key);
	return true;
}

/**
 * Reports whether the current user has a key saved — WITHOUT returning the key.
 * Use this to drive sidebar UI state (e.g. "key set ✓" vs. "enter key").
 *
 * @return {boolean}
 */
function hasUserApiKey() {
	return !!PropertiesService.getUserProperties().getProperty(AI_KEY_PROPERTY);
}

/**
 * Deletes the current user's stored key.
 * @return {boolean} true on success.
 */
function clearUserApiKey() {
	PropertiesService.getUserProperties().deleteProperty(AI_KEY_PROPERTY);
	return true;
}

/**
 * Reusable gate for ANY AI-powered function across ANY module.
 *
 * Usage — put this as the first line of any function that needs AI:
 *
 *   function aiSummarizeSlide() {
 *     if (!ensureApiKey_("aiSummarizeSlide")) return;  // pops the dialog if no key
 *     const result = callGroq_(systemMsg, userMsg);
 *     ...
 *   }
 *
 * If a key exists, returns true and the caller proceeds normally.
 * If not, it opens the key-entry dialog and returns false. After the user
 * saves their key, the dialog re-runs `continueFnName` automatically, so the
 * original action completes without the user having to click again.
 *
 * @param {string} continueFnName - Name of the global function to re-run after
 *   the key is saved. Must be a no-argument global function.
 * @return {boolean} true if a key is already set (proceed); false otherwise.
 */
function ensureApiKey_(continueFnName) {
	if (hasUserApiKey()) return true;
	showApiKeyDialog(continueFnName);
	return false;
}

/**
 * Menu-safe entry point for explicit "set up my AI key" actions.
 * (Menu callbacks receive an event object, so we don't point a menu item
 * directly at showApiKeyDialog — that arg would be treated as continueFnName.)
 */
function showAiKeySetup() {
	showApiKeyDialog();
}

/**
 * Opens the reusable Groq key-entry modal dialog.
 * Can also be wired to a menu item (e.g. "🔑 設定 AI 金鑰") for explicit setup.
 *
 * @param {string} [continueFnName] - Optional function to re-run after saving.
 */
function showApiKeyDialog(continueFnName) {
	const template = HtmlService.createTemplateFromFile(
		"src/components/ai-key-dialog",
	);
	template.continueFnName = continueFnName || "";
	const html = template.evaluate().setWidth(440).setHeight(380);
	SlidesApp.getUi().showModalDialog(html, "🔑 Set up AI");
}

/**
 * Internal: read the current user's key or throw a friendly error.
 * Not exposed to the client.
 *
 * @return {string}
 */
function getUserApiKeyOrThrow_() {
	const key = PropertiesService.getUserProperties().getProperty(
		AI_KEY_PROPERTY,
	);
	if (!key) {
		throw new Error(
			"No API key set. Open the 🔑 API Key panel and paste your Groq key " +
				"(get a free one at https://console.groq.com/keys).",
		);
	}
	return key;
}

/**
 * Calls Groq's chat completions endpoint with the current user's stored key.
 * The key is read server-side here — the client never supplies it.
 *
 * @param {string} systemMessage - System role content.
 * @param {string} userMessage - User role content.
 * @param {Object} [opts] - { model, maxTokens, temperature }.
 * @return {{success: boolean, generatedText?: string, model?: string, usage?: Object, error?: string}}
 */
function callGroq_(systemMessage, userMessage, opts) {
	try {
		const apiKey = getUserApiKeyOrThrow_();
		const options = opts || {};

		const body = {
			model: options.model || GROQ_DEFAULT_MODEL,
			messages: [
				{ role: "system", content: systemMessage },
				{ role: "user", content: userMessage },
			],
			max_tokens: options.maxTokens || 1000,
			temperature: options.temperature != null ? options.temperature : 0.7,
		};

		const response = UrlFetchApp.fetch(GROQ_API_URL, {
			method: "POST",
			contentType: "application/json",
			headers: { Authorization: `Bearer ${apiKey}` },
			payload: JSON.stringify(body),
			muteHttpExceptions: true, // read error bodies without dumping the key into a stack trace
		});

		const code = response.getResponseCode();
		const data = JSON.parse(response.getContentText());

		if (code !== 200) {
			// Log status only — NEVER the request headers/payload (they contain the key).
			console.error("Groq API error: " + code);
			const msg = data && data.error ? data.error.message : "Unknown error";
			return { success: false, error: `Groq API error (${code}): ${msg}` };
		}

		if (!data.choices || data.choices.length === 0) {
			return { success: false, error: "No response generated from Groq API" };
		}

		return {
			success: true,
			generatedText: data.choices[0].message.content.trim(),
			usage: data.usage || {},
			model: data.model || body.model,
		};
	} catch (e) {
		console.error("Error calling Groq API: " + e.message);
		return { success: false, error: e.message, generatedText: "" };
	}
}

// Utility for creating badges in Google Slides
function convertToBadges() {
	const presentation = SlidesApp.getActivePresentation();
	const slide = presentation.getSelection().getCurrentPage();
	const selection = presentation.getSelection();

	const shape = validateSelectedTextBox(selection);
	if (!shape) return;

	const text = shape.getText().asString().trim();
	shape.getParentGroup() ? shape.getParentGroup().remove() : shape.remove();

	const items = text
		.split(",")
		.map((item) => item.trim())
		.filter((item) => item.length > 0);
	items.reverse();
	// Constants
	const fontSize = 10;
	const padding = 2;
	const height = 14;
	const startXRight = 710; // Align to right
	const startY = 350;
	const gap = 3;
	const charWidth = 6.5;
	const minWidth = 40;

	let y = startY;

	items.forEach((item) => {
		const textWidth = Math.max(item.length * charWidth + padding * 2, minWidth);
		const x = startXRight - textWidth; // Align right

		const badge = slide.insertShape(
			SlidesApp.ShapeType.TEXT_BOX,
			x,
			y,
			textWidth,
			height,
		);
		badge.setContentAlignment(SlidesApp.ContentAlignment.MIDDLE);

		// Set background color to blue
		badge.getFill().setSolidFill(main_color); // or use 'blue' named color

		const badgeText = badge.getText();
		badgeText.setText(item);

		// Set font size and font color to white
		badgeText
			.getTextStyle()
			.setFontSize(fontSize)
			.setForegroundColor(base_color); // white

		// Align text to the right
		badgeText
			.getParagraphStyle()
			.setParagraphAlignment(SlidesApp.ParagraphAlignment.END);

		y -= height + gap; // Move to next line
	});
}
// 🔧 Validation Helper Function
function validateSelectedTextBox(selection) {
	const pageElementRange = selection.getPageElementRange();

	if (!pageElementRange) {
		SlidesApp.getUi().alert("請選取一個非空的文字框。");
		return null;
	}

	const selectedElements = pageElementRange.getPageElements();

	if (selectedElements.length !== 1) {
		SlidesApp.getUi().alert("請選取一個文字框。");
		return null;
	}

	const element = selectedElements[0];

	if (element.getPageElementType() !== SlidesApp.PageElementType.SHAPE) {
		SlidesApp.getUi().alert("選取的不是文字框。");
		return null;
	}

	const shape = element.asShape();
	const text = shape.getText().asString().trim();

	if (text === "") {
		SlidesApp.getUi().alert("文字框是空的。");
		return null;
	}

	return shape;
}

/**
 * Utility to center elements by averaging the padding around them
 * This helps to position elements evenly between their neighbors
 */

/**
 * Centers the selected element(s) by averaging the padding from its nearest neighbors
 * in all four directions (top, bottom, left, right)
 * If no neighbors are found in a particular direction, uses the presentation edge
 * 
 * @returns {boolean} True if the operation was successful, false otherwise
 */
function averagePadding() {
  // Get the active presentation and selection
  const presentation = SlidesApp.getActivePresentation();
  const selection = presentation.getSelection();
  const selectionType = selection.getSelectionType();

  // Step 1: Validate that elements are selected
  if (selectionType !== SlidesApp.SelectionType.PAGE_ELEMENT) {
    SlidesApp.getUi().alert('Please select one or more elements');
    return false;
  }

  const pageElements = selection.getPageElementRange().getPageElements();
  if (pageElements.length === 0) {
    SlidesApp.getUi().alert('Please select at least one element');
    return false;
  }

  const currentPage = selection.getCurrentPage();
  const allPageElements = currentPage.getPageElements();

  // Get presentation dimensions
  const slideWidth = presentation.getPageWidth();
  const slideHeight = presentation.getPageHeight();

  // Step 2: Calculate the bounding box of all selected elements
  let minLeft = Infinity;
  let minTop = Infinity;
  let maxRight = 0;
  let maxBottom = 0;

  // Find the extreme coordinates of the selected elements
  pageElements.forEach(element => {
    const left = element.getLeft();
    const top = element.getTop();
    const right = left + element.getWidth();
    const bottom = top + element.getHeight();

    minLeft = Math.min(minLeft, left);
    minTop = Math.min(minTop, top);
    maxRight = Math.max(maxRight, right);
    maxBottom = Math.max(maxBottom, bottom);
  });

  // Calculate the dimensions of the bounding box
  const selectedLeft = minLeft;
  const selectedTop = minTop;
  const selectedWidth = maxRight - minLeft;
  const selectedHeight = maxBottom - minTop;
  const selectedRight = maxRight;
  const selectedBottom = maxBottom;

  // Step 3: Find nearest neighbors in all four directions
  // Create a set of selected element IDs for quick lookup
  const selectedElementIds = new Set();
  pageElements.forEach(element => {
    selectedElementIds.add(element.getObjectId());
  });

  const neighbors = {
    top: findNearestTopNeighbor(selectedLeft, selectedTop, selectedRight, selectedBottom, allPageElements, selectedElementIds),
    bottom: findNearestBottomNeighbor(selectedLeft, selectedTop, selectedRight, selectedBottom, allPageElements, selectedElementIds),
    left: findNearestLeftNeighbor(selectedLeft, selectedTop, selectedRight, selectedBottom, allPageElements, selectedElementIds),
    right: findNearestRightNeighbor(selectedLeft, selectedTop, selectedRight, selectedBottom, allPageElements, selectedElementIds)
  };

  // Step 4: Calculate new position based on average padding
  let newX = selectedLeft;
  let newY = selectedTop;
  let horizontalCentered = false;
  let verticalCentered = false;

  // Calculate horizontal centering
  // If both left and right neighbors exist, center between them
  if (neighbors.left && neighbors.right) {
    const leftEdge = neighbors.left.right;
    const rightEdge = neighbors.right.left;
    const availableWidth = rightEdge - leftEdge;
    newX = leftEdge + (availableWidth - selectedWidth) / 2;
    horizontalCentered = true;
  } 
  // If only left neighbor exists, use slide right edge
  else if (neighbors.left) {
    const leftEdge = neighbors.left.right;
    const rightEdge = slideWidth;
    const availableWidth = rightEdge - leftEdge;
    newX = leftEdge + (availableWidth - selectedWidth) / 2;
    horizontalCentered = true;
  } 
  // If only right neighbor exists, use slide left edge
  else if (neighbors.right) {
    const leftEdge = 0;
    const rightEdge = neighbors.right.left;
    const availableWidth = rightEdge - leftEdge;
    newX = leftEdge + (availableWidth - selectedWidth) / 2;
    horizontalCentered = true;
  }
  // If no horizontal neighbors, center in slide
  else {
    newX = (slideWidth - selectedWidth) / 2;
    horizontalCentered = true;
  }

  // Calculate vertical centering
  // If both top and bottom neighbors exist, center between them
  if (neighbors.top && neighbors.bottom) {
    const topEdge = neighbors.top.bottom;
    const bottomEdge = neighbors.bottom.top;
    const availableHeight = bottomEdge - topEdge;
    newY = topEdge + (availableHeight - selectedHeight) / 2;
    verticalCentered = true;
  }
  // If only top neighbor exists, use slide bottom edge
  else if (neighbors.top) {
    const topEdge = neighbors.top.bottom;
    const bottomEdge = slideHeight;
    const availableHeight = bottomEdge - topEdge;
    newY = topEdge + (availableHeight - selectedHeight) / 2;
    verticalCentered = true;
  }
  // If only bottom neighbor exists, use slide top edge
  else if (neighbors.bottom) {
    const topEdge = 0;
    const bottomEdge = neighbors.bottom.top;
    const availableHeight = bottomEdge - topEdge;
    newY = topEdge + (availableHeight - selectedHeight) / 2;
    verticalCentered = true;
  }
  // If no vertical neighbors, center in slide
  else {
    newY = (slideHeight - selectedHeight) / 2;
    verticalCentered = true;
  }

  // Step 5: Calculate the amount to move each element
  const deltaX = newX - selectedLeft;
  const deltaY = newY - selectedTop;

  // Apply the movement to all selected elements
  pageElements.forEach(element => {
    const currentLeft = element.getLeft();
    const currentTop = element.getTop();

    element.setLeft(currentLeft + deltaX);
    element.setTop(currentTop + deltaY);
  });

  // Log the operation for debugging
  console.log(`Centered ${pageElements.length} elements. Moved by: X=${deltaX}, Y=${deltaY}`);

  return true;
}

/**
 * Finds the nearest element above the selected elements
 * 
 * @param {number} selectedLeft - Left coordinate of the selection bounding box
 * @param {number} selectedTop - Top coordinate of the selection bounding box
 * @param {number} selectedRight - Right coordinate of the selection bounding box
 * @param {number} selectedBottom - Bottom coordinate of the selection bounding box
 * @param {PageElement[]} allElements - All elements on the current slide
 * @param {Set<string>} selectedElementIds - Set of IDs of the selected elements to exclude
 * @returns {Object|null} The nearest top neighbor's information or null if none found
 */
function findNearestTopNeighbor(selectedLeft, selectedTop, selectedRight, selectedBottom, allElements, selectedElementIds) {
  let nearestDistance = Infinity;
  let nearestElement = null;

  for (const element of allElements) {
    // Skip if it's one of the selected elements
    if (selectedElementIds.has(element.getObjectId())) continue;

    const elementBottom = element.getTop() + element.getHeight();
    const elementLeft = element.getLeft();
    const elementRight = elementLeft + element.getWidth();

    // Check if the element is above the selected elements
    if (elementBottom < selectedTop) {
      // Check if there's horizontal overlap
      const hasHorizontalOverlap = 
        (elementLeft <= selectedRight && elementRight >= selectedLeft);

      if (hasHorizontalOverlap) {
        const distance = selectedTop - elementBottom;
        if (distance < nearestDistance) {
          nearestDistance = distance;
          nearestElement = {
            element: element,
            bottom: elementBottom,
            distance: distance
          };
        }
      }
    }
  }

  return nearestElement;
}

/**
 * Finds the nearest element below the selected elements
 * 
 * @param {number} selectedLeft - Left coordinate of the selection bounding box
 * @param {number} selectedTop - Top coordinate of the selection bounding box
 * @param {number} selectedRight - Right coordinate of the selection bounding box
 * @param {number} selectedBottom - Bottom coordinate of the selection bounding box
 * @param {PageElement[]} allElements - All elements on the current slide
 * @param {Set<string>} selectedElementIds - Set of IDs of the selected elements to exclude
 * @returns {Object|null} The nearest bottom neighbor's information or null if none found
 */
function findNearestBottomNeighbor(selectedLeft, selectedTop, selectedRight, selectedBottom, allElements, selectedElementIds) {
  let nearestDistance = Infinity;
  let nearestElement = null;

  for (const element of allElements) {
    // Skip if it's one of the selected elements
    if (selectedElementIds.has(element.getObjectId())) continue;

    const elementTop = element.getTop();
    const elementLeft = element.getLeft();
    const elementRight = elementLeft + element.getWidth();

    // Check if the element is below the selected elements
    if (elementTop > selectedBottom) {
      // Check if there's horizontal overlap
      const hasHorizontalOverlap = 
        (elementLeft <= selectedRight && elementRight >= selectedLeft);

      if (hasHorizontalOverlap) {
        const distance = elementTop - selectedBottom;
        if (distance < nearestDistance) {
          nearestDistance = distance;
          nearestElement = {
            element: element,
            top: elementTop,
            distance: distance
          };
        }
      }
    }
  }

  return nearestElement;
}

/**
