/**
 * Server-side core for the Bar Chart Minter (簡易長條圖鑄造器) dialog.
 *
 * Draws a lightweight, shapes-based bar chart directly onto the current slide —
 * no embedded Google Sheets chart. Each bar is a RECTANGLE scaled
 * proportionally to its value within a fixed chart area, with category labels
 * and (optionally) value labels. All pieces are grouped at the end.
 *
 * Mirrors the Callout Minter pattern (src/util/callout_minter.js): built with
 * the SlidesApp service (not the batch API) so the inserted shapes can be read
 * back and grouped afterwards.
 *
 * Input format (one bar per line): `label | value`
 *   2022 | 12
 *   2023 | 18
 *   2024 | 27
 */

/**
 * Single source of truth for bar-chart color templates. Colors resolve from the
 * global palette (main_color / accent_color / sub1_color …) so they track the
 * configured theme.
 *
 * - main / accent: a single fill color applied to every bar.
 * - multi: cycles a small palette per bar.
 *
 * @return {Array<{id,name,mode,fill?,palette?}>}
 */
function buildBarChartTemplates_() {
	const main = (typeof main_color !== "undefined" && main_color) || "#3D6869";
	const accent =
		(typeof accent_color !== "undefined" && accent_color) || "#f29424";
	const sub1 = (typeof sub1_color !== "undefined" && sub1_color) || "#E7EAE7";
	return [
		{ id: "main", name: "主色 Main", mode: "single", fill: main },
		{ id: "accent", name: "強調 Accent", mode: "single", fill: accent },
		{
			id: "multi",
			name: "多彩 Multi",
			mode: "multi",
			palette: [main, accent, "#2E7D32", "#C0392B", "#2D6CDF", "#8E44AD", sub1],
		},
	];
}

/**
 * Returns the bar-chart templates for client-side preview. Called from the
 * dialog through google.script.run.
 * @return {Array<Object>}
 */
function getBarChartTemplates() {
	return buildBarChartTemplates_();
}

/**
 * Groq system prompt for turning free-form context into bar-chart data lines.
 * Output is ONLY `label | value` lines (value numeric), nothing else.
 */
var BARCHART_AI_SYSTEM_PROMPT = [
	"You convert the user's content into bar-chart data.",
	"Output ONLY data lines, one bar per line, in EXACTLY this format:",
	"label | value",
	"Example:",
	"2022 | 12",
	"2023 | 18",
	"2024 | 27",
	"Strict rules:",
	"- No preamble, no explanation, no closing remarks, no code fences.",
	"- Produce between 3 and 8 bars.",
	"- The value MUST be a number. Strip units, currency symbols, and % signs; keep only the number.",
	"- Keep labels short.",
	"- Do not invent data that isn't implied by the input.",
].join("\n");

/**
 * Generates bar-chart data (`label | value` lines) from free-form context via
 * Groq. Called from the dialog through google.script.run.
 *
 * @param {string} context - Arbitrary text the user pasted.
 * @return {{success: boolean, generatedText?: string, error?: string, needKey?: boolean}}
 */
function generateBarChartFromContext(context) {
	const text = (context || "").trim();
	if (!text) {
		return { success: false, error: "No context provided." };
	}

	// Don't throw on a missing key — let the dialog show a friendly prompt to
	// run the explicit "🔑 設定 AI 金鑰 (Groq)" menu item.
	if (!hasUserApiKey()) {
		return {
			success: false,
			needKey: true,
			error:
				"No AI key set. Run 🖖 跨頁功能 → 🔑 設定 AI 金鑰 (Groq) first, then try again.",
		};
	}

	return callGroq_(BARCHART_AI_SYSTEM_PROMPT, text, {
		maxTokens: 1500,
		temperature: 0.3,
	});
}

/**
 * Parses `label | value` lines into {label, value} bars. Non-numeric values are
 * treated as 0 (and the line is kept, so the category still shows). Lines
 * without a separator use the whole line as the label with value 0.
 *
 * @param {Array<{label:string, value:(number|string)}>|string} data
 * @return {Array<{label:string, value:number}>}
 */
function parseBarChartData_(data) {
	const out = [];

	// Accept either an already-structured array (from the dialog) or raw text.
	if (Array.isArray(data)) {
		for (let i = 0; i < data.length; i++) {
			const row = data[i] || {};
			const label = String(row.label != null ? row.label : "").trim();
			let value = Number(row.value);
			if (!isFinite(value)) value = 0;
			if (label || value) out.push({ label: label, value: value });
		}
		return out;
	}

	const text = String(data || "").replace(/\r\n/g, "\n");
	const lines = text.split("\n");
	for (let i = 0; i < lines.length; i++) {
		const line = lines[i].trim();
		if (!line) continue;
		const parts = line.split("|");
		const label = (parts[0] || "").trim();
		let value = 0;
		if (parts.length > 1) {
			const raw = (parts[1] || "").trim().replace(/[, ]+/g, "");
			const n = parseFloat(raw);
			value = isFinite(n) ? n : 0;
		}
		out.push({ label: label, value: value });
	}
	return out;
}

/**
 * Inserts a shapes-based bar chart onto the current slide.
 *
 * Chart geometry: a fixed chart area (width 600, height 260) starting at
 * X ~60, vertically centered. Bars are scaled proportionally to the max value.
 * Vertical bars grow upward from a baseline; horizontal bars grow rightward
 * from a left axis. Category labels sit under (vertical) or beside (horizontal)
 * each bar, and value labels sit at the bar end when enabled. All shapes are
 * grouped.
 *
 * @param {{data: Array<{label:string,value:(number|string)}>, templateId: string,
 *   orientation: string, showValues: boolean}} payload
 * @return {{success: boolean, error?: string}}
 */
function insertBarChartIntoSlide(payload) {
	try {
		const p = payload || {};
		const bars = parseBarChartData_(p.data);
		if (!bars.length) {
			return { success: false, error: "No data. Use `label | value` per line." };
		}

		const templates = buildBarChartTemplates_();
		let tpl = templates[0];
		for (let i = 0; i < templates.length; i++) {
			if (templates[i].id === p.templateId) tpl = templates[i];
		}
		const palette =
			tpl.mode === "multi" && tpl.palette && tpl.palette.length
				? tpl.palette
				: [tpl.fill || "#3D6869"];
		const colorFor = (i) => palette[i % palette.length];

		const orientation = p.orientation === "horizontal" ? "horizontal" : "vertical";
		const showValues = p.showValues !== false;
		const font =
			(typeof main_font_family !== "undefined" && main_font_family) ||
			"Source Sans Pro";
		const axisColor = "#999999";

		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();
		let slide = null;
		try {
			slide = selection.getCurrentPage().asSlide();
		} catch (e) {
			slide = presentation.getSlides()[0];
		}
		if (!slide) return { success: false, error: "No slide available." };

		// Fixed chart area, vertically centered on the slide.
		const chartW = 600;
		const chartH = 260;
		const startX = 60;
		const pageH = presentation.getPageHeight();
		const startY = Math.max((pageH - chartH) / 2, 30);

		// Max value drives the scale. Guard against all-zero / negative data.
		let maxVal = 0;
		for (let i = 0; i < bars.length; i++) {
			if (bars[i].value > maxVal) maxVal = bars[i].value;
		}
		if (maxVal <= 0) maxVal = 1;

		const n = bars.length;
		const labelH = 18; // space reserved for category labels
		const valueH = 16; // space reserved for value labels at the bar end
		const group = [];

		if (orientation === "vertical") {
			// Baseline sits above the category labels; bars grow upward from it.
			const baselineY = startY + chartH - labelH;
			const plotH = chartH - labelH - valueH; // usable bar height
			const slot = chartW / n;
			const barW = Math.max(8, slot * 0.6);

			// Baseline (a thin horizontal rectangle).
			const baseline = slide.insertShape(
				SlidesApp.ShapeType.RECTANGLE,
				startX,
				baselineY,
				chartW,
				1.5,
			);
			baseline.getFill().setSolidFill(axisColor);
			baseline.getBorder().getLineFill().setSolidFill(axisColor);
			group.push(baseline);

			for (let i = 0; i < n; i++) {
				const v = Math.max(0, bars[i].value);
				const h = (v / maxVal) * plotH;
				const cx = startX + slot * i + slot / 2;
				const barX = cx - barW / 2;
				const barY = baselineY - h;

				if (h > 0) {
					const bar = slide.insertShape(
						SlidesApp.ShapeType.RECTANGLE,
						barX,
						barY,
						barW,
						h,
					);
					bar.getFill().setSolidFill(colorFor(i));
					bar.getBorder().getLineFill().setSolidFill(colorFor(i));
					group.push(bar);
				}

				// Value label above the bar.
				if (showValues) {
					const valShape = slide.insertShape(
						SlidesApp.ShapeType.TEXT_BOX,
						cx - slot / 2,
						barY - valueH,
						slot,
						valueH,
					);
					valShape.getText().setText(formatBarValue_(bars[i].value));
					styleBarLabel_(valShape, font, 9, "#333333", true);
					group.push(valShape);
				}

				// Category label below the baseline.
				const catShape = slide.insertShape(
					SlidesApp.ShapeType.TEXT_BOX,
					cx - slot / 2,
					baselineY + 2,
					slot,
					labelH,
				);
				catShape.getText().setText(bars[i].label || "");
				styleBarLabel_(catShape, font, 9, "#555555", false);
				group.push(catShape);
			}
		} else {
			// Horizontal bars: vertical axis on the left, bars grow rightward.
			const labelW = 90; // space reserved for category labels on the left
			const axisX = startX + labelW;
			const plotW = chartW - labelW - 40; // leave room for value labels
			const slot = chartH / n;
			const barH = Math.max(8, slot * 0.6);

			// Vertical axis.
			const axis = slide.insertShape(
				SlidesApp.ShapeType.RECTANGLE,
				axisX,
				startY,
				1.5,
				chartH,
			);
			axis.getFill().setSolidFill(axisColor);
			axis.getBorder().getLineFill().setSolidFill(axisColor);
			group.push(axis);

			for (let i = 0; i < n; i++) {
				const v = Math.max(0, bars[i].value);
				const w = (v / maxVal) * plotW;
				const cy = startY + slot * i + slot / 2;
				const barY = cy - barH / 2;

				if (w > 0) {
					const bar = slide.insertShape(
						SlidesApp.ShapeType.RECTANGLE,
						axisX,
						barY,
						w,
						barH,
					);
					bar.getFill().setSolidFill(colorFor(i));
					bar.getBorder().getLineFill().setSolidFill(colorFor(i));
					group.push(bar);
				}

				// Category label to the left of the axis.
				const catShape = slide.insertShape(
					SlidesApp.ShapeType.TEXT_BOX,
					startX,
					cy - slot / 2,
					labelW - 4,
					slot,
				);
				catShape.getText().setText(bars[i].label || "");
				styleBarLabel_(catShape, font, 9, "#555555", false);
				catShape.setContentAlignment(SlidesApp.ContentAlignment.MIDDLE);
				try {
					catShape
						.getText()
						.getParagraphStyle()
						.setParagraphAlignment(SlidesApp.ParagraphAlignment.END);
				} catch (e) {}
				group.push(catShape);

				// Value label at the bar end.
				if (showValues) {
					const valShape = slide.insertShape(
						SlidesApp.ShapeType.TEXT_BOX,
						axisX + w + 2,
						cy - valueH / 2,
						60,
						valueH,
					);
					valShape.getText().setText(formatBarValue_(bars[i].value));
					styleBarLabel_(valShape, font, 9, "#333333", true);
					valShape.setContentAlignment(SlidesApp.ContentAlignment.MIDDLE);
					try {
						valShape
							.getText()
							.getParagraphStyle()
							.setParagraphAlignment(SlidesApp.ParagraphAlignment.START);
					} catch (e) {}
					group.push(valShape);
				}
			}
		}

		if (group.length > 1) slide.group(group);

		return { success: true };
	} catch (e) {
		console.error("Error inserting bar chart: " + e.message);
		return { success: false, error: e.message };
	}
}

/**
 * Applies common label styling (font, size, color, optional bold, center
 * alignment) to a label text box. Wrapped in try/catch so empty text boxes
 * don't throw.
 *
 * @param {GoogleAppsScript.Slides.Shape} shape
 * @param {string} font
 * @param {number} size
 * @param {string} color
 * @param {boolean} bold
 */
function styleBarLabel_(shape, font, size, color, bold) {
	try {
		const t = shape.getText();
		t.getTextStyle()
			.setForegroundColor(color)
			.setFontFamily(font)
			.setFontSize(size)
			.setBold(!!bold);
		t.getParagraphStyle().setParagraphAlignment(
			SlidesApp.ParagraphAlignment.CENTER,
		);
	} catch (e) {
		// empty text box — ignore
	}
	try {
		shape.getBorder().setTransparent();
	} catch (e) {}
}

/**
 * Formats a numeric value for the value label: integers stay whole, decimals
 * are trimmed to at most one place.
 *
 * @param {number} v
 * @return {string}
 */
function formatBarValue_(v) {
	const n = Number(v);
	if (!isFinite(n)) return "0";
	if (Math.round(n) === n) return String(n);
	return String(Math.round(n * 10) / 10);
}

// Utility for creating and managing boxes in Google Slides
function createStyledBoxesOnCurrentSlide() {
	const ui = SlidesApp.getUi();
	const slideWidth = SlidesApp.getActivePresentation().getPageWidth();
	const slideHeight = SlidesApp.getActivePresentation().getPageHeight();
	const response = ui.prompt(
		"Create Boxes",
		"Enter the number of boxes to create:",
		ui.ButtonSet.OK_CANCEL,
	);

	if (response.getSelectedButton() !== ui.Button.OK) return;

	const n = parseInt(response.getResponseText());

	if (isNaN(n) || n <= 0) {
		ui.alert("Invalid input. Please enter a positive number.");
		return;
	}

	const selection = SlidesApp.getActivePresentation().getSelection();
	const currentSlide = selection.getCurrentPage();

	if (!currentSlide) {
		ui.alert("No slide is currently selected.");
		return;
	}
	const boxWidth = 200;
	const boxHeight = 60;
	const verticalSpacing = 15;
	const startY = 100;

	for (let i = 0; i < n; i++) {
		const x = (slideWidth - boxWidth) / 2;
		const y = startY + i * (boxHeight + verticalSpacing);

		const box = currentSlide.insertTextBox("", x, y, boxWidth, boxHeight);
		box.setContentAlignment(SlidesApp.ContentAlignment.MIDDLE); // Vertically center

		const textRange = box.getText();
		textRange.setText("Box " + (i + 1));
		textRange.getTextStyle().setFontSize(20);
		textRange.getTextStyle().setForegroundColor(base_color);
		textRange
			.getParagraphStyle()
			.setParagraphAlignment(SlidesApp.ParagraphAlignment.CENTER); // Horizontally center

		box.getFill().setSolidFill(main_color); // Blue background
	}

	ui.alert(`${n} fully centered boxes created on the current slide.`);
}

/**
 * Server-side core for the Callout Minter dialog.
 *
 * Replaces the old convertShapeToCallout() one-shot menu action with a
 * minter-style dialog (template picker + header/body inputs + HTML preview).
 *
 * Two modes, auto-detected on insert:
 *  - Convert: a shape/text box is selected → restyle it as the callout body and
 *    add the header banner + left accent bar around it.
 *  - Insert: nothing selected → drop a brand-new callout on the current slide.
 *
 * Built with the SlidesApp service (not the batch API) because both modes need
 * to read the element's geometry and group the pieces afterwards.
 */

/**
 * Single source of truth for callout templates. Colors resolve from the global
 * palette (main_color / accent_color) so they track the configured theme.
 * style: 'banner' = top header + left bar; 'quote' = left bar only, no header.
 *
 * @return {Array<{id,name,headerLabel,style,headerFill,headerText,barColor,bodyFill,bodyBorder,bodyText}>}
 */
function buildCalloutTemplates_() {
	const main = (typeof main_color !== "undefined" && main_color) || "#3D6869";
	const accent =
		(typeof accent_color !== "undefined" && accent_color) || "#f29424";
	const green = "#2E7D32";
	const red = "#C0392B";
	return [
		{
			id: "info", name: "INFO", headerLabel: "INFO", style: "banner",
			headerFill: "#E7EAE7", headerText: main, barColor: main,
			bodyFill: "#FFFFFF", bodyBorder: main, bodyText: "#000000",
		},
		{
			id: "note", name: "NOTE", headerLabel: "NOTE", style: "banner",
			headerFill: main, headerText: "#FFFFFF", barColor: main,
			bodyFill: "#FFFFFF", bodyBorder: main, bodyText: "#000000",
		},
		{
			id: "tip", name: "TIP", headerLabel: "TIP", style: "banner",
			headerFill: "#E7F4EC", headerText: green, barColor: green,
			bodyFill: "#FFFFFF", bodyBorder: green, bodyText: "#000000",
		},
		{
			id: "success", name: "SUCCESS", headerLabel: "SUCCESS", style: "banner",
			headerFill: green, headerText: "#FFFFFF", barColor: green,
			bodyFill: "#FFFFFF", bodyBorder: green, bodyText: "#000000",
		},
		{
			id: "warning", name: "WARNING", headerLabel: "WARNING", style: "banner",
			headerFill: "#FCEAD2", headerText: "#B26A00", barColor: accent,
			bodyFill: "#FFFFFF", bodyBorder: accent, bodyText: "#000000",
		},
		{
			id: "danger", name: "DANGER", headerLabel: "DANGER", style: "banner",
			headerFill: red, headerText: "#FFFFFF", barColor: red,
			bodyFill: "#FFFFFF", bodyBorder: red, bodyText: "#000000",
		},
		{
			id: "quote", name: "QUOTE", headerLabel: "", style: "quote",
			headerFill: "", headerText: "", barColor: "#999999",
			bodyFill: "#F7F7F7", bodyBorder: "#F7F7F7", bodyText: "#333333",
		},
	];
}

/**
 * Returns the callout templates for client-side preview. Called from the dialog
 * through google.script.run.
 * @return {Array<Object>}
 */
function getCalloutTemplates() {
	return buildCalloutTemplates_();
}

/**
 * Groq system prompt for turning free-form context into a single callout. The
 * model must reply with EXACTLY two lines — a tiny HEADER label and a concise
 * BODY — and nothing else, so the dialog can map them straight to its fields.
 */
var CALLOUT_AI_SYSTEM_PROMPT = [
	"You convert the user's content into ONE callout (highlight box).",
	"Output EXACTLY two lines and nothing else:",
	"First line:  HEADER: <a very short label, 1-3 words>",
	"Second line: BODY: <one or two concise sentences>",
	"Strict rules:",
	"- No preamble, no explanation, no closing remarks, no code fences.",
	"- Keep the header tiny (e.g. 重點 / 注意 / INFO).",
	"- Keep the body concise; do not invent facts not implied by the input.",
].join("\n");

/**
 * Generates a callout (HEADER + BODY) from free-form context via Groq.
 * Called from the dialog through google.script.run.
 *
 * @param {string} context - Arbitrary text the user pasted.
 * @return {{success: boolean, generatedText?: string, error?: string, needKey?: boolean}}
 */
function generateCalloutFromContext(context) {
	const text = (context || "").trim();
	if (!text) {
		return { success: false, error: "No context provided." };
	}

	// Don't throw on a missing key — let the dialog show a friendly prompt to
	// run the explicit "🔑 設定 AI 金鑰 (Groq)" menu item.
	if (!hasUserApiKey()) {
		return {
			success: false,
			needKey: true,
			error:
				"No AI key set. Run 🖖 跨頁功能 → 🔑 設定 AI 金鑰 (Groq) first, then try again.",
		};
	}

	return callGroq_(CALLOUT_AI_SYSTEM_PROMPT, text, {
		maxTokens: 500,
		temperature: 0.3,
	});
}

/**
 * Inserts (or converts a selection into) a styled callout.
 *
 * @param {{templateId: string, header: string, body: string}} payload
 * @return {{success: boolean, error?: string, mode?: string}}
 */
function insertCalloutIntoSlide(payload) {
	try {
		const p = payload || {};
		const templates = buildCalloutTemplates_();
		let tpl = templates[0];
		for (let i = 0; i < templates.length; i++) {
			if (templates[i].id === p.templateId) tpl = templates[i];
		}
		const header = (p.header != null ? p.header : tpl.headerLabel) || "";
		const body = p.body || "";
		const font =
			(typeof main_font_family !== "undefined" && main_font_family) ||
			"Source Sans Pro";

		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();

		// Convert mode: a shape or text box is selected.
		let mainElement = null;
		let slide = null;
		let mode = "insert";
		if (selection.getSelectionType() === SlidesApp.SelectionType.PAGE_ELEMENT) {
			const els = selection.getPageElementRange().getPageElements();
			const el = els && els[0];
			if (el) {
				const t = el.getPageElementType();
				if (t === SlidesApp.PageElementType.SHAPE) {
					mainElement = el.asShape();
				} else if (t === SlidesApp.PageElementType.TEXT_BOX) {
					mainElement = el.asTextBox();
				}
				if (mainElement) {
					slide = el.getParentPage();
					mode = "convert";
				}
			}
		}

		// Insert mode: no usable selection → create a new body text box.
		if (!mainElement) {
			try {
				slide = selection.getCurrentPage().asSlide();
			} catch (e) {
				slide = presentation.getSlides()[0];
			}
			if (!slide) return { success: false, error: "No slide available." };
			const W = 320;
			const H = 120;
			const X = Math.max((presentation.getPageWidth() - W) / 2, 0);
			const Y = 140;
			mainElement = slide.insertShape(SlidesApp.ShapeType.TEXT_BOX, X, Y, W, H);
			mainElement.getText().setText(body || "Your text here…");
		} else if (body) {
			// Convert mode: only overwrite text when the user typed some.
			mainElement.getText().setText(body);
		}

		// Style the main (body) element.
		mainElement.getFill().setSolidFill(tpl.bodyFill);
		mainElement.getBorder().getLineFill().setSolidFill(tpl.bodyBorder);
		mainElement.getBorder().setWeight(1);
		try {
			const mt = mainElement.getText();
			mt.getTextStyle().setForegroundColor(tpl.bodyText).setFontFamily(font);
			mt.getParagraphStyle().setParagraphAlignment(
				SlidesApp.ParagraphAlignment.START,
			);
		} catch (e) {
			// no text — ignore
		}

		const mx = mainElement.getLeft();
		const my = mainElement.getTop();
		const mw = mainElement.getWidth();
		const mh = mainElement.getHeight();

		const group = [];

		// Header banner (banner style with a non-empty header only).
		const headerH = 20;
		const showHeader = tpl.style === "banner" && header;
		const topOffset = showHeader ? headerH : 0;
		if (showHeader) {
			const headerShape = slide.insertShape(
				SlidesApp.ShapeType.RECTANGLE,
				mx,
				my - headerH,
				mw,
				headerH,
			);
			headerShape.getFill().setSolidFill(tpl.headerFill);
			headerShape.getBorder().getLineFill().setSolidFill(tpl.bodyBorder);
			headerShape.getBorder().setWeight(1);
			headerShape.getText().setText(header);
			headerShape
				.getText()
				.getTextStyle()
				.setForegroundColor(tpl.headerText)
				.setBold(true)
				.setFontSize(12)
				.setFontFamily(font);
			headerShape
				.getText()
				.getParagraphStyle()
				.setParagraphAlignment(SlidesApp.ParagraphAlignment.START);
			headerShape.setContentAlignment(SlidesApp.ContentAlignment.MIDDLE);
			group.push(headerShape);
		}

		// Left accent bar (spans the header + body).
		const barW = 3;
		const barShape = slide.insertShape(
			SlidesApp.ShapeType.RECTANGLE,
			mx - barW,
			my - topOffset,
			barW,
			mh + topOffset,
		);
		barShape.getFill().setSolidFill(tpl.barColor);
		barShape.getBorder().getLineFill().setSolidFill(tpl.barColor);
		group.push(barShape);

		group.push(mainElement);
		if (group.length > 1) slide.group(group);

		return { success: true, mode: mode };
	} catch (e) {
		console.error("Error inserting callout: " + e.message);
		return { success: false, error: e.message };
	}
}

// Utility for managing chains of titles in Google Slides
function copyPreviousTitleText() {
	const presentation = SlidesApp.getActivePresentation();
	const slides = presentation.getSlides();
	const currentSlide = presentation.getSelection().getCurrentPage();
	const currentIndex = slides.findIndex(
		(slide) => slide.getObjectId() === currentSlide.getObjectId(),
	);

	if (currentIndex <= 0) {
		return;
	}

	// === Step 1: Remove existing 'PREVIOUS_TITLE' from current slide ===
	const currentElements = currentSlide.getPageElements();
	for (const element of currentElements) {
		if (
			element.getPageElementType() === SlidesApp.PageElementType.SHAPE &&
			element.getTitle() === "PREVIOUS_TITLE"
		) {
			element.remove();
		}
	}

	// === Step 2: Try to get text from previous slide ===
	const previousSlide = slides[currentIndex - 1];
	const pageElements = previousSlide.getPageElements();
	let titleText = "";

	// Try to find shape with title "PREVIOUS_TITLE"
	for (const element of pageElements) {
		if (
			element.getPageElementType() === SlidesApp.PageElementType.SHAPE &&
			element.getTitle() === "PREVIOUS_TITLE"
		) {
			const text = element.asShape().getText().asString().trim();
			if (text.length > 0) {
				titleText = text;
				break;
			}
		}
	}

	// Fallback: first non-empty text shape
	if (!titleText) {
		for (const element of pageElements) {
			if (element.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
				const shape = element.asShape();
				const text = shape.getText().asString().trim();
				if (text.length > 0) {
					titleText = text;
					break;
				}
			}
		}
	}

	if (!titleText) {
		return;
	}
	// === Step 3: Insert new text box on current slide ===
	const newShape = currentSlide.insertTextBox(titleText, 24, 18, 500, 25);
	newShape.setTitle("PREVIOUS_TITLE");

	// === Step 4: Style it ===
	const textRange = newShape.getText();
	textRange.getTextStyle().setFontSize(12);
	textRange.getTextStyle().setForegroundColor("#888888");
}

function createNextSlideWithCurrentTitle() {
	const presentation = SlidesApp.getActivePresentation();
	const slides = presentation.getSlides();
	const currentPageId = presentation
		.getSelection()
		.getCurrentPage()
		.getObjectId();

	// Find current slide index
	const currentIndex = slides.findIndex(
		(slide) => slide.getObjectId() === currentPageId,
	);
	if (currentIndex < 0 || currentIndex >= slides.length) {
		Logger.log("Current slide not found.");
		return;
	}

	const currentSlide = slides[currentIndex];

	// ✅ Fix: Get layout using indexed slide reference
	const layout = slides[currentIndex].getLayout();
	const layoutName = layout ? layout.getLayoutName() : "No layout";
	Logger.log("Current slide layout: " + layoutName);

	// Create new slide after current with same layout
	const newSlide = presentation.insertSlide(currentIndex + 1, layout);
	Logger.log("Inserted new slide after current one.");

	// Try to get text from shape titled 'PREVIOUS_TITLE'
	const pageElements = currentSlide.getPageElements();
	let titleText = "";

	for (const element of pageElements) {
		if (
			element.getPageElementType() === SlidesApp.PageElementType.SHAPE &&
			element.getTitle() === "PREVIOUS_TITLE"
		) {
			const text = element.asShape().getText().asString().trim();
			if (text.length > 0) {
				titleText = text;
				Logger.log("Found text via title 'PREVIOUS_TITLE': " + titleText);
				break;
			}
		}
	}
	// Fallback: use first non-empty text box
	if (!titleText) {
		for (const element of pageElements) {
			if (element.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
				const shape = element.asShape();
				const text = shape.getText().asString().trim();
				if (text.length > 0) {
					titleText = text;
					Logger.log("Fallback: Found first non-empty text: " + titleText);
					break;
				}
			}
		}
	}
	if (!titleText) {
		Logger.log("No suitable text found on current slide.");
		return;
	}
	insertStyledTitleBox(newSlide, titleText, "#888888");
}

function insertStyledTitleBox(slide, titleText, color) {
	// Insert styled text box at fixed position and size
	const newShape = slide.insertTextBox(titleText, 24, 18, 200, 25);
	newShape.setTitle("PREVIOUS_TITLE");
	// Apply font styling
	const textRange = newShape.getText();
	textRange.getTextStyle().setFontSize(12);
	textRange.getTextStyle().setForegroundColor(color);
}

/**
 * 配色方案生成器工具
 * 基於色彩理論計算多種配色風格
 */

/**
 * 將 HEX 顏色轉換為 HSL
 * @param {string} hex - HEX 顏色值 (#RRGGBB)
 * @returns {Object} {h, s, l} HSL 值
 */
function hexToHsl(hex) {
	// 移除 # 符號
	hex = hex.replace("#", "");

	// 轉換為 RGB
	const r = parseInt(hex.substr(0, 2), 16) / 255;
	const g = parseInt(hex.substr(2, 2), 16) / 255;
	const b = parseInt(hex.substr(4, 2), 16) / 255;

	const max = Math.max(r, g, b);
	const min = Math.min(r, g, b);
	let h,
		s,
		l = (max + min) / 2;

	if (max === min) {
		h = s = 0; // 灰色
	} else {
		const d = max - min;
		s = l > 0.5 ? d / (2 - max - min) : d / (max + min);

		switch (max) {
			case r:
				h = (g - b) / d + (g < b ? 6 : 0);
				break;
			case g:
				h = (b - r) / d + 2;
				break;
			case b:
				h = (r - g) / d + 4;
				break;
		}
		h /= 6;
	}

	return {
		h: Math.round(h * 360),
		s: Math.round(s * 100),
		l: Math.round(l * 100),
	};
}

/**
 * 將 HSL 顏色轉換為 HEX
 * @param {number} h - 色相 (0-360)
 * @param {number} s - 飽和度 (0-100)
 * @param {number} l - 亮度 (0-100)
 * @returns {string} HEX 顏色值
 */
function hslToHex(h, s, l) {
	h = h % 360;
	s = Math.max(0, Math.min(100, s)) / 100;
	l = Math.max(0, Math.min(100, l)) / 100;

	const c = (1 - Math.abs(2 * l - 1)) * s;
	const x = c * (1 - Math.abs(((h / 60) % 2) - 1));
	const m = l - c / 2;
	let r = 0,
		g = 0,
		b = 0;

	if (0 <= h && h < 60) {
		r = c;
		g = x;
		b = 0;
	} else if (60 <= h && h < 120) {
		r = x;
		g = c;
		b = 0;
	} else if (120 <= h && h < 180) {
		r = 0;
		g = c;
		b = x;
	} else if (180 <= h && h < 240) {
		r = 0;
		g = x;
		b = c;
	} else if (240 <= h && h < 300) {
		r = x;
		g = 0;
		b = c;
	} else if (300 <= h && h < 360) {
		r = c;
		g = 0;
		b = x;
	}

	r = Math.round((r + m) * 255);
	g = Math.round((g + m) * 255);
	b = Math.round((b + m) * 255);

	return (
		"#" +
		[r, g, b]
			.map((x) => {
				const hex = x.toString(16);
				return hex.length === 1 ? "0" + hex : hex;
			})
			.join("")
	);
}

/**
 * 驗證 HEX 顏色格式
 * @param {string} hex - HEX 顏色值
 * @returns {boolean} 是否為有效的 HEX 格式
 */
function isValidHex(hex) {
	const hexRegex = /^#?([A-Fa-f0-9]{6}|[A-Fa-f0-9]{3})$/;
	return hexRegex.test(hex);
}

/**
 * 標準化 HEX 顏色格式
 * @param {string} hex - HEX 顏色值
 * @returns {string} 標準化後的 HEX 顏色值 (#RRGGBB)
 */
function normalizeHex(hex) {
	hex = hex.replace("#", "");

	// 將 3 位 HEX 轉換為 6 位
	if (hex.length === 3) {
		hex = hex
			.split("")
			.map((char) => char + char)
			.join("");
	}

	return "#" + hex.toUpperCase();
}

/**
 * 單色系配色方案（Monochromatic）
 * 基於不同的亮度和飽和度變化
 * @param {string} baseHex - 主色 HEX 值
 * @returns {Array} 5 個顏色的 HEX 陣列
 */
function generateMonochromatic(baseHex) {
	const hsl = hexToHsl(baseHex);
	const colors = [];

	// 主色
	colors.push(baseHex);

	// 更深的變化（降低亮度）
	colors.push(hslToHex(hsl.h, hsl.s, Math.max(10, hsl.l - 30)));

	// 更淺的變化（提高亮度）
	colors.push(hslToHex(hsl.h, hsl.s, Math.min(90, hsl.l + 30)));

	// 降低飽和度
	colors.push(hslToHex(hsl.h, Math.max(10, hsl.s - 40), hsl.l));

	// 提高飽和度
	colors.push(hslToHex(hsl.h, Math.min(100, hsl.s + 20), hsl.l));

	return colors;
}

/**
 * 類似色配色方案（Analogous）
 * 使用色相環上相鄰的顏色
 * @param {string} baseHex - 主色 HEX 值
 * @returns {Array} 5 個顏色的 HEX 陣列
 */
function generateAnalogous(baseHex) {
	const hsl = hexToHsl(baseHex);
	const colors = [];

	// 主色
	colors.push(baseHex);

	// 左側相鄰色 (-30度)
	colors.push(hslToHex((hsl.h - 30 + 360) % 360, hsl.s, hsl.l));

	// 右側相鄰色 (+30度)
	colors.push(hslToHex((hsl.h + 30) % 360, hsl.s, hsl.l));

	// 更遠的左側色 (-60度)
	colors.push(hslToHex((hsl.h - 60 + 360) % 360, hsl.s, hsl.l));

	// 更遠的右側色 (+60度)
	colors.push(hslToHex((hsl.h + 60) % 360, hsl.s, hsl.l));

	return colors;
}

/**
 * 互補色配色方案（Complementary）
 * 使用色相環對面的顏色
 * @param {string} baseHex - 主色 HEX 值
 * @returns {Array} 5 個顏色的 HEX 陣列
 */
function generateComplementary(baseHex) {
	const hsl = hexToHsl(baseHex);
	const colors = [];

	// 主色
	colors.push(baseHex);

	// 互補色 (+180度)
	const complementHue = (hsl.h + 180) % 360;
	colors.push(hslToHex(complementHue, hsl.s, hsl.l));

	// 主色的淺色變化
	colors.push(hslToHex(hsl.h, hsl.s, Math.min(90, hsl.l + 25)));

	// 互補色的深色變化
	colors.push(hslToHex(complementHue, hsl.s, Math.max(10, hsl.l - 25)));

	// 中性色（降低飽和度的主色）
	colors.push(hslToHex(hsl.h, Math.max(10, hsl.s - 50), hsl.l));

	return colors;
}

/**
 * 分裂互補色配色方案（Split Complementary）
 * 使用互補色兩側的顏色
 * @param {string} baseHex - 主色 HEX 值
 * @returns {Array} 5 個顏色的 HEX 陣列
 */
function generateSplitComplementary(baseHex) {
	const hsl = hexToHsl(baseHex);
	const colors = [];

	// 主色
	colors.push(baseHex);

	// 分裂互補色 1 (+150度)
	colors.push(hslToHex((hsl.h + 150) % 360, hsl.s, hsl.l));

	// 分裂互補色 2 (+210度)
	colors.push(hslToHex((hsl.h + 210) % 360, hsl.s, hsl.l));

	// 主色的變化
	colors.push(
		hslToHex(hsl.h, Math.max(20, hsl.s - 30), Math.min(80, hsl.l + 20)),
	);

	// 分裂互補色的平均
	colors.push(hslToHex((hsl.h + 180) % 360, Math.max(20, hsl.s - 20), hsl.l));

	return colors;
}

/**
 * 三分色配色方案（Triadic）
 * 使用色相環上等距的三個顏色
 * @param {string} baseHex - 主色 HEX 值
 * @returns {Array} 5 個顏色的 HEX 陣列
 */
function generateTriadic(baseHex) {
	const hsl = hexToHsl(baseHex);
	const colors = [];

	// 主色
	colors.push(baseHex);

	// 三分色 1 (+120度)
	colors.push(hslToHex((hsl.h + 120) % 360, hsl.s, hsl.l));

	// 三分色 2 (+240度)
	colors.push(hslToHex((hsl.h + 240) % 360, hsl.s, hsl.l));

	// 主色的淺色變化
	colors.push(hslToHex(hsl.h, hsl.s, Math.min(85, hsl.l + 20)));

	// 主色的深色變化
	colors.push(hslToHex(hsl.h, hsl.s, Math.max(15, hsl.l - 20)));

	return colors;
}

/**
 * 四方色配色方案（Tetradic）
 * 使用色相環上兩對互補色
 * @param {string} baseHex - 主色 HEX 值
 * @returns {Array} 5 個顏色的 HEX 陣列
 */
function generateTetradic(baseHex) {
	const hsl = hexToHsl(baseHex);
	const colors = [];

	// 主色
	colors.push(baseHex);

	// 相鄰色 (+90度)
	colors.push(hslToHex((hsl.h + 90) % 360, hsl.s, hsl.l));

	// 互補色 (+180度)
	colors.push(hslToHex((hsl.h + 180) % 360, hsl.s, hsl.l));

	// 第四個色 (+270度)
	colors.push(hslToHex((hsl.h + 270) % 360, hsl.s, hsl.l));

	// 中性色（降低飽和度）
	colors.push(hslToHex(hsl.h, Math.max(15, hsl.s - 40), hsl.l));

	return colors;
}

/**
 * 黃金比例配色方案（Golden Ratio）
 * 使用黃金比例角度 (137.5°) 計算配色
 * @param {string} baseHex - 主色 HEX 值
 * @returns {Array} 5 個顏色的 HEX 陣列
 */
function generateGoldenRatio(baseHex) {
	const hsl = hexToHsl(baseHex);
	const colors = [];
	const goldenAngle = 137.5;

	// 主色
	colors.push(baseHex);

	// 黃金比例色彩
	for (let i = 1; i < 5; i++) {
		const newHue = (hsl.h + goldenAngle * i) % 360;
		colors.push(hslToHex(newHue, hsl.s, hsl.l));
	}

	return colors;
}

/**
 * 生成配色方案的主要函數
 * @param {string} baseHex - 主色 HEX 值
 * @param {string} scheme - 配色方案類型
 * @returns {Array} 5 個顏色的 HEX 陣列
 */
function generateColorPalette(baseHex, scheme) {
	// 驗證和標準化輸入
	if (!isValidHex(baseHex)) {
		throw new Error("無效的 HEX 顏色格式");
	}

	baseHex = normalizeHex(baseHex);

	switch (scheme.toLowerCase()) {
		case "monochromatic":
			return generateMonochromatic(baseHex);
		case "analogous":
			return generateAnalogous(baseHex);
		case "complementary":
			return generateComplementary(baseHex);
		case "splitcomplementary":
		case "split-complementary":
			return generateSplitComplementary(baseHex);
		case "triadic":
			return generateTriadic(baseHex);
		case "tetradic":
			return generateTetradic(baseHex);
		case "goldenratio":
		case "golden-ratio":
			return generateGoldenRatio(baseHex);
		default:
			throw new Error("不支援的配色方案類型");
	}
}

/**
 * 配色方案 API 函數
 * 提供與 Google Slides 整合的配色功能
 */

/**
 * 生成配色方案並返回結果
 * @param {string} baseHex - 主色 HEX 值
 * @param {string} scheme - 配色方案類型
 * @returns {Object} 包含配色方案和成功狀態的物件
 */
function generateColorScheme(baseHex, scheme) {
	try {
		const colors = generateColorPalette(baseHex, scheme);
		return {
			success: true,
			colors: colors,
			message: `成功生成 ${scheme} 配色方案`,
		};
	} catch (error) {
		return {
			success: false,
			colors: [],
			message: error.message,
		};
	}
}

/**
 * 將顏色套用到選中的物件
 * @param {string} hexColor - HEX 顏色值
 * @returns {Object} 操作結果
 */
function applyColorToSelected(hexColor) {
	try {
		const presentation = SlidesApp.getActivePresentation();
		const selection = SlidesApp.getActivePresentation().getSelection();

		if (!selection) {
			return {
				success: false,
				message: "請先選擇要套用顏色的物件",
			};
		}

		const selectedElements = selection.getPageElements();
		if (!selectedElements || selectedElements.length === 0) {
			return {
				success: false,
				message: "沒有選中任何物件",
			};
		}

		let appliedCount = 0;
		const requests = [];

		selectedElements.forEach((element) => {
			const elementId = element.getObjectId();

			// 根據元素類型套用顏色
			if (element.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
				// 形狀背景色
				requests.push({
					updateShapeProperties: {
						objectId: elementId,
						shapeProperties: {
							shapeBackgroundFill: {
								solidFill: {
									color: {
										rgbColor: hexToRgb(hexColor),
									},
								},
							},
						},
						fields: "shapeBackgroundFill.solidFill.color",
					},
				});
				appliedCount++;
			} else if (
				element.getPageElementType() === SlidesApp.PageElementType.TABLE
			) {
				// 表格處理可以在這裡擴展
				appliedCount++;
			}
		});

		// 執行批次更新
		if (requests.length > 0) {
			runRequestProcessors([requests]);
		}

		return {
			success: true,
			message: `成功套用顏色到 ${appliedCount} 個物件`,
		};
	} catch (error) {
		return {
			success: false,
			message: `套用顏色時發生錯誤: ${error.message}`,
		};
	}
}

/**
 * 建立色卡頁面
 * @param {Array} colors - 顏色陣列
 * @param {string} schemeName - 配色方案名稱
 * @returns {Object} 操作結果
 */
function createColorPalettePage(colors, schemeName) {
	try {
		const presentation = SlidesApp.getActivePresentation();

		// 建立新的投影片
		const newSlide = presentation.appendSlide(SlidesApp.PredefinedLayout.BLANK);

		// 設定標題
		const titleShape = newSlide.insertTextBox(
			`${schemeName} 配色方案`,
			50,
			50,
			600,
			60,
		);
		const titleTextStyle = titleShape.getText().getTextStyle();
		titleTextStyle
			.setFontSize(24)
			.setFontWeight("bold")
			.setForegroundColor("#333333");

		// 計算色塊位置
		const colorBlockWidth = 100;
		const colorBlockHeight = 80;
		const startX = 100;
		const startY = 150;
		const spacing = 120;

		const requests = [];

		// 為每個顏色建立色塊和標籤
		colors.forEach((color, index) => {
			const x = startX + index * spacing;
			const y = startY;

			// 建立色塊
			const colorBlockId = `colorBlock_${index}_${Date.now()}`;
			requests.push({
				createShape: {
					objectId: colorBlockId,
					shapeType: "RECTANGLE",
					elementProperties: {
						pageObjectId: newSlide.getObjectId(),
						size: {
							width: { magnitude: colorBlockWidth, unit: "PT" },
							height: { magnitude: colorBlockHeight, unit: "PT" },
						},
						transform: {
							scaleX: 1,
							scaleY: 1,
							translateX: x,
							translateY: y,
							unit: "PT",
						},
					},
				},
			});

			// 設定色塊顏色
			requests.push({
				updateShapeProperties: {
					objectId: colorBlockId,
					shapeProperties: {
						shapeBackgroundFill: {
							solidFill: {
								color: {
									rgbColor: hexToRgb(color),
								},
							},
						},
						outline: {
							outlineFill: {
								solidFill: {
									color: {
										rgbColor: { red: 0.8, green: 0.8, blue: 0.8 },
									},
								},
							},
							weight: {
								magnitude: 1,
								unit: "PT",
							},
						},
					},
					fields: "shapeBackgroundFill.solidFill.color,outline",
				},
			});

			// 建立 HEX 標籤
			const labelId = `colorLabel_${index}_${Date.now()}`;
			requests.push({
				createShape: {
					objectId: labelId,
					shapeType: "TEXT_BOX",
					elementProperties: {
						pageObjectId: newSlide.getObjectId(),
						size: {
							width: { magnitude: colorBlockWidth, unit: "PT" },
							height: { magnitude: 30, unit: "PT" },
						},
						transform: {
							scaleX: 1,
							scaleY: 1,
							translateX: x,
							translateY: y + colorBlockHeight + 10,
							unit: "PT",
						},
					},
				},
			});

			// 設定標籤文字
			requests.push({
				insertText: {
					objectId: labelId,
					text: color.toUpperCase(),
				},
			});

			// 設定標籤樣式
			requests.push({
				updateTextStyle: {
					objectId: labelId,
					style: {
						fontSize: { magnitude: 12, unit: "PT" },
						foregroundColor: {
							opaqueColor: {
								rgbColor: { red: 0.2, green: 0.2, blue: 0.2 },
							},
						},
						fontFamily: "Arial",
					},
					fields: "fontSize,foregroundColor,fontFamily",
				},
			});

			// 文字置中對齊
			requests.push({
				updateParagraphStyle: {
					objectId: labelId,
					style: {
						alignment: "CENTER",
					},
					fields: "alignment",
				},
			});
		});

		// 執行批次請求
		if (requests.length > 0) {
			runRequestProcessors([requests]);
		}

		return {
			success: true,
			message: `成功建立 ${schemeName} 色卡頁面`,
			slideId: newSlide.getObjectId(),
		};
	} catch (error) {
		return {
			success: false,
			message: `建立色卡頁面時發生錯誤: ${error.message}`,
		};
	}
}

/**
 * 將 HEX 顏色轉換為 RGB 物件（Google Slides API 格式）
 * @param {string} hex - HEX 顏色值
 * @returns {Object} RGB 顏色物件
 */
function hexToRgb(hex) {
	const normalizedHex = normalizeHex(hex).replace("#", "");
	const r = parseInt(normalizedHex.substr(0, 2), 16) / 255;
	const g = parseInt(normalizedHex.substr(2, 2), 16) / 255;
	const b = parseInt(normalizedHex.substr(4, 2), 16) / 255;

	return {
		red: r,
		green: g,
		blue: b,
	};
}

