function addThreeColumn() {
	// Creates 3 columns, 30px gap between columns, 180px wide boxes, with blue color
	createBoxColumns(3, 30, 180, main_color);
}

function createBoxColumns(columnCount, gapBetweenColumns, boxWidth, colorHex) {
	const slide = SlidesApp.getActivePresentation()
		.getSelection()
		.getCurrentPage();
	const startX = 30;
	const topY = 150;
	const topHeight = 40;
	const bottomY = topY + topHeight;
	const bottomHeight = 120;
	const strokeWidth = 2; // in points
	const white = base_color;

	for (let i = 0; i < columnCount; i++) {
		const currentX = startX + i * (boxWidth + gapBetweenColumns);

		// Top box (filled with color)
		const topBox = slide.insertShape(
			SlidesApp.ShapeType.RECTANGLE,
			currentX,
			topY,
			boxWidth,
			topHeight,
		);
		topBox.getFill().setSolidFill(colorHex);
		topBox.getBorder().getLineFill().setSolidFill(colorHex);
		topBox.getBorder().setWeight(strokeWidth);

		// Bottom box (white fill, colored border)
		const bottomBox = slide.insertShape(
			SlidesApp.ShapeType.RECTANGLE,
			currentX,
			bottomY,
			boxWidth,
			bottomHeight,
		);
		bottomBox.getFill().setSolidFill(base_color);
		bottomBox.getBorder().getLineFill().setSolidFill(colorHex);
		bottomBox.getBorder().setWeight(strokeWidth);
	}
}

/**
 * Server-side core for the Comparison (對照) Minter dialog.
 *
 * Turns "---"-separated markdown blocks into N comparison columns, then renders
 * each column as a side-by-side card: a colored title header bar on top of a
 * body box that lists the column's bullet points. Everything is inserted onto
 * the current slide in a single Slides.Presentations.batchUpdate.
 *
 * Mirrors the Grid Minter pattern (src/util/grid_minter.js):
 *  - Columns are separated by a line containing only "---" (same parser shape).
 *  - Insertion batches every request into one batchUpdate.
 *  - Templates resolve from the global palette (main_color / accent_color) so
 *    they track the configured theme.
 *
 * The column markdown format (also documented in the dialog):
 *   # 方案 A
 *   成本低
 *   導入快
 *   ---
 *   # 方案 B
 *   效能高
 *   可擴充
 * Columns are separated by a line containing only "---". Within a column, the
 * first "# " line is the title and every remaining non-heading line is a bullet.
 */

/**
 * Groq system prompt for turning free-form context into comparison-column
 * markdown that parseCompareColumns_() understands.
 */
var COMPARE_AI_SYSTEM_PROMPT = [
	"You convert the user's content into a side-by-side comparison.",
	"Output EXACTLY this format and nothing else:",
	"- Each column is a block that starts with a title line beginning with '# '.",
	"- After the title line, put one bullet point per line (plain text, NO leading bullet character).",
	"- Separate consecutive columns with a line that contains only '---'.",
	"Example:",
	"# 方案 A",
	"成本較低",
	"導入快速",
	"---",
	"# 方案 B",
	"效能較高",
	"可擴充性佳",
	"Strict rules:",
	"- No preamble, no explanation, no closing remarks, no code fences.",
	"- The very first line MUST start with '# '.",
	"- Produce EXACTLY 2 columns unless the input clearly implies more.",
	"- Give each column 2–5 bullet points.",
	"- Keep every line concise; do not invent facts that aren't implied by the input.",
].join("\n");

/**
 * Generates comparison-column Markdown from free-form context via Groq.
 * Called from the dialog through google.script.run.
 *
 * @param {string} context - Arbitrary text the user pasted.
 * @return {{success: boolean, generatedText?: string, error?: string, needKey?: boolean}}
 */
function generateCompareFromContext(context) {
	const text = (context || "").trim();
	if (!text) {
		return { success: false, error: "No context provided." };
	}

	// Don't throw on a missing key — let the dialog show a friendly prompt to
	// run the explicit "🔑 設定 AI 金鑰 (Groq)" menu item.
	if (!hasUserApiKey()) {
		return {
			success: false,
			needKey: true,
			error:
				"No AI key set. Run 🖖 跨頁功能 → 🔑 設定 AI 金鑰 (Groq) first, then try again.",
		};
	}

	return callGroq_(COMPARE_AI_SYSTEM_PROMPT, text, {
		maxTokens: 2000,
		temperature: 0.3,
	});
}

/**
 * Single source of truth for comparison templates. Each template carries the
 * per-column header fill/text and body border/text so columns share one look.
 * Colors resolve from the global palette where applicable.
 *
 * @return {Array<{id,name,headerFill,headerText,bodyFill,bodyBorder,bodyText}>}
 */
function buildCompareTemplates_() {
	const main = (typeof main_color !== "undefined" && main_color) || "#3D6869";
	const accent =
		(typeof accent_color !== "undefined" && accent_color) || "#f29424";
	const green = "#2E7D32";
	const red = "#C0392B";
	return [
		{
			id: "neutral",
			name: "Neutral",
			// Both columns share the main color header.
			columns: [
				{
					headerFill: main, headerText: "#FFFFFF",
					bodyFill: "#FFFFFF", bodyBorder: main, bodyText: "#000000",
				},
			],
		},
		{
			id: "pros-cons",
			name: "Pros / Cons",
			// First column green (pros), second column red (cons), then repeat.
			columns: [
				{
					headerFill: green, headerText: "#FFFFFF",
					bodyFill: "#FFFFFF", bodyBorder: green, bodyText: "#000000",
				},
				{
					headerFill: red, headerText: "#FFFFFF",
					bodyFill: "#FFFFFF", bodyBorder: red, bodyText: "#000000",
				},
			],
		},
		{
			id: "a-vs-b",
			name: "A vs B",
			// First column main, second column accent, then repeat.
			columns: [
				{
					headerFill: main, headerText: "#FFFFFF",
					bodyFill: "#FFFFFF", bodyBorder: main, bodyText: "#000000",
				},
				{
					headerFill: accent, headerText: "#FFFFFF",
					bodyFill: "#FFFFFF", bodyBorder: accent, bodyText: "#000000",
				},
			],
		},
	];
}

/**
 * Returns the comparison templates for client-side preview. Called from the
 * dialog through google.script.run.
 * @return {Array<Object>}
 */
function getCompareTemplates() {
	return buildCompareTemplates_();
}

/**
 * Resolves the per-column style for column index `i` from a template. Templates
 * may define fewer column styles than there are columns; the list cycles.
 *
 * @param {Object} tpl - a template from buildCompareTemplates_()
 * @param {number} i - zero-based column index
 * @return {{headerFill,headerText,bodyFill,bodyBorder,bodyText}}
 */
function compareColumnStyle_(tpl, i) {
	const cols = (tpl && tpl.columns) || [];
	if (!cols.length) {
		return {
			headerFill: "#3D6869", headerText: "#FFFFFF",
			bodyFill: "#FFFFFF", bodyBorder: "#3D6869", bodyText: "#000000",
		};
	}
	return cols[i % cols.length];
}

/**
 * Parses comparison markdown into an array of {title, points}.
 * Columns are separated by a line containing only "---" (---, ----, …). Within
 * a column, the first "# " line is the title and every remaining non-heading,
 * non-blank line is a bullet point.
 *
 * @param {string} markdown
 * @return {Array<{title: string, points: string[]}>}
 */
function parseCompareColumns_(markdown) {
	const text = (markdown || "").replace(/\r\n/g, "\n").trim();
	if (!text) return [];

	// Split on a line that is only dashes (---, ----, …), tolerating whitespace.
	const blocks = text
		.split(/\n\s*-{3,}\s*\n/)
		.map((b) => b.trim())
		.filter((b) => b.length);

	const columns = [];
	for (const block of blocks) {
		const lines = block.split("\n");
		let title = "";
		const points = [];
		for (const raw of lines) {
			const line = raw.trim();
			if (!line) continue;
			const h1 = line.match(/^#\s+(.+)$/);
			if (h1) {
				if (!title) title = h1[1].trim();
			} else {
				// Strip a leading bullet marker if the user typed one.
				points.push(line.replace(/^[•\-*]\s+/, ""));
			}
		}
		if (title || points.length) {
			columns.push({ title: title, points: points });
		}
	}
	return columns;
}

/**
 * Pushes the Slides API requests that render one comparison column (a colored
 * title header bar + a body box of bullet points) into the shared requests array.
 *
 * @param {Array} requests - shared batch request array
 * @param {string} pageId - target slide objectId
 * @param {{x:number,y:number,w:number,headerH:number,bodyH:number}} pos
 * @param {{title:string, points:string[]}} column
 * @param {{headerFill,headerText,bodyFill,bodyBorder,bodyText}} style
 */
function buildCompareColumnRequests_(requests, pageId, pos, column, style) {
	const uid = Utilities.getUuid().replace(/-/g, "");
	const headerId = "cmphead" + uid;
	const bodyId = "cmpbody" + uid;
	const font =
		(typeof main_font_family !== "undefined" && main_font_family) ||
		"Source Sans Pro";

	// --- Header bar -----------------------------------------------------------
	requests.push({
		createShape: {
			objectId: headerId,
			shapeType: "RECTANGLE",
			elementProperties: {
				pageObjectId: pageId,
				size: {
					width: { magnitude: pos.w, unit: "PT" },
					height: { magnitude: pos.headerH, unit: "PT" },
				},
				transform: {
					scaleX: 1,
					scaleY: 1,
					translateX: pos.x,
					translateY: pos.y,
					unit: "PT",
				},
			},
		},
	});
	requests.push({
		updateShapeProperties: {
			objectId: headerId,
			shapeProperties: {
				shapeBackgroundFill: {
					solidFill: { color: { rgbColor: hexToRgbColor_(style.headerFill) } },
				},
				outline: {
					outlineFill: {
						solidFill: { color: { rgbColor: hexToRgbColor_(style.headerFill) } },
					},
					weight: { magnitude: 1, unit: "PT" },
					dashStyle: "SOLID",
				},
				contentAlignment: "MIDDLE",
			},
			fields:
				"shapeBackgroundFill.solidFill.color,outline.outlineFill.solidFill.color,outline.weight,outline.dashStyle,contentAlignment",
		},
	});
	const titleText = column.title || "";
	if (titleText) {
		requests.push({
			insertText: { objectId: headerId, insertionIndex: 0, text: titleText },
		});
		requests.push({
			updateTextStyle: {
				objectId: headerId,
				textRange: { type: "ALL" },
				style: {
					foregroundColor: {
						opaqueColor: { rgbColor: hexToRgbColor_(style.headerText) },
					},
					bold: true,
					fontFamily: font,
					fontSize: { magnitude: 16, unit: "PT" },
				},
				fields: "foregroundColor,bold,fontFamily,fontSize",
			},
		});
		requests.push({
			updateParagraphStyle: {
				objectId: headerId,
				textRange: { type: "ALL" },
				style: { alignment: "CENTER" },
				fields: "alignment",
			},
		});
	}

	// --- Body box -------------------------------------------------------------
	const bodyY = pos.y + pos.headerH;
	requests.push({
		createShape: {
			objectId: bodyId,
			shapeType: "TEXT_BOX",
			elementProperties: {
				pageObjectId: pageId,
				size: {
					width: { magnitude: pos.w, unit: "PT" },
					height: { magnitude: pos.bodyH, unit: "PT" },
				},
				transform: {
					scaleX: 1,
					scaleY: 1,
					translateX: pos.x,
					translateY: bodyY,
					unit: "PT",
				},
			},
		},
	});
	requests.push({
		updateShapeProperties: {
			objectId: bodyId,
			shapeProperties: {
				shapeBackgroundFill: {
					solidFill: { color: { rgbColor: hexToRgbColor_(style.bodyFill) } },
				},
				outline: {
					outlineFill: {
						solidFill: { color: { rgbColor: hexToRgbColor_(style.bodyBorder) } },
					},
					weight: { magnitude: 1, unit: "PT" },
					dashStyle: "SOLID",
				},
				contentAlignment: "TOP",
			},
			fields:
				"shapeBackgroundFill.solidFill.color,outline.outlineFill.solidFill.color,outline.weight,outline.dashStyle,contentAlignment",
		},
	});

	const points = column.points || [];
	if (points.length) {
		const bodyText = points.map((p) => "• " + p).join("\n");
		requests.push({
			insertText: { objectId: bodyId, insertionIndex: 0, text: bodyText },
		});
		requests.push({
			updateTextStyle: {
				objectId: bodyId,
				textRange: { type: "ALL" },
				style: {
					foregroundColor: {
						opaqueColor: { rgbColor: hexToRgbColor_(style.bodyText) },
					},
					fontFamily: font,
					fontSize: { magnitude: 13, unit: "PT" },
				},
				fields: "foregroundColor,fontFamily,fontSize",
			},
		});
		requests.push({
			updateParagraphStyle: {
				objectId: bodyId,
				textRange: { type: "ALL" },
				style: { alignment: "START", lineSpacing: 130, spaceBelow: { magnitude: 4, unit: "PT" } },
				fields: "alignment,lineSpacing,spaceBelow",
			},
		});
	}
}

/**
 * Inserts comparison columns as side-by-side cards onto the current slide.
 * Columns divide the usable page width evenly (auto-width by count), start at
 * Y ≈ 120, and each card is a colored title header bar over a bullet body box.
 * Everything is sent in a single batchUpdate.
 *
 * @param {{columns: Array<{title:string, points:string[]}>, templateId: string}} payload
 * @return {{success: boolean, error?: string}}
 */
function insertCompareIntoSlide(payload) {
	try {
		const p = payload || {};
		const columns = p.columns || [];
		if (!columns.length) {
			return { success: false, error: "No columns to insert." };
		}

		const templates = buildCompareTemplates_();
		let tpl = templates[0];
		for (let i = 0; i < templates.length; i++) {
			if (templates[i].id === p.templateId) tpl = templates[i];
		}

		const presentation = SlidesApp.getActivePresentation();
		const pageW = presentation.getPageWidth();
		const pageH = presentation.getPageHeight();

		// Resolve the target slide (fall back to the first slide).
		let slide = null;
		try {
			slide = presentation.getSelection().getCurrentPage().asSlide();
		} catch (e) {
			slide = presentation.getSlides()[0];
		}
		if (!slide) return { success: false, error: "No slide available." };
		const pageId = slide.getObjectId();

		// Layout: even columns across the usable width, start near the top.
		const margin = 30;
		const gap = 18;
		const top = 120;
		const headerH = 36;
		const n = columns.length;
		const usableW = pageW - 2 * margin;
		const colW = (usableW - (n - 1) * gap) / n;
		const bodyH = Math.max(80, pageH - top - headerH - margin);

		const requests = [];
		for (let i = 0; i < n; i++) {
			const x = margin + i * (colW + gap);
			const style = compareColumnStyle_(tpl, i);
			buildCompareColumnRequests_(
				requests,
				pageId,
				{ x: x, y: top, w: colW, headerH: headerH, bodyH: bodyH },
				columns[i],
				style,
			);
		}

		if (requests.length) {
			try {
				Slides.Presentations.batchUpdate({ requests }, presentation.getId());
			} catch (batchErr) {
				return { success: false, error: batchErr.message };
			}
		}

		return { success: true };
	} catch (e) {
		console.error("Error inserting comparison: " + e.message);
		return { success: false, error: e.message };
	}
}

// Date utility functions for Google Slides module
function updateDateInFirstSlide() {
  const presentation = SlidesApp.getActivePresentation();
  const firstSlide = presentation.getSlides()[0];
  const today = Utilities.formatDate(new Date(), Session.getScriptTimeZone(), "yyyy-MM-dd");

  const regex = /^\d{4}[-\/]\d{2}[-\/]\d{2}$/; // Matches yyyy-mm-dd or yyyy/mm/dd

  const pageElements = firstSlide.getPageElements();

  pageElements.forEach(element => {
    if (element.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
      const shape = element.asShape();
      const textRange = shape.getText();
      const text = textRange.asString().trim();

      if (regex.test(text)) {
        textRange.setText(today);
      }
    }
  });
}

/**
 * util_default_style.js
 *
 * Provides utility functions for applying predefined styles to shapes and textboxes
 * in Google Slides presentations. Serves as the single source of truth for all style definitions.
 */

/**
 * Centralized style definitions - single source of truth for all style configurations
 * Used by both server-side functions and client-side preview updates
 */
const STYLE_DEFINITIONS = {
	1: {
		// Base color fill, main color border and text
		name: "Style 1",
		description: "White fill, main color border and text",
		borderColor: "main_color",
		borderWidth: 1,
		fillColor: "base_color",
		textColor: "main_color",
	},
	2: {
		// Main color fill, text color border and base color text
		name: "Style 2",
		description: "Main color fill, white text",
		borderColor: "main_color",
		borderWidth: 1,
		fillColor: "main_color",
		textColor: "base_color",
	},
	3: {
		// Sub1 color fill, main color border and main color text
		name: "Style 3",
		description: "Sub1 color fill, main color border and text",
		borderColor: "main_color",
		borderWidth: 1,
		fillColor: "sub1_color",
		textColor: "main_color",
	},
	4: {
		// Base color fill, accent color border and accent color text
		name: "Style 4",
		description: "White fill, accent color border and text",
		borderColor: "accent_color",
		borderWidth: 1,
		fillColor: "base_color",
		textColor: "accent_color",
	},
	5: {
		// Accent color fill, accent color border and base color text
		name: "Style 5",
		description: "Accent color fill, white text",
		borderColor: "accent_color",
		borderWidth: 1,
		fillColor: "accent_color",
		textColor: "base_color",
	},
	6: {
		// Base color fill, base color border and main color text
		name: "Style 6",
		description: "White fill, white border, main color text",
		borderColor: "base_color",
		borderWidth: 1,
		fillColor: "base_color",
		textColor: "main_color",
	},
};

/**
 * Get style definitions for client-side use
 * Returns style definitions with actual color values resolved
 */
function getStyleDefinitions() {
	const config = getConfigValues();
	const styles = {};

	for (const [key, style] of Object.entries(STYLE_DEFINITIONS)) {
		styles[key] = {
			...style,
			borderColor: resolveColorVariable(style.borderColor, config),
			fillColor: resolveColorVariable(style.fillColor, config),
			textColor: resolveColorVariable(style.textColor, config),
		};
	}

	return styles;
}

/**
 * Resolve color variable name to actual color value
 */
function resolveColorVariable(colorVar, config) {
	switch (colorVar) {
		case "main_color":
			return config.mainColor || main_color;
		case "base_color":
			return config.baseColor || base_color;
		case "sub1_color":
			return config.sub1Color || sub1_color;
		case "accent_color":
			return config.accentColor || accent_color;
		case "text_color":
			return config.textColor || text_color;
		default:
			return colorVar;
	}
}

/**
 * Apply a default style to the selected shape or textbox
 * @param {number} styleNumber - The style number to apply (1-6)
 */
function applyDefaultStyle(styleNumber) {
	const presentation = SlidesApp.getActivePresentation();
	const selection = presentation.getSelection();
	const selectedElements = selection.getPageElementRange()
		? selection.getPageElementRange().getPageElements()
		: [];

	// Get the resolved styles using centralized definitions
	const styles = getStyleDefinitions();

	// Get the selected style
	const style = styles[styleNumber];
	if (!style) {
		Logger.log("Invalid style number: " + styleNumber);
		return;
	}

	// Apply the style to each selected element
	for (let i = 0; i < selectedElements.length; i++) {
		const element = selectedElements[i];

		// Check if the element is a shape
		if (element.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
			const shape = element.asShape();

			try {
				// First, ensure the shape has text to avoid 'has no text' error
				// This must be done before any text styling operations
				if (!shape.getText().asString()) {
					shape.getText().setText("TEXT_HERE");
				}

				// Apply border
				shape.getBorder().setWeight(style.borderWidth);
				shape.getBorder().getLineFill().setSolidFill(style.borderColor);

				// Apply fill
				shape.getFill().setSolidFill(style.fillColor);

				// Apply text color
				shape.getText().getTextStyle().setForegroundColor(style.textColor);
			} catch (e) {
				Logger.log("Error applying style to shape: " + e.toString());
			}
		}
		// Check if the element is a text box (which is also a shape in Google Slides)
		else if (
			element.getPageElementType() === SlidesApp.PageElementType.SHAPE &&
			element.asShape().getShapeType() === SlidesApp.ShapeType.TEXT_BOX
		) {
			const textBox = element.asShape();

			try {
				// First, ensure the textbox has text to avoid 'has no text' error
				// This must be done before any text styling operations
				if (!textBox.getText().asString()) {
					textBox.getText().setText("TEXT_HERE");
				}

				// Apply border
				textBox.getBorder().setWeight(style.borderWidth);
				textBox.getBorder().getLineFill().setSolidFill(style.borderColor);

				// Apply fill
				textBox.getFill().setSolidFill(style.fillColor);

				// Apply text color
				textBox.getText().getTextStyle().setForegroundColor(style.textColor);
			} catch (e) {
				Logger.log("Error applying style to textbox: " + e.toString());
			}
		}
	}
}

