/**
 * Graph ID management utilities for hierarchical shape naming
 * Handles parsing, generating, and managing graph IDs for flowchart shapes
 * Format: graph[parent1|parent2|...](layout)[current][children]
 * - Parent field contains full parent hierarchy separated by |
 * - Layout types: LR (Left-Right), TD (Top-Down), RL (Right-Left), DT (Down-Top)
 * - Children can have individual layouts: [B1:RL,B2:TD,B3]
 * - Child without layout inherits parent's layout
 * Example: graph[A1|B1](LR)[C1][] means C1's parent is B1, and B1's parent is A1
 */

/**
 * Parses a child ID to extract its ID and optional layout
 * @param {string} childStr - Child string like "B1" or "B1:RL"
 * @returns {Object} - Object with {id, layout}
 */
function parseChildWithLayout(childStr) {
	const parts = childStr.trim().split(":");
	return {
		id: parts[0],
		layout: parts[1] || null, // null means inherit from parent
	};
}

/**
 * Parses a graph ID to extract its components
 * @param {string} graphId - The graph ID to parse
 * @returns {Object|null} - Object with parent, layout, current, children arrays or null if not a graph ID
 */
function parseGraphId(graphId) {
	if (!graphId || !graphId.startsWith("graph[")) {
		return null;
	}

	// New format: graph[parent](layout)[current][children]
	const newFormatMatches = graphId.match(
		/graph\[([^\]]*)\]\(([^)]*)\)\[([^\]]*)\]\[([^\]]*)\]/,
	);
	if (newFormatMatches) {
		const childrenStr = newFormatMatches[4] || "";
		const children = childrenStr
			? childrenStr
					.split(",")
					.filter((c) => c.trim())
					.map(parseChildWithLayout)
			: [];

		return {
			parent: newFormatMatches[1] || "",
			layout: newFormatMatches[2] || "LR", // Default to LR
			current: newFormatMatches[3] || "",
			children: children,
			// Keep backward compatibility with simple array
			childrenIds: children.map((c) => c.id),
		};
	}

	// Legacy format: graph[parent][current][children] - assume LR layout
	const legacyMatches = graphId.match(
		/graph\[([^\]]*)\]\[([^\]]*)\]\[([^\]]*)\]/,
	);
	if (legacyMatches) {
		const childrenStr = legacyMatches[3] || "";
		const children = childrenStr
			? childrenStr
					.split(",")
					.filter((c) => c.trim())
					.map((c) => ({ id: c.trim(), layout: null }))
			: [];

		return {
			parent: legacyMatches[1] || "",
			layout: "LR", // Default legacy to LR
			current: legacyMatches[2] || "",
			children: children,
			// Keep backward compatibility with simple array
			childrenIds: children.map((c) => c.id),
		};
	}

	return null;
}

/**
 * Formats a child for the graph ID string
 * @param {string|Object} child - Child ID string or object with {id, layout}
 * @returns {string} - Formatted child string (e.g., "B1" or "B1:RL")
 */
function formatChildForGraphId(child) {
	if (typeof child === "string") {
		return child;
	}
	if (child && typeof child === "object") {
		return child.layout ? `${child.id}:${child.layout}` : child.id;
	}
	return "";
}

/**
 * Generates a graph ID from components with layout information
 * @param {string} parent - Parent ID
 * @param {string} layout - Layout type ("LR", "TD", "RL", or "DT")
 * @param {string} current - Current ID
 * @param {Array} children - Array of child IDs (strings or objects with {id, layout})
 * @returns {string} - Generated graph ID
 */
function generateGraphId(parent, layout, current, children = []) {
	// Handle legacy calls with 3 parameters (parent, current, children)
	let actualParent = parent || "";
	let actualLayout = layout;
	let actualCurrent = current;
	let actualChildren = children;

	if (Array.isArray(layout)) {
		actualChildren = layout;
		actualCurrent = current || "";
		actualLayout = ""; // No layout for legacy calls (they're typically parents)
		actualParent = "";
		actualCurrent = parent;
	} else if (
		typeof layout === "string" &&
		layout !== "" &&
		!["LR", "TD", "RL", "DT"].includes(layout)
	) {
		// Handle legacy calls: generateGraphId(parent, current, children)
		actualChildren = current || [];
		actualCurrent = layout;
		actualLayout = ""; // No layout for legacy calls
	}

	// Only add layout annotation to children (when parent is not empty)
	const finalLayout = actualParent ? actualLayout : "";

	// Format children with their layouts
	const childrenStr = Array.isArray(actualChildren)
		? actualChildren
				.map(formatChildForGraphId)
				.filter((c) => c)
				.join(",")
		: "";

	// Handle different graph ID formats based on context
	// For root shapes (empty parent and empty layout), use legacy format without parentheses
	if (actualParent === "" && actualLayout === "") {
		return `graph[][${actualCurrent}][${childrenStr}]`;
	} else {
		// Non-root shape or shape with explicit layout: include layout parentheses
		return `graph[${actualParent}](${actualLayout})[${actualCurrent}][${childrenStr}]`;
	}
}

/**
 * Legacy wrapper for generateGraphId to maintain backwards compatibility
 * @param {string} parent - Parent ID
 * @param {string} current - Current ID
 * @param {Array} children - Array of child IDs
 * @returns {string} - Generated graph ID with LR layout
 */
function generateGraphIdLegacy(parent, current, children = []) {
	return generateGraphId(parent, "LR", current, children);
}

/**
 * Generates the next level ID for a child
 * @param {string} parentLevel - Parent's level (e.g., "A", "B", "C")
 * @returns {string} - Next level (e.g., "A" -> "B", "B" -> "C")
 */
function getNextLevel(parentLevel) {
	if (!parentLevel) return "A";
	const lastChar = parentLevel.charAt(parentLevel.length - 1);
	if (lastChar >= "A" && lastChar < "Z") {
		return (
			parentLevel.slice(0, -1) + String.fromCharCode(lastChar.charCodeAt(0) + 1)
		);
	}
	return parentLevel + "A";
}

/**
 * Generates sibling IDs for multiple children
 * @param {string} baseLevel - Base level for siblings (e.g., "C")
 * @param {number} count - Number of siblings to generate
 * @returns {Array} - Array of sibling IDs (e.g., ["C1", "C2", "C3"])
 */
function generateSiblingIds(baseLevel, count) {
	const siblings = [];
	for (let i = 1; i <= count; i++) {
		siblings.push(`${baseLevel}${i}`);
	}
	return siblings;
}

/**
 * Sets the graph ID on a shape by updating its title (alt text)
 * @param {GoogleAppsScript.Slides.Shape} shape - Shape to update
 * @param {string} graphId - New graph ID to set
 */
function setShapeGraphId(shape, graphId) {
	try {
		// Set the shape's title (alt text) to the graph ID
		// This keeps the graph ID hidden while allowing custom text in the shape
		shape.setTitle(graphId);
	} catch (e) {
		console.log(`Warning: Could not set shape title: ${e.message}`);
	}
}

/**
 * Gets the graph ID from a shape's title (alt text)
 * @param {GoogleAppsScript.Slides.Shape} shape - Shape to read from
 * @returns {string|null} - Graph ID or null if not found
 */
function getShapeGraphId(shape) {
	try {
		// Get the shape's title (alt text)
		const title = shape.getTitle();
		if (title && title.startsWith("graph[")) {
			return title;
		}
		// Fallback: check text content for backward compatibility
		// This helps migrate old shapes that stored graph ID in text
		const text = shape.getText().asString().trim();
		if (text && text.startsWith("graph[")) {
			// Migrate to title and clear the text
			shape.setTitle(text);
			shape.getText().clear();
			return text;
		}
		return null;
	} catch (e) {
		console.log(`Warning: Could not get shape title: ${e.message}`);
		return null;
	}
}

/**
 * Updates parent shape to include new children in its ID
 * @param {GoogleAppsScript.Slides.Shape} parentShape - Parent shape to update
 * @param {Array} newChildIds - Array of new child IDs (strings or objects with {id, layout})
 */
function updateParentWithChildren(parentShape, newChildIds) {
	const currentId = getShapeGraphId(parentShape);
	if (!currentId) {
		// If parent doesn't have a graph ID, create one without layout annotation
		const newId = generateGraphId("", "", "A1", newChildIds);
		setShapeGraphId(parentShape, newId);
		return;
	}

	const parsed = parseGraphId(currentId);
	if (!parsed) return;

	// Convert new children to objects if they're strings
	const newChildren = newChildIds.map((child) =>
		typeof child === "string" ? { id: child, layout: null } : child,
	);

	// Create a map of existing children to preserve their layouts
	const childMap = new Map();
	parsed.children.forEach((child) => {
		childMap.set(child.id, child);
	});

	// Add new children to the map
	newChildren.forEach((child) => {
		if (!childMap.has(child.id)) {
			childMap.set(child.id, child);
		}
	});

	// Convert map back to array
	const allChildren = Array.from(childMap.values());

	const updatedId = generateGraphId(
		parsed.parent,
		parsed.layout,
		parsed.current,
		allChildren,
	);
	setShapeGraphId(parentShape, updatedId);
}

/**
 * Initializes a shape as a root graph node
 * @param {GoogleAppsScript.Slides.Shape} shape - Shape to initialize
 * @returns {string} - Generated root graph ID
 */
function initializeAsRootGraphShape(shape) {
	const rootId = generateGraphId("", "", "A1", []);
	setShapeGraphId(shape, rootId);
	return rootId;
}

/**
 * Determines parent-child relationship between two shapes based on their graph IDs
 * @param {string} idA - First shape's graph ID
 * @param {string} idB - Second shape's graph ID
 * @returns {Object|null} - Relationship info {parent, child, parentId, childId} or null if invalid
 */
function determineParentChildRelationship(idA, idB) {
	const parsedA = parseGraphId(idA);
	const parsedB = parseGraphId(idB);

	if (!parsedA || !parsedB) {
		return null;
	}

	// Determine parent-child relationship based on hierarchy level
	// Lower levels (A < B < C) are parents of higher levels
	const levelA = parsedA.current.match(/^([A-Z]+)/)?.[1] || "A";
	const levelB = parsedB.current.match(/^([A-Z]+)/)?.[1] || "A";

	if (levelA <= levelB) {
		return {
			parent: "A",
			child: "B",
			parentId: parsedA,
			childId: parsedB,
		};
	} else {
		return {
			parent: "B",
			child: "A",
			parentId: parsedB,
			childId: parsedA,
		};
	}
}

/**
 * Updates the relationship between two existing graph shapes
 * @param {GoogleAppsScript.Slides.Shape} shapeA - First shape
 * @param {GoogleAppsScript.Slides.Shape} shapeB - Second shape
 * @returns {Object|null} - Updated relationship or null if failed
 */
function updateGraphShapeRelationship(shapeA, shapeB) {
	const idA = getShapeGraphId(shapeA);
	const idB = getShapeGraphId(shapeB);

	if (!idA || !idB) {
		return null;
	}

	const relationship = determineParentChildRelationship(idA, idB);
	if (!relationship) {
		return null;
	}

	const parentShape = relationship.parent === "A" ? shapeA : shapeB;
	const childShape = relationship.parent === "A" ? shapeB : shapeA;
	const parentId = relationship.parentId;
	const childId = relationship.childId;

	// Update parent to include this child
	if (!parentId.childrenIds.includes(childId.current)) {
		const updatedChildren = [...parentId.childrenIds, childId.current];
		const newParentId = generateGraphId(
			parentId.parent,
			parentId.layout,
			parentId.current,
			updatedChildren,
		);
		setShapeGraphId(parentShape, newParentId);
	}

	// Update child to reflect correct parent using parent's layout
	const newChildId = generateGraphId(
		parentId.current,
		parentId.layout,
		childId.current,
		childId.children,
	);
	setShapeGraphId(childShape, newChildId);

	return {
		parentShape,
		childShape,
		updated: true,
	};
}

/**
 * Layout detection utilities for flowchart arrangements
 * Detects whether existing shapes are arranged horizontally (LR) or vertically (TD)
 */

/**
 * Analyzes connections to determine the primary layout direction
 * @param {GoogleAppsScript.Slides.Shape} parentShape - Parent shape to analyze
 * @param {Array} siblingShapes - Array of sibling shape data
 * @returns {string} - "horizontal" or "vertical"
 */
function detectLayoutFromConnections(parentShape, siblingShapes) {
	const slide = parentShape.getParentPage();
	const allLines = slide.getLines();

	const parentCenter = getCenterOf(parentShape);
	const connections = { horizontal: 0, vertical: 0 };

	// Analyze all lines connected to parent or siblings
	for (const line of allLines) {
		try {
			const startSite = line.getLineConnections().getStartConnection();
			const endSite = line.getLineConnections().getEndConnection();

			if (!startSite || !endSite) continue;

			// Check if line connects parent to any sibling
			const startShape = startSite.getConnectedPage()
				? startSite.getConnectedPage()
				: null;
			const endShape = endSite.getConnectedPage()
				? endSite.getConnectedPage()
				: null;

			const isParentConnection =
				startShape === parentShape || endShape === parentShape;

			if (isParentConnection) {
				const otherShape = startShape === parentShape ? endShape : startShape;
				if (otherShape) {
					const otherCenter = getCenterOf(otherShape);
					const dx = Math.abs(otherCenter.x - parentCenter.x);
					const dy = Math.abs(otherCenter.y - parentCenter.y);

					// Determine primary direction of this connection
					if (dx > dy) {
						connections.horizontal++;
					} else {
						connections.vertical++;
					}
				}
			}
		} catch (e) {
			// Skip problematic connections
			continue;
		}
	}

	// Return the predominant direction
	return connections.horizontal >= connections.vertical
		? "horizontal"
		: "vertical";
}

/**
 * Analyzes sibling positions to detect layout pattern
 * @param {Array} siblingShapes - Array of sibling shape data
 * @param {number} tolerance - Position tolerance in pixels
 * @returns {string} - "horizontal" or "vertical"
 */
function detectLayoutFromPositions(siblingShapes, tolerance = 20) {
	if (siblingShapes.length < 2) {
		return "horizontal"; // Default fallback
	}

	const firstSibling = siblingShapes[0];
	let horizontalAligned = 0;
	let verticalAligned = 0;

	// Compare each sibling with the first one
	for (let i = 1; i < siblingShapes.length; i++) {
		const sibling = siblingShapes[i];
		const deltaX = Math.abs(sibling.left - firstSibling.left);
		const deltaY = Math.abs(sibling.top - firstSibling.top);

		if (deltaY < tolerance) horizontalAligned++;
		if (deltaX < tolerance) verticalAligned++;
	}

	return horizontalAligned > verticalAligned ? "horizontal" : "vertical";
}

/**
 * Enhanced layout detection combining multiple methods
 * @param {GoogleAppsScript.Slides.Shape} parentShape - Parent shape
 * @param {Array} siblingShapes - Array of sibling shapes
 * @returns {string} - "horizontal" or "vertical"
 */
function detectLayout(parentShape, siblingShapes) {
	// Method 1: Try connection-based detection first
	try {
		const connectionLayout = detectLayoutFromConnections(
			parentShape,
			siblingShapes,
		);
		if (connectionLayout) {
			return connectionLayout;
		}
	} catch (e) {
		console.log(`Connection detection failed: ${e.message}`);
	}

	// Method 2: Fallback to position-based detection
	try {
		return detectLayoutFromPositions(siblingShapes);
	} catch (e) {
		console.log(`Position detection failed: ${e.message}`);
	}

	// Method 3: Ultimate fallback
	return "horizontal";
}

/**
 * Line update utilities for flowchart elements
 * Provides functions for updating existing lines with new styles and properties
 */

/**
 * Updates the selected lines with new line type and arrow styles
 * @param {string} lineType - Type of line to use (STRAIGHT, BENT, or CURVED)
 * @param {string} startArrow - Start arrow style (NONE, FILL_ARROW, etc.)
 * @param {string} endArrow - End arrow style (NONE, FILL_ARROW, etc.)
 * @returns {string} - Result message
 */
function updateSelectedLines(
	lineType = "STRAIGHT",
	startArrow = "NONE",
	endArrow = "FILL_ARROW",
) {
	try {
		console.log(
			`Starting line update: type=${lineType}, startArrow=${startArrow}, endArrow=${endArrow}`,
		);

		const pres = SlidesApp.getActivePresentation();
		const selection = pres.getSelection();

		if (!selection) {
			console.log("No selection found");
			return "Please select one or more lines to update.";
		}

		const elements = getSelectedElements(selection);
		if (!elements) {
			return "Please select one or more line elements to update.";
		}

		console.log(`Found ${elements.length} selected elements`);

		const updateResults = processLineUpdates(
			elements,
			lineType,
			startArrow,
			endArrow,
		);

		return formatUpdateResults(updateResults);
	} catch (e) {
		console.error(`Error updating lines: ${e.message}`);
		console.error(`Stack trace: ${e.stack}`);
		return `Error: ${e.message}`;
	}
}

/**
 * Gets selected elements from the current selection
 * @param {Selection} selection - The current selection
 * @returns {Array|null} Array of selected elements or null if invalid
 */
function getSelectedElements(selection) {
	const selectionType = selection.getSelectionType();
	console.log(`Selection type: ${selectionType}`);

	let elements = [];

	if (selectionType === SlidesApp.SelectionType.PAGE_ELEMENT_RANGE) {
		// Multiple elements selected
		const range = selection.getPageElementRange();
		if (!range) {
			console.log("No page element range found");
			return null;
		}
		elements = range.getPageElements();
	} else if (selectionType === SlidesApp.SelectionType.PAGE_ELEMENT) {
		// Single element selected
		const range = selection.getPageElementRange();
		if (range) {
			elements = range.getPageElements();
		} else {
			console.log("Could not get page element range for single selection");
			return null;
		}
	} else {
		console.log(`Unsupported selection type: ${selectionType}`);
		return null;
	}

	return elements;
}

/**
 * Processes line updates for all selected elements
 * @param {Array} elements - Array of selected elements
 * @param {string} lineType - Line type to apply
 * @param {string} startArrow - Start arrow style
 * @param {string} endArrow - End arrow style
 * @returns {Object} Update results with counts
 */
function processLineUpdates(elements, lineType, startArrow, endArrow) {
	let updatedCount = 0;
	let skippedCount = 0;
	let errorCount = 0;

	for (let i = 0; i < elements.length; i++) {
		const element = elements[i];
		const elementType = element.getPageElementType();
		console.log(`Element ${i}: type = ${elementType}`);

		if (elementType === SlidesApp.PageElementType.LINE) {
			try {
				const success = updateSingleLine(
					element.asLine(),
					lineType,
					startArrow,
					endArrow,
					i,
				);
				if (success) {
					updatedCount++;
				} else {
					skippedCount++;
				}
			} catch (lineError) {
				console.error(`Error updating line ${i}: ${lineError.message}`);
				console.error(`Stack trace: ${lineError.stack}`);
				errorCount++;
			}
		} else {
			console.log(`Element ${i} is not a line, skipping`);
			skippedCount++;
		}
	}

	return { updatedCount, skippedCount, errorCount };
}

/**
 * Updates a single line element
 * @param {Line} line - The line to update
 * @param {string} lineType - Line type to apply
 * @param {string} startArrow - Start arrow style
 * @param {string} endArrow - End arrow style
 * @param {number} index - Line index for logging
 * @returns {boolean} True if update was successful
 */
function updateSingleLine(line, lineType, startArrow, endArrow, index) {
	console.log(`Processing line ${index}`);

	// Get connection info before deletion
	const slide = line.getParentPage();
	const startConnection = line.getStart();
	const endConnection = line.getEnd();

	console.log(
		`Line connections - Start: ${startConnection ? "exists" : "null"}, End: ${endConnection ? "exists" : "null"}`,
	);

	if (!startConnection || !endConnection) {
		console.log(`Line ${index} missing connection sites`);
		return false;
	}

	// Get shapes on the slide for reconnection
	const allShapes = slide.getShapes();
	console.log(`Found ${allShapes.length} shapes on slide`);

	if (allShapes.length < 2) {
		console.log(`Line ${index} - not enough shapes on slide to connect`);
		return false;
	}

	// Store line style properties before deletion
	const lineStyle = extractLineStyle(line, index);

	// Get shapes to reconnect (simple heuristic using first two shapes)
	const startShape = allShapes[0];
	const endShape = allShapes[1];

	console.log(`Using shapes: shape1 and shape2 as connection candidates`);
	console.log(
		`Shape1 at (${startShape.getLeft()}, ${startShape.getTop()}), Shape2 at (${endShape.getLeft()}, ${endShape.getTop()})`,
	);

	// Remove the old line first
	line.remove();
	console.log(`Line ${index} removed`);

	// Create new line with updated properties
	return recreateLine(
		startShape,
		endShape,
		lineType,
		startArrow,
		endArrow,
		lineStyle,
		index,
	);
}

/**
 * Extracts style properties from a line before deletion
 * @param {Line} line - The line to extract style from
 * @param {number} index - Line index for logging
 * @returns {Object} Line style properties
 */
function extractLineStyle(line, index) {
	let lineWeight = 2; // default weight
	let lineColor = null;

	try {
		const lineStyle = line.getLineStyle();
		if (lineStyle && lineStyle.getWeight) {
			lineWeight = lineStyle.getWeight();
		}

		if (lineStyle && lineStyle.getSolidFill) {
			const solidFill = lineStyle.getSolidFill();
			if (solidFill) {
				const color = solidFill.getColor();
				if (color && color.getColorType() === SlidesApp.ColorType.RGB) {
					const rgb = color.asRgbColor();
					lineColor = {
						red: rgb.getRed(),
						green: rgb.getGreen(),
						blue: rgb.getBlue(),
					};
				}
			}
		}
	} catch (styleError) {
		console.log(
			`Could not read line style: ${styleError.message}, using defaults`,
		);
	}

	console.log(
		`Line ${index} style - Weight: ${lineWeight}, Color: ${lineColor ? "exists" : "default"}`,
	);

	return { lineWeight, lineColor };
}

/**
 * Recreates a line with new properties
 * @param {Shape} startShape - Starting shape for connection
 * @param {Shape} endShape - Ending shape for connection
 * @param {string} lineType - Line type to apply
 * @param {string} startArrow - Start arrow style
 * @param {string} endArrow - End arrow style
 * @param {Object} lineStyle - Original line style properties
 * @param {number} index - Line index for logging
 * @returns {boolean} True if recreation was successful
 */
function recreateLine(
	startShape,
	endShape,
	lineType,
	startArrow,
	endArrow,
	lineStyle,
	index,
) {
	// Create new line using the createConnection function which handles this properly
	console.log(`Creating new line with type: ${lineType}`);

	// Determine orientation based on shape positions
	const orientation = calculateLineOrientation(startShape, endShape);
	console.log(`Using orientation: ${orientation}`);

	// Use the createConnection function from connectionUtils
	console.log(
		`Calling createConnection with startShape, endShape, orientation=${orientation}, lineType=${lineType}`,
	);

	const newLine = createConnection(
		startShape,
		endShape,
		orientation,
		lineType,
		startArrow,
		endArrow,
	);

	console.log(`createConnection returned: ${newLine ? "LINE OBJECT" : "NULL"}`);

	if (!newLine) {
		console.log(
			`❌ Failed to create connection for line ${index} - createConnection returned null`,
		);
		return false;
	}

	console.log(
		`✅ New line created for element ${index} with arrows already applied`,
	);

	// Apply original line style properties
	applyLineStyle(newLine, lineStyle);

	console.log(`Successfully updated line ${index}`);
	return true;
}

/**
 * Calculates the orientation for a line between two shapes
 * @param {Shape} startShape - Starting shape
 * @param {Shape} endShape - Ending shape
 * @returns {string} "horizontal" or "vertical"
 */
function calculateLineOrientation(startShape, endShape) {
	const startCenter = {
		x: startShape.getLeft() + startShape.getWidth() / 2,
		y: startShape.getTop() + startShape.getHeight() / 2,
	};
	const endCenter = {
		x: endShape.getLeft() + endShape.getWidth() / 2,
		y: endShape.getTop() + endShape.getHeight() / 2,
	};

	// Determine if it's more horizontal or vertical
	const dx = Math.abs(endCenter.x - startCenter.x);
	const dy = Math.abs(endCenter.y - startCenter.y);

	return dx > dy ? "horizontal" : "vertical";
}

/**
 * Applies style properties to a line
 * @param {Line} line - The line to style
 * @param {Object} lineStyle - Style properties to apply
 */
function applyLineStyle(line, lineStyle) {
	try {
		const newLineStyle = line.getLineStyle();
		if (newLineStyle && newLineStyle.setWeight) {
			newLineStyle.setWeight(lineStyle.lineWeight);
			console.log(`Set line weight: ${lineStyle.lineWeight}`);
		}

		if (lineStyle.lineColor && newLineStyle && newLineStyle.setSolidFill) {
			newLineStyle.setSolidFill(
				lineStyle.lineColor.red,
				lineStyle.lineColor.green,
				lineStyle.lineColor.blue,
			);
			console.log(
				`Set line color: RGB(${lineStyle.lineColor.red}, ${lineStyle.lineColor.green}, ${lineStyle.lineColor.blue})`,
			);
		}
	} catch (styleError) {
		console.log(
			`Could not apply line style: ${styleError.message}, but line was created`,
		);
	}
}

/**
 * Formats the update results into a user-friendly message
 * @param {Object} results - Update results with counts
 * @returns {string} Formatted message
 */
function formatUpdateResults(results) {
	const { updatedCount, skippedCount, errorCount } = results;

	console.log(
		`Update complete - Updated: ${updatedCount}, Skipped: ${skippedCount}, Errors: ${errorCount}`,
	);

	if (updatedCount === 0) {
		return errorCount > 0
			? `❌ Failed to update lines (${errorCount} errors). Check console for details.`
			: "No lines were selected. Please select one or more lines.";
	}

	let message = `✅ Updated ${updatedCount} line${updatedCount > 1 ? "s" : ""}`;
	if (skippedCount > 0) {
		message += ` (skipped ${skippedCount} non-line element${skippedCount > 1 ? "s" : ""})`;
	}
	if (errorCount > 0) {
		message += ` (${errorCount} error${errorCount > 1 ? "s" : ""})`;
	}
	return message;
}

