/**
 * Validates that a selection contains valid shapes
 * @param {GoogleAppsScript.Slides.PageElementRange} range - Selection range
 * @param {number} expectedCount - Expected number of shapes
 * @returns {Object} - Validation result with shapes array or error message
 */
function validateShapeSelection(range, expectedCount) {
	if (!range) {
		const message =
			expectedCount === 1
				? "Please select a shape."
				: `Please select exactly ${expectedCount === 2 ? "TWO" : expectedCount} shapes.`;
		return { error: message };
	}

	const elements = range.getPageElements();
	if (elements.length !== expectedCount) {
		const message =
			expectedCount === 1
				? "Please select exactly ONE shape."
				: `Please select exactly ${expectedCount === 2 ? "TWO" : expectedCount} shapes.`;
		return { error: message };
	}

	// Validate all elements are shapes
	for (const element of elements) {
		if (element.getPageElementType() !== SlidesApp.PageElementType.SHAPE) {
			const message =
				expectedCount === 1
					? "Selected item must be a SHAPE."
					: "All selected items must be SHAPES.";
			return { error: message };
		}
	}

	// Convert to shapes
	const shapes = elements.map((element) => element.asShape());

	// For multiple shapes, verify they're on the same slide
	if (expectedCount > 1) {
		const firstSlideId = String(shapes[0].getParentPage().getObjectId());
		for (let i = 1; i < shapes.length; i++) {
			if (String(shapes[i].getParentPage().getObjectId()) !== firstSlideId) {
				return { error: "All shapes must be on the SAME slide." };
			}
		}
	}

	return expectedCount === 1 ? { shape: shapes[0] } : { shapes };
}

/**
 * Gets the current selection from the active presentation
 * @returns {GoogleAppsScript.Slides.PageElementRange|null} - Selection range or null
 */
function getCurrentSelection() {
	try {
		const pres = SlidesApp.getActivePresentation();
		const selection = pres.getSelection();
		return selection.getPageElementRange();
	} catch (e) {
		console.log(`Warning: Could not get selection: ${e.message}`);
		return null;
	}
}

/**
 * Displays an alert to the user
 * @param {string} message - Message to display
 * @param {string} title - Optional title for the alert
 */
function showAlert(message, title = "Alert") {
	try {
		SlidesApp.getUi().alert(title, message);
	} catch (e) {
		console.error(`Failed to show alert: ${e.message}`);
	}
}

/**
 * Gets shape properties in a standardized format
 * @param {GoogleAppsScript.Slides.Shape} shape - Shape to get properties from
 * @returns {Object} - Shape properties {left, top, width, height, center}
 */
function getShapeProperties(shape) {
	const left = shape.getLeft();
	const top = shape.getTop();
	const width = shape.getWidth();
	const height = shape.getHeight();

	return {
		left,
		top,
		width,
		height,
		center: {
			x: left + width / 2,
			y: top + height / 2,
		},
	};
}

/**
 * Sibling creation utilities for flowchart shapes
 * Creates sibling shapes next to selected shapes with layout consistency
 */

/**
 * Creates a sibling shape next to the selected shape
 * Analyzes existing sibling positions and places the new sibling appropriately
 * @param {number} horizontalGap - Horizontal gap in points
 * @param {number} verticalGap - Vertical gap in points
 * @param {string} lineType - Type of line to use
 * @param {string} startArrow - Start arrow style
 * @param {string} endArrow - End arrow style
 */
function createSiblingShape(
	horizontalGap = 20,
	verticalGap = 20,
	lineType = "STRAIGHT",
	startArrow = "NONE",
	endArrow = "FILL_ARROW",
	defaultStyle = null,
) {
	const pres = SlidesApp.getActivePresentation();
	const selection = pres.getSelection();
	const range = selection.getPageElementRange();

	if (!range) {
		return SlidesApp.getUi().alert(
			"Please select a shape to create a sibling for.",
		);
	}

	const els = range.getPageElements();
	if (els.length !== 1) {
		return SlidesApp.getUi().alert("Please select exactly ONE shape.");
	}

	const element = els[0];
	if (element.getPageElementType() !== SlidesApp.PageElementType.SHAPE) {
		return SlidesApp.getUi().alert("Selected item must be a SHAPE.");
	}

	const selectedShape = element.asShape();
	const selectedGraphId = getShapeGraphId(selectedShape);

	if (!selectedGraphId) {
		return SlidesApp.getUi().alert(
			"Selected shape must have a graph ID. Please create it as part of a flowchart first.",
		);
	}

	const parsed = parseGraphId(selectedGraphId);
	if (!parsed || !parsed.parent) {
		return SlidesApp.getUi().alert(
			"Selected shape must have a parent. Cannot create sibling for root shapes.",
		);
	}

	// Find the parent shape
	const slide = selectedShape.getParentPage();
	const allShapes = slide.getShapes();
	let parentShape = null;
	const siblingShapes = [];

	// Extract the immediate parent from the hierarchy chain
	// For example: if parent is "A1|B1", the immediate parent is "B1"
	const parentHierarchy = parsed.parent;
	const immediateParent = parentHierarchy.includes("|")
		? parentHierarchy.split("|").pop()
		: parentHierarchy;

	// Find parent and all existing sibling shapes (including selected shape)
	for (const shape of allShapes) {
		const graphId = getShapeGraphId(shape);
		if (graphId) {
			const shapeData = parseGraphId(graphId);
			if (shapeData) {
				// Check if this is the parent
				if (shapeData.current === immediateParent) {
					parentShape = shape;
				}
				// Check if this is a sibling (same parent hierarchy)
				if (shapeData.parent === parentHierarchy) {
					siblingShapes.push({
						shape: shape,
						data: shapeData,
						left: shape.getLeft(),
						top: shape.getTop(),
						width: shape.getWidth(),
						height: shape.getHeight(),
					});
				}
			}
		}
	}

	if (!parentShape) {
		return SlidesApp.getUi().alert(
			"Could not find parent shape. The hierarchy may be broken.",
		);
	}

	// Generate new sibling ID based on parent's children list
	const parentData = parseGraphId(getShapeGraphId(parentShape));
	if (!parentData) {
		return SlidesApp.getUi().alert("Parent shape has invalid graph ID format.");
	}

	// Get selected shape dimensions early
	const selectedLeft = selectedShape.getLeft();
	const selectedTop = selectedShape.getTop();
	const selectedWidth = selectedShape.getWidth();
	const selectedHeight = selectedShape.getHeight();

	// Determine layout from the selected shape's own layout annotation
	// Look for the selected shape in parent's children to get its layout
	let layoutToUse = "LR"; // Default
	for (const child of parentData.children) {
		if (child.id === parsed.current) {
			layoutToUse = child.layout || "LR";
			break;
		}
	}

	// Group existing siblings by their actual layout from parent's children list
	const siblingsByLayout = new Map();
	for (const sibling of siblingShapes) {
		// Find this sibling's layout from parent's children list
		let siblingLayout = "LR"; // default
		for (const child of parentData.children) {
			if (child.id === sibling.data.current) {
				siblingLayout = child.layout || "LR";
				break;
			}
		}

		if (!siblingsByLayout.has(siblingLayout)) {
			siblingsByLayout.set(siblingLayout, []);
		}
		siblingsByLayout.get(siblingLayout).push({
			...sibling,
			actualLayout: siblingLayout, // Store the actual layout
		});
	}

	// Get the level from current selected shape (e.g., "C1" -> "C")
	const currentLevel = parsed.current.match(/^([A-Z]+)/)?.[1] || "A";

	// Find the highest numbered sibling from parent's children list
	let maxSiblingNumber = 0;

	// Check parent's children list first (most reliable source)
	for (const childId of parentData.childrenIds) {
		const childLevel = childId.match(/^([A-Z]+)(\d+)$/);
		if (childLevel && childLevel[1] === currentLevel) {
			const number = Number.parseInt(childLevel[2]);
			if (number > maxSiblingNumber) {
				maxSiblingNumber = number;
			}
		}
	}

	// Also check actual shapes on slide as backup
	for (const sibling of siblingShapes) {
		const siblingLevel = sibling.data.current.match(/^([A-Z]+)(\d+)$/);
		if (siblingLevel && siblingLevel[1] === currentLevel) {
			const number = Number.parseInt(siblingLevel[2]);
			if (number > maxSiblingNumber) {
				maxSiblingNumber = number;
			}
		}
	}

	const newSiblingId = `${currentLevel}${maxSiblingNumber + 1}`;

	// Create the new sibling shape first (we'll position it later)
	const newShape = slide.insertShape(
		selectedShape.getShapeType(),
		selectedLeft, // temporary position
		selectedTop, // temporary position
		selectedWidth,
		selectedHeight,
	);

	// Copy styling from selected shape
	copyShapeStyle(selectedShape, newShape);

	// Add placeholder text for styling purposes
	try {
		newShape.getText().setText("_");
	} catch (e) {
		console.log(`Warning: Could not set sibling shape text: ${e.message}`);
	}

	// Apply default style if specified (overrides inherited styling)
	if (defaultStyle) {
		try {
			applyStyleToShape(newShape, defaultStyle);
		} catch (e) {
			console.log(`Warning: Could not apply default style: ${e.message}`);
		}
	}

	// Set the hierarchical graph ID using the determined layout
	const newGraphId = generateGraphId(
		parsed.parent,
		layoutToUse,
		newSiblingId,
		[],
	);
	setShapeGraphId(newShape, newGraphId);

	// Create new sibling shape info and add it to the appropriate layout group
	const newSiblingInfo = {
		shape: newShape,
		data: parseGraphId(newGraphId),
		left: selectedLeft,
		top: selectedTop,
		width: selectedWidth,
		height: selectedHeight,
		actualLayout: layoutToUse,
	};

	// Add the new sibling to the appropriate layout group
	if (!siblingsByLayout.has(layoutToUse)) {
		siblingsByLayout.set(layoutToUse, []);
	}
	siblingsByLayout.get(layoutToUse).push(newSiblingInfo);

	// Now reposition siblings by layout groups
	// Each layout group positions its children independently and centers them to parent
	for (const [layout, layoutSiblings] of siblingsByLayout) {
		if (layoutSiblings.length === 0) continue;

		// Sort siblings by their current IDs for consistent ordering
		layoutSiblings.sort((a, b) => {
			const aNum = Number.parseInt(a.data.current.match(/\d+$/)?.[0] || "0");
			const bNum = Number.parseInt(b.data.current.match(/\d+$/)?.[0] || "0");
			return aNum - bNum;
		});

		const isHorizontal = layout === "LR" || layout === "RL";
		const parentCenterX = parentShape.getLeft() + parentShape.getWidth() / 2;
		const parentCenterY = parentShape.getTop() + parentShape.getHeight() / 2;

		if (isHorizontal) {
			// Horizontal layout (LR/RL): siblings spread vertically, centered to parent's Y
			const totalGroupHeight =
				layoutSiblings.length * selectedHeight +
				(layoutSiblings.length - 1) * verticalGap;
			const groupStartY = parentCenterY - totalGroupHeight / 2;

			// Position siblings based on layout direction
			let siblingX;
			if (layout === "LR") {
				// LR: siblings positioned to the right of parent
				siblingX =
					parentShape.getLeft() + parentShape.getWidth() + horizontalGap;
			} else {
				// RL: siblings positioned to the left of parent
				siblingX = parentShape.getLeft() - selectedWidth - horizontalGap;
			}

			layoutSiblings.forEach((sibling, index) => {
				const newY = groupStartY + index * (selectedHeight + verticalGap);
				sibling.shape.setTop(newY);
				sibling.shape.setLeft(siblingX);
			});
		} else {
			// Vertical layout (TD/DT): siblings spread horizontally, centered to parent's X
			const totalGroupWidth =
				layoutSiblings.length * selectedWidth +
				(layoutSiblings.length - 1) * horizontalGap;
			const groupStartX = parentCenterX - totalGroupWidth / 2;

			// Position siblings based on layout direction
			let siblingY;
			if (layout === "TD") {
				// TD: siblings positioned below parent
				siblingY = parentShape.getTop() + parentShape.getHeight() + verticalGap;
			} else {
				// DT: siblings positioned above parent
				siblingY = parentShape.getTop() - selectedHeight - verticalGap;
			}

			layoutSiblings.forEach((sibling, index) => {
				const newX = groupStartX + index * (selectedWidth + horizontalGap);
				sibling.shape.setLeft(newX);
				sibling.shape.setTop(siblingY);
			});
		}
	}

	// Update parent to include the new sibling with its layout
	const newChildWithLayout = { id: newSiblingId, layout: layoutToUse };
	const updatedChildren = [...parentData.children, newChildWithLayout];
	const updatedParentId = generateGraphId(
		parentData.parent,
		parentData.layout,
		parentData.current,
		updatedChildren,
	);
	setShapeGraphId(parentShape, updatedParentId);

	// Connect based on the new sibling's specific layout
	let parentSide, childSide;
	if (layoutToUse === "LR") {
		// LR layout: parent connects from RIGHT, child connects from LEFT
		parentSide = "RIGHT";
		childSide = "LEFT";
	} else if (layoutToUse === "RL") {
		// RL layout: parent connects from LEFT, child connects from RIGHT
		parentSide = "LEFT";
		childSide = "RIGHT";
	} else if (layoutToUse === "TD") {
		// TD layout: parent connects from BOTTOM, child connects from TOP
		parentSide = "BOTTOM";
		childSide = "TOP";
	} else if (layoutToUse === "DT") {
		// DT layout: parent connects from TOP, child connects from BOTTOM
		parentSide = "TOP";
		childSide = "BOTTOM";
	} else {
		// Default fallback to LR
		parentSide = "RIGHT";
		childSide = "LEFT";
	}

	const parentSite = pickConnectionSite(parentShape, parentSide);
	const childSite = pickConnectionSite(newShape, childSide);

	if (parentSite && childSite) {
		const lineCategory =
			SlidesApp.LineCategory[lineType] || SlidesApp.LineCategory.STRAIGHT;
		const line = slide.insertLine(lineCategory, parentSite, childSite);

		// Apply arrow styles
		if (
			startArrow &&
			startArrow !== "NONE" &&
			SlidesApp.ArrowStyle[startArrow]
		) {
			line.setStartArrow(SlidesApp.ArrowStyle[startArrow]);
		}
		if (endArrow && endArrow !== "NONE" && SlidesApp.ArrowStyle[endArrow]) {
			line.setEndArrow(SlidesApp.ArrowStyle[endArrow]);
		}
	}

	return newShape;
}

/**
 * Smart selection utilities for flowchart shapes
 * Provides selection functions based on graph ID relationships
 */

/**
 * Validates that a shape is selected and has a graph ID
 * @returns {Object} - Validation result with shape, slide, and graphId or error message
 */
function validateSelectedShape() {
	const pres = SlidesApp.getActivePresentation();
	const selection = pres.getSelection();
	const range = selection.getPageElementRange();

	if (!range) {
		return { error: "Please select a shape first." };
	}

	const elements = range.getPageElements();
	if (elements.length !== 1) {
		return { error: "Please select exactly ONE shape." };
	}

	const element = elements[0];
	if (element.getPageElementType() !== SlidesApp.PageElementType.SHAPE) {
		return { error: "Selected item must be a SHAPE." };
	}

	const shape = element.asShape();
	const graphId = getShapeGraphId(shape);

	if (!graphId) {
		return {
			error:
				"Selected shape must have a graph ID. Please create it as part of a flowchart first.",
		};
	}

	const slide = shape.getParentPage();

	return {
		shape: shape,
		slide: slide,
		graphId: graphId,
	};
}

/**
 * Selects all sibling shapes that share the same parent
 */
function selectAllSiblings() {
	const validation = validateSelectedShape();
	if (validation.error) {
		return;
	}

	const { shape, slide, graphId } = validation;
	const parsed = parseGraphId(graphId);

	if (!parsed || !parsed.parent) {
		return;
	}

	const allShapes = slide.getShapes();
	const siblingShapes = [shape]; // Include the originally selected shape

	// Find all shapes with the same parent hierarchy
	for (const currentShape of allShapes) {
		if (currentShape === shape) continue; // Skip the originally selected shape (already included)

		const currentGraphId = getShapeGraphId(currentShape);
		if (currentGraphId) {
			const currentParsed = parseGraphId(currentGraphId);
			if (currentParsed?.parent === parsed.parent) {
				siblingShapes.push(currentShape);
			}
		}
	}

	if (siblingShapes.length === 1) {
		return;
	}

	// Select all sibling shapes
	try {
		// First select the first shape, then add the rest
		if (siblingShapes.length > 0) {
			siblingShapes[0].select();

			// Add remaining shapes to selection if more than one
			for (let i = 1; i < siblingShapes.length; i++) {
				siblingShapes[i].select(false); // false means don't replace existing selection
			}
		}
	} catch (e) {
		console.error(`Error selecting siblings: ${e.message}`);
	}
}

/**
 * Selects all shapes at the same level (same starting alphabet in graph ID)
 */
function selectAllLevel() {
	const validation = validateSelectedShape();
	if (validation.error) {
		return;
	}

	const { shape, slide, graphId } = validation;
	const parsed = parseGraphId(graphId);

	if (!parsed || !parsed.current) {
		return;
	}

	// Extract the level (starting alphabet) from the current ID
	const levelMatch = parsed.current.match(/^([A-Z]+)/);
	if (!levelMatch) {
		return;
	}

	const level = levelMatch[1];
	const allShapes = slide.getShapes();
	const levelShapes = [shape]; // Include the originally selected shape

	// Find all shapes that start with the same level
	for (const currentShape of allShapes) {
		if (currentShape === shape) continue; // Skip the originally selected shape (already included)

		const currentGraphId = getShapeGraphId(currentShape);
		if (currentGraphId) {
			const currentParsed = parseGraphId(currentGraphId);
			if (currentParsed?.current) {
				const currentLevelMatch = currentParsed.current.match(/^([A-Z]+)/);
				if (currentLevelMatch && currentLevelMatch[1] === level) {
					levelShapes.push(currentShape);
				}
			}
		}
	}

	if (levelShapes.length === 1) {
		return;
	}

	// Select all level shapes
	try {
		// First select the first shape, then add the rest
		if (levelShapes.length > 0) {
			levelShapes[0].select();

			// Add remaining shapes to selection if more than one
			for (let i = 1; i < levelShapes.length; i++) {
				levelShapes[i].select(false); // false means don't replace existing selection
			}
		}
	} catch (e) {
		console.error(`Error selecting level shapes: ${e.message}`);
	}
}

/**
 * Selects all parent shapes up to the root
 */
function selectAllParents() {
	const validation = validateSelectedShape();
	if (validation.error) {
		return;
	}

	const { shape, slide, graphId } = validation;
	const parsed = parseGraphId(graphId);

	if (!parsed || !parsed.parent) {
		return;
	}

	const allShapes = slide.getShapes();
	const parentShapes = [shape]; // Include the originally selected shape

	// Build the parent hierarchy chain
	const parentHierarchy = parsed.parent.split("|");

	// Find each parent in the hierarchy
	for (const parentId of parentHierarchy) {
		for (const currentShape of allShapes) {
			const currentGraphId = getShapeGraphId(currentShape);
			if (currentGraphId) {
				const currentParsed = parseGraphId(currentGraphId);
				if (currentParsed && currentParsed.current === parentId) {
					parentShapes.push(currentShape);
					break; // Found this parent, move to next
				}
			}
		}
	}

	if (parentShapes.length === 1) {
		return;
	}

	// Select all parent shapes
	try {
		// First select the first shape, then add the rest
		if (parentShapes.length > 0) {
			parentShapes[0].select();

			// Add remaining shapes to selection if more than one
			for (let i = 1; i < parentShapes.length; i++) {
				parentShapes[i].select(false); // false means don't replace existing selection
			}
		}
	} catch (e) {
		console.error(`Error selecting parent shapes: ${e.message}`);
	}
}

/**
 * Selects all family members (all descendants/children and grandchildren)
 */
function selectFamily() {
	const validation = validateSelectedShape();
	if (validation.error) {
		return;
	}

	const { shape, slide, graphId } = validation;
	const parsed = parseGraphId(graphId);

	if (!parsed || !parsed.current) {
		return;
	}

	const allShapes = slide.getShapes();
	const familyShapes = [shape]; // Include the originally selected shape

	/**
	 * Recursively find all descendants of a given shape ID
	 * @param {string} parentId - The ID to find descendants for
	 * @param {Set} visited - Set to track visited IDs to prevent infinite loops
	 */
	function findDescendants(parentId, visited = new Set()) {
		if (visited.has(parentId)) {
			return; // Prevent infinite loops
		}
		visited.add(parentId);

		for (const currentShape of allShapes) {
			if (currentShape === shape && familyShapes.includes(currentShape)) {
				continue; // Skip if already included
			}

			const currentGraphId = getShapeGraphId(currentShape);
			if (currentGraphId) {
				const currentParsed = parseGraphId(currentGraphId);
				if (currentParsed?.parent) {
					// Check if this shape is a direct child of parentId
					const parentHierarchy = currentParsed.parent.split("|");
					if (parentHierarchy[parentHierarchy.length - 1] === parentId) {
						// This is a direct child
						if (!familyShapes.includes(currentShape)) {
							familyShapes.push(currentShape);
						}
						// Recursively find its children
						findDescendants(currentParsed.current, visited);
					}
				}
			}
		}
	}

	// Start the recursive search from the selected shape
	findDescendants(parsed.current);

	if (familyShapes.length === 1) {
		return;
	}

	// Select all family shapes
	try {
		// First select the first shape, then add the rest
		if (familyShapes.length > 0) {
			familyShapes[0].select();

			// Add remaining shapes to selection if more than one
			for (let i = 1; i < familyShapes.length; i++) {
				familyShapes[i].select(false); // false means don't replace existing selection
			}
		}
	} catch (e) {
		console.error(`Error selecting family shapes: ${e.message}`);
	}
}

/**
 * Wrapper function to receive gap value from HTML
 * @param {number} gap - Gap between shapes in pixels
 */
function alignChildrenWithGap(gap = 20) {
	alignChildren(gap);
}

/**
 * Aligns all direct children of the selected shape
 * @param {number} gap - Gap between shapes in pixels (default 20)
 */
function alignChildren(gap = 20) {
	const validation = validateSelectedShape();
	if (validation.error) {
		return;
	}

	const { shape, slide, graphId } = validation;
	const parsed = parseGraphId(graphId);

	if (!parsed || !parsed.current) {
		return;
	}

	const allShapes = slide.getShapes();
	const childShapes = [];

	// Find all direct children (same pattern as selectFamily)
	for (const currentShape of allShapes) {
		const currentGraphId = getShapeGraphId(currentShape);
		if (currentGraphId) {
			const currentParsed = parseGraphId(currentGraphId);
			if (currentParsed?.parent) {
				// Check if this shape is a direct child
				const parentHierarchy = currentParsed.parent.split("|");
				if (parentHierarchy[parentHierarchy.length - 1] === parsed.current) {
					childShapes.push(currentShape);
				}
			}
		}
	}

	if (childShapes.length === 0) {
		return;
	}

	try {
		// Get parent position and dimensions
		const parentLeft = shape.getLeft();
		const parentTop = shape.getTop();
		const parentWidth = shape.getWidth();
		const parentHeight = shape.getHeight();
		const parentCenterX = parentLeft + parentWidth / 2;
		const parentCenterY = parentTop + parentHeight / 2;

		// Get child dimensions
		const childData = childShapes.map((child) => ({
			shape: child,
			width: child.getWidth(),
			height: child.getHeight(),
		}));

		if (parsed.layout === "TD" || parsed.layout === "DT") {
			// Top-Down layout: align children horizontally below parent
			const startY = parentTop + parentHeight + gap;
			const totalWidth =
				childData.reduce((sum, child) => sum + child.width, 0) +
				gap * (childData.length - 1);
			let currentX = parentCenterX - totalWidth / 2;

			childData.forEach((child) => {
				child.shape.setLeft(currentX);
				child.shape.setTop(startY);
				currentX += child.width + gap;
			});
		} else {
			// Left-Right layout: align children vertically to the right of parent
			const startX = parentLeft + parentWidth + gap;
			const totalHeight =
				childData.reduce((sum, child) => sum + child.height, 0) +
				gap * (childData.length - 1);
			let currentY = parentCenterY - totalHeight / 2;

			childData.forEach((child) => {
				child.shape.setLeft(startX);
				child.shape.setTop(currentY);
				currentY += child.height + gap;
			});
		}

		// Re-select the original shape
		shape.select();
	} catch (e) {
		console.error(`Error aligning children: ${e.message}`);
	}
}

/**
 * Aligns the parent shape based on the center of its children
 */
function alignWithParent() {
	const validation = validateSelectedShape();
	if (validation.error) {
		return;
	}

	const { shape, slide, graphId } = validation;
	const parsed = parseGraphId(graphId);

	if (!parsed || !parsed.parent) {
		return;
	}

	// Get the immediate parent ID
	const parentHierarchy = parsed.parent.split("|");
	const immediateParentId = parentHierarchy[parentHierarchy.length - 1];

	const allShapes = slide.getShapes();
	let parentShape = null;
	let parentLayout = null;

	// Find the parent shape
	for (const currentShape of allShapes) {
		const currentGraphId = getShapeGraphId(currentShape);
		if (currentGraphId) {
			const currentParsed = parseGraphId(currentGraphId);
			if (currentParsed && currentParsed.current === immediateParentId) {
				parentShape = currentShape;
				parentLayout = currentParsed.layout;
				break;
			}
		}
	}

	if (!parentShape) {
		return;
	}

	// Find all siblings (including selected shape)
	const siblingShapes = [shape];
	for (const currentShape of allShapes) {
		if (currentShape === shape) continue;

		const currentGraphId = getShapeGraphId(currentShape);
		if (currentGraphId) {
			const currentParsed = parseGraphId(currentGraphId);
			if (currentParsed?.parent) {
				const currentParentHierarchy = currentParsed.parent.split("|");
				if (
					currentParentHierarchy[currentParentHierarchy.length - 1] ===
					immediateParentId
				) {
					siblingShapes.push(currentShape);
				}
			}
		}
	}

	if (siblingShapes.length === 0) {
		return;
	}

	try {
		// Calculate bounding box of all siblings
		let minX = Number.POSITIVE_INFINITY;
		let maxX = Number.NEGATIVE_INFINITY;
		let minY = Number.POSITIVE_INFINITY;
		let maxY = Number.NEGATIVE_INFINITY;

		for (const sibling of siblingShapes) {
			const left = sibling.getLeft();
			const top = sibling.getTop();
			const right = left + sibling.getWidth();
			const bottom = top + sibling.getHeight();

			minX = Math.min(minX, left);
			maxX = Math.max(maxX, right);
			minY = Math.min(minY, top);
			maxY = Math.max(maxY, bottom);
		}

		// Calculate center of siblings
		const siblingsCenterX = (minX + maxX) / 2;
		const siblingsCenterY = (minY + maxY) / 2;

		// Move parent to align with siblings center
		const parentWidth = parentShape.getWidth();
		const parentHeight = parentShape.getHeight();

		if (parentLayout === "TD" || parentLayout === "DT") {
			// Top-Down: align parent horizontally with siblings center
			const newParentLeft = siblingsCenterX - parentWidth / 2;
			parentShape.setLeft(newParentLeft);
		} else {
			// Left-Right: align parent vertically with siblings center
			const newParentTop = siblingsCenterY - parentHeight / 2;
			parentShape.setTop(newParentTop);
		}

		// Re-select the original shape
		shape.select();
	} catch (e) {
		console.error(`Error aligning parent: ${e.message}`);
	}
}

/**
 * Stage Bar utilities for flowchart elements
 * Provides functions for creating HOME_PLATE stage bars for process flows and timelines
 * Creates visual process indicators behind selected shapes
 */

/**
 * Adds a stage bar (HOME_PLATE shape) behind selected shapes
 * @param {number} baseY - Base Y position for the stage bar (default 100)
 * @param {number} offsetX - X offset from the leftmost shape (default -20)
 * @param {number} extraWidth - Extra width beyond the rightmost shape (default 30)
 * @param {number} height - Height of the stage bar (default 15)
 * @param {string} fillColor - Fill color for the stage bar (default #3D6869)
 * @param {number} opacity - Opacity of the stage bar (default 1.0)
 * @param {string} strokeColor - Border stroke color (default #FFFFFF)
 * @param {string} text - Optional text to display on the stage bar (default "")
 * @param {number} fontSize - Font size for the text (default 10)
 */
function addStageBar(
	baseY = 100,
	offsetX = -20,
	extraWidth = 30,
	height = 15,
	fillColor = "#3D6869",
	opacity = 1.0,
	strokeColor = "#FFFFFF",
	text = "",
	fontSize = 10,
) {
	try {
		const pres = SlidesApp.getActivePresentation();
		const selection = pres.getSelection();

		if (!selection) {
			throw new Error("Please select one or more shapes to add a stage bar.");
		}

		const range = selection.getPageElementRange();
		if (!range) {
			throw new Error("Please select one or more shapes to add a stage bar.");
		}

		const elements = range.getPageElements();
		if (elements.length === 0) {
			throw new Error("No elements selected.");
		}

		// Filter to only include shapes
		const shapes = elements.filter(
			(element) =>
				element.getPageElementType() === SlidesApp.PageElementType.SHAPE,
		);

		if (shapes.length === 0) {
			throw new Error("Please select at least one shape to add a stage bar.");
		}

		// Calculate the leftmost and rightmost positions
		let minLeft = Number.MAX_VALUE;
		let maxRight = Number.MIN_VALUE;

		shapes.forEach((element) => {
			const shape = element.asShape();
			const left = shape.getLeft();
			const width = shape.getWidth();
			const right = left + width;

			minLeft = Math.min(minLeft, left);
			maxRight = Math.max(maxRight, right);
		});

		// Calculate stage bar dimensions
		const stageLeft = minLeft + offsetX;
		const stageWidth = maxRight - minLeft + extraWidth;
		const stageTop = baseY;

		// Get the slide from the first shape
		const slide = shapes[0].asShape().getParentPage();

		// Create the HOME_PLATE shape as stage bar
		const stageBar = slide.insertShape(
			SlidesApp.ShapeType.HOME_PLATE,
			stageLeft,
			stageTop,
			stageWidth,
			height,
		);

		// Style the stage bar
		stageBar.getFill().setSolidFill(fillColor, opacity);

		// Set white border by default
		stageBar.getBorder().setWeight(1);
		stageBar.getBorder().getLineFill().setSolidFill(strokeColor);

		// Add text if provided
		if (text && text.trim() !== "") {
			stageBar.getText().setText(text);
			const textStyle = stageBar.getText().getTextStyle();
			textStyle.setFontSize(fontSize);
			textStyle.setForegroundColor("#FFFFFF"); // White text for contrast
			textStyle.setBold(false);

			// Center align the text
			const paragraphStyle = stageBar.getText().getParagraphStyle();
			paragraphStyle.setParagraphAlignment(SlidesApp.ParagraphAlignment.CENTER);
		}

		// Set title for identification
		stageBar.setTitle("flowchartstagesbar");

		// Reorder all stage bars on the slide (leftmost on top)
		// This will handle sending all bars to back in the correct order
		reorderStageBars(slide);

		// Select the created stage bar
		stageBar.select();

		console.log(
			`Stage bar created: ${stageWidth}x${height} at (${stageLeft}, ${stageTop}) with color ${fillColor}`,
		);

		return `Stage bar added successfully! Width: ${Math.round(stageWidth)} at Y: ${baseY}`;
	} catch (e) {
		const errorMsg = `Error creating stage bar: ${e.message}`;
		console.error(errorMsg);
		throw new Error(errorMsg);
	}
}

/**
 * Quick function to add a default stage bar
 * Uses default settings for rapid prototyping
 */
function addDefaultStageBar() {
	return addStageBar();
}

/**
 * Add a stage bar with custom color theme
 * @param {string} theme - Color theme: 'blue', 'green', 'orange', 'purple', or hex color
 * @param {string} text - Optional text to display on the stage bar
 */
function addThemedStageBar(theme = "blue", text = "") {
	const themes = {
		blue: "#2196F3",
		green: "#4CAF50",
		orange: "#FF9800",
		purple: "#9C27B0",
		teal: "#009688",
		red: "#F44336",
		gray: "#757575",
	};

	const color = themes[theme] || theme;
	return addStageBar(100, -20, 30, 15, color, 1.0, "#FFFFFF", text, 10);
}

/**
 * Add multiple stage bars at different Y positions
 * Useful for creating multi-level process diagrams
 * @param {Array} yPositions - Array of Y positions for multiple stage bars
 * @param {string} fillColor - Fill color for all stage bars
 */
function addMultipleStageBar(
	yPositions = [100, 150, 200],
	fillColor = "#3D6869",
) {
	const results = [];

	yPositions.forEach((yPos, index) => {
		try {
			const result = addStageBar(
				yPos,
				-20,
				30,
				15,
				fillColor,
				1.0 - index * 0.1,
				"#FFFFFF",
			);
			results.push(`Level ${index + 1}: ${result}`);
		} catch (e) {
			results.push(`Level ${index + 1}: Failed - ${e.message}`);
		}
	});

	return results.join("\n");
}

/**
 * Reorders all stage bars on a slide so that leftmost bars appear on top
 * This creates a proper layering effect for overlapping stage bars
 * @param {Slide} slide - The slide containing the stage bars
 */
function reorderStageBars(slide) {
	try {
		// Get all shapes on the slide
		const shapes = slide.getShapes();

		// Filter to only get stage bars (shapes with title "flowchartstagesbar")
		const stageBars = [];
		shapes.forEach((shape) => {
			if (shape.getTitle() === "flowchartstagesbar") {
				stageBars.push({
					shape: shape,
					x: shape.getLeft(),
				});
			}
		});

		// Always send all stage bars to back, even if there's only one
		// This ensures they're behind other content
		if (stageBars.length === 0) {
			return;
		}

		// Sort stage bars by X position (left to right)
		stageBars.sort((a, b) => a.x - b.x);

		// Send stage bars to back from LEFT TO RIGHT (X=100, X=150, X=200, X=300)
		// The LAST one sent to back (X=300) will be at the very bottom
		// The FIRST one sent to back (X=100) will be on top of other stage bars
		for (let i = 0; i < stageBars.length; i++) {
			stageBars[i].shape.sendToBack();
		}

		console.log(
			`Reordered ${stageBars.length} stage bars (leftmost on top, all behind other content)`,
		);
	} catch (e) {
		console.error(`Error reordering stage bars: ${e.message}`);
		// Don't throw error to avoid interrupting the main flow
	}
}

/**
 * Manually reorder all stage bars on the current slide
 * Useful for fixing layering after manual adjustments
 */
function reorderCurrentSlideStageBars() {
	try {
		const pres = SlidesApp.getActivePresentation();
		const selection = pres.getSelection();
		const currentPage = selection.getCurrentPage();

		if (!currentPage) {
			throw new Error("No current slide selected");
		}

		reorderStageBars(currentPage);

		return "Stage bars reordered successfully (leftmost on top)";
	} catch (e) {
		const errorMsg = `Error reordering stage bars: ${e.message}`;
		console.error(errorMsg);
		throw new Error(errorMsg);
	}
}

/**
 * Server-side core for the Gallery Minter (圖片藝廊鑄造器) dialog.
 *
 * Takes a list of image URLs (one per line, optional "| caption" suffix) and
 * lays them out as a grid of images on the current slide. Columns are chosen
 * automatically from the image count (grid-style equal layout) unless the user
 * overrides them. Each image is fitted (aspect-preserving) into its grid cell,
 * with an optional caption text box rendered below.
 *
 * Mirrors the Callout / Grid Minter pattern:
 *  - getGalleryTemplates() feeds the dialog's template picker + live preview.
 *  - insertGalleryIntoSlide(payload) inserts onto the current slide.
 *  - Positions are computed like grid_minter (start Y ~120, margin 30, gap 12).
 *
 * Images are fetched by Google Slides itself via slide.insertImage(url), so the
 * URLs MUST be publicly accessible. Each insertImage() is wrapped in try/catch;
 * a failed URL is collected as a warning and never aborts the rest of the batch.
 */

/**
 * Single source of truth for gallery templates. Colors resolve from the global
 * palette so they track the configured theme. `border` controls whether each
 * image gets an outline; `borderColor` is the outline color when enabled.
 *
 * @return {Array<{id,name,border,borderColor,borderWidth,captionColor,swatch}>}
 */
function buildGalleryTemplates_() {
	const main = (typeof main_color !== "undefined" && main_color) || "#3D6869";
	const accent =
		(typeof accent_color !== "undefined" && accent_color) || "#f29424";
	const text =
