/**
 * Splits the selected shape into a grid of shapes.
 * @param {number} rows - Number of rows in the grid.
 * @param {number} columns - Number of columns in the grid.
 * @param {number} gap - Gap size between shapes in points.
 */
function splitSelectedShape(rows, columns, gap) {
	try {
		// Get the active presentation and selection
		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();
		const slide = selection.getCurrentPage();

		// Get the selected shape
		const selectedElements = selection.getPageElementRange().getPageElements();
		const selectedShapes = selectedElements.filter(
			(element) =>
				element.getPageElementType() === SlidesApp.PageElementType.SHAPE,
		);

		if (selectedShapes.length !== 1) {
			throw new Error("Please select exactly one shape to split.");
		}

		const originalShape = selectedShapes[0].asShape();

		// Log shape information for debugging
		console.log("Element type: " + originalShape.getPageElementType());
		console.log("Element ID: " + originalShape.getObjectId());
		console.log(
			"Position: Left " +
				originalShape.getLeft() +
				", Top " +
				originalShape.getTop(),
		);
		console.log(
			"Size: Width " +
				originalShape.getWidth() +
				", Height " +
				originalShape.getHeight(),
		);
		console.log("Rotation: " + originalShape.getRotation() + " degrees");
		console.log("Shape type: " + originalShape.getShapeType());

		// Get the properties of the original shape
		const originalLeft = originalShape.getLeft();
		const originalTop = originalShape.getTop();
		const originalWidth = originalShape.getWidth();
		const originalHeight = originalShape.getHeight();
		const originalRotation = originalShape.getRotation();
		const originalShapeType = originalShape.getShapeType();

		// Calculate the dimensions for each new shape
		const cellWidth = (originalWidth - gap * (columns - 1)) / columns;
		const cellHeight = (originalHeight - gap * (rows - 1)) / rows;

		// Create an array to store all new shapes
		const newShapes = [];

		// Create the grid of shapes
		for (let row = 0; row < rows; row++) {
			for (let col = 0; col < columns; col++) {
				// Calculate position for the new shape
				const left = originalLeft + col * (cellWidth + gap);
				const top = originalTop + row * (cellHeight + gap);

				// Create the new shape
				const newShape = slide.insertShape(
					originalShapeType,
					left,
					top,
					cellWidth,
					cellHeight,
				);

				// Apply rotation if the original shape had any
				if (originalRotation !== 0) {
					newShape.setRotation(originalRotation);
				}

				// Copy the styling from the original shape
				copyShapeStyle(originalShape, newShape);

				// Add to our array of new shapes
				newShapes.push(newShape);
			}
		}

		// Remove the original shape
		originalShape.remove();

		// Log completion message
		console.log(
			"Successfully created " +
				newShapes.length +
				" shapes in a " +
				rows +
				"x" +
				columns +
				" grid with " +
				gap +
				"pt gaps",
		);
	} catch (error) {
		SlidesApp.getUi().alert(
			"Error",
			"An error occurred: " + error.message,
			SlidesApp.getUi().ButtonSet.OK,
		);
	}
}

/**
 * Copies the style from one shape to another.
 * @param {Shape} sourceShape - The shape to copy style from.
 * @param {Shape} targetShape - The shape to apply the style to.
 */
function copyShapeStyle(sourceShape, targetShape) {
	try {
		// Copy fill
		try {
			const sourceFill = sourceShape.getFill();
			if (sourceFill && sourceFill.getType() === SlidesApp.FillType.SOLID) {
				const sourceSolidFill = sourceFill.getSolidFill();
				if (sourceSolidFill) {
					const color = sourceSolidFill.getColor();
					const alpha = sourceSolidFill.getAlpha();
					targetShape.getFill().setSolidFill(color, alpha);
				}
			}
		} catch (e) {
			console.log("Warning: Could not copy fill: " + e.message);
		}

		// Copy border - using proper border handling for Google Slides
		const sourceBorder = sourceShape.getBorder();
		const targetBorder = targetShape.getBorder();

		if (sourceBorder && targetBorder) {
			// Set border weight and dash style
			try {
				targetBorder.setWeight(sourceBorder.getWeight());
			} catch (e) {
				console.log("Warning: Could not copy border weight: " + e.message);
			}

			try {
				targetBorder.setDashStyle(sourceBorder.getDashStyle());
			} catch (e) {
				console.log("Warning: Could not copy border dash style: " + e.message);
			}

			// Set border color if it's a solid fill
			const borderLineFill = sourceBorder.getLineFill();
			if (
				borderLineFill &&
				borderLineFill.getType() === SlidesApp.FillType.SOLID
			) {
				const sourceSolidFill = borderLineFill.getSolidFill();
				if (sourceSolidFill) {
					targetBorder
						.getLineFill()
						.setSolidFill(
							sourceSolidFill.getColor(),
							sourceSolidFill.getAlpha(),
						);
				}
			}
		}

		// Copy text style if applicable
		if (sourceShape.getText() && targetShape.getText()) {
			try {
				const sourceTextStyle = sourceShape.getText().getTextStyle();
				const targetTextStyle = targetShape.getText().getTextStyle();

				// Copy basic text properties
				try {
					const fontFamily = sourceTextStyle.getFontFamily();
					if (fontFamily) {
						targetTextStyle.setFontFamily(fontFamily);
					}
				} catch (e) {
					console.log("Warning: Could not copy font family: " + e.message);
				}

				try {
					const fontSize = sourceTextStyle.getFontSize();
					if (fontSize) {
						targetTextStyle.setFontSize(fontSize);
					}
				} catch (e) {
					console.log("Warning: Could not copy font size: " + e.message);
				}

				// Copy bold styling - using safer boolean check
				try {
					const isBold = sourceTextStyle.isBold();
					if (typeof isBold === "boolean") {
						targetTextStyle.setBold(isBold);
					}
				} catch (e) {
					console.log("Warning: Could not copy bold style: " + e.message);
				}

				// Copy italic styling - using safer boolean check
				try {
					const isItalic = sourceTextStyle.isItalic();
					if (typeof isItalic === "boolean") {
						targetTextStyle.setItalic(isItalic);
					}
				} catch (e) {
					console.log("Warning: Could not copy italic style: " + e.message);
				}

				// Copy underline styling - using safer boolean check
				try {
					const isUnderline = sourceTextStyle.isUnderline();
					if (typeof isUnderline === "boolean") {
						targetTextStyle.setUnderline(isUnderline);
					}
				} catch (e) {
					console.log("Warning: Could not copy underline style: " + e.message);
				}

				// Copy text color if available
				try {
					const fontColor = sourceTextStyle.getForegroundColor();
					if (fontColor) {
						targetTextStyle.setForegroundColor(fontColor);
					}
				} catch (e) {
					console.log("Warning: Could not copy font color: " + e.message);
				}
			} catch (e) {
				console.log("Warning: Could not copy text style: " + e.message);
			}
		}
	} catch (error) {
		// Log error but continue execution
		console.log("Error copying style: " + error.message);
	}
}

/**
 * Syntax Parser for Child Shapes
 * Handles text parsing and grid layout logic
 */

/**
 * Parses grid syntax supporting two formats:
 * 1. Multi-row: {[item1|item2|item3][item4|item5]} - rows with columns
 * 2. Single-row: {item1} {item2} {item3} - simple column layout
 * @param {string} text - The text to parse
 * @return {Object|null} Grid layout object or null if invalid syntax
 */
function parseGridSyntax(text) {
	// First try to match multi-row format: {[...][...]}
	const multiRowRegex = /\{(\[.*?\])+\}/;
	const multiRowMatch = text.match(multiRowRegex);

	if (multiRowMatch) {
		return parseMultiRowSyntax(multiRowMatch[0]);
	}

	// Try to match single-row format: {} {} {}
	const singleRowRegex = /\{([^}]*)\}/g;
	const singleRowMatches = [];
	let singleRowMatch;

	while ((singleRowMatch = singleRowRegex.exec(text)) !== null) {
		const content = singleRowMatch[1].trim();
		if (content) {
			singleRowMatches.push(content);
		}
	}

	if (singleRowMatches.length > 0) {
		return parseSingleRowSyntax(singleRowMatches);
	}

	return null;
}

/**
 * Parses multi-row syntax like {[item1|item2][item3|item4]}
 * @param {string} gridText - The matched grid text
 * @return {Object} Grid layout object
 */
function parseMultiRowSyntax(gridText) {
	// Extract all row patterns [...]
	const rowRegex = /\[([^\]]*)\]/g;
	const rows = [];
	let rowMatch;

	while ((rowMatch = rowRegex.exec(gridText)) !== null) {
		const rowContent = rowMatch[1];
		// Split by | to get columns, filter out empty strings
		const columns = rowContent.split("|").filter((col) => col.trim() !== "");
		if (columns.length > 0) {
			rows.push(columns);
		}
	}

	if (rows.length === 0) {
		return null;
	}

	// Find the maximum number of columns across all rows
	const maxColumns = Math.max(...rows.map((row) => row.length));

	return {
		rows: rows.length,
		maxColumns: maxColumns,
		rowData: rows,
		isVariableColumns: rows.some((row) => row.length !== maxColumns),
		syntaxType: "multi-row",
	};
}

/**
 * Parses single-row syntax like {item1} {item2} {item3}
 * @param {Array} matches - Array of matched content strings
 * @return {Object} Grid layout object
 */
function parseSingleRowSyntax(matches) {
	return {
		rows: 1,
		maxColumns: matches.length,
		rowData: [matches], // Single row with all the columns
		isVariableColumns: false,
		syntaxType: "single-row",
	};
}

/**
 * Simple syntax parser: Line 1 = title, Line 2 = parent text, Line 3+ = rows (| separated)
 * Supports [bold] text formatting and (footer) boxes. No complex {[]} syntax needed.
 */
function autoCreateChildShapesFromLines() {
	try {
		// Get the active presentation and selection
		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();

		// Check if a shape is selected
		const selectedElements = selection.getPageElementRange()
			? selection.getPageElementRange().getPageElements()
			: [];

		const selectedShapes = selectedElements.filter(
			(element) =>
				element.getPageElementType() === SlidesApp.PageElementType.SHAPE,
		);

		if (selectedShapes.length !== 1) {
			SlidesApp.getUi().alert(
				"Error",
				"Please select exactly one shape with line-based text to create child shapes.",
				SlidesApp.getUi().ButtonSet.OK,
			);
			return;
		}

		const parentShape = selectedShapes[0].asShape();

		// Get the raw text content (preserve line breaks)
		const rawTextContent = parentShape.getText().asString();
		const lines = rawTextContent.split(/\r?\n/);

		// Filter out empty lines
		const nonEmptyLines = lines.filter((line) => line.trim() !== "");

		if (nonEmptyLines.length < 3) {
			SlidesApp.getUi().alert(
				"Error",
				"Need at least 3 lines: Line 1 = title, Line 2 = parent text, Line 3+ = rows",
				SlidesApp.getUi().ButtonSet.OK,
			);
			return;
		}

		// Parse the lines
		const titleText = nonEmptyLines[0].trim();
		const parentText = nonEmptyLines[1].trim();
		const rowLines = nonEmptyLines.slice(2);

		// Parse rows (split by | but handle -|> syntax)
		const rowData = rowLines
			.map((line) => parseRowWithHomePlates(line))
			.filter((rowInfo) => rowInfo.cells.length > 0);

		if (rowData.length === 0) {
			SlidesApp.getUi().alert(
				"Error",
				"No valid rows found. Use | to separate columns in each row.",
				SlidesApp.getUi().ButtonSet.OK,
			);
			return;
		}

		// Create the layout structure
		const maxColumns = Math.max(
			...rowData.map((rowInfo) => rowInfo.cells.length),
		);
		const layout = {
			rows: rowData.length,
			maxColumns: maxColumns,
			rowData: rowData,
			isVariableColumns: rowData.some(
				(rowInfo) => rowInfo.cells.length !== maxColumns,
			),
			syntaxType: "line-based",
		};

		// Get the slide
		const slide = selection.getCurrentPage();

		// Create title text box if title exists
		if (titleText) {
			createTitleTextBoxFromText(parentShape, titleText, slide);
		}

		// Set parent text
		parentShape.getText().setText(parentText);
		parentShape.setContentAlignment(SlidesApp.ContentAlignment.TOP);
		parentShape.setTitle("PARENT");

		// Create child shapes with default settings
		const DEFAULT_PADDING = 10;
		const DEFAULT_PADDING_TOP = 30;
		const DEFAULT_GAP = 10;

		createChildShapesWithLayout(
			parentShape,
			layout,
			DEFAULT_PADDING,
			DEFAULT_PADDING_TOP,
			DEFAULT_GAP,
		);

		console.log(
			`Auto-created child shapes from ${rowData.length} lines with line-based syntax`,
		);
	} catch (error) {
		SlidesApp.getUi().alert(
			"Error",
			`An error occurred: ${error.message}`,
			SlidesApp.getUi().ButtonSet.OK,
		);
	}
}

/**
 * Parses a row line to detect -|> syntax for home plates and extract cells.
 * Also detects -- syntax for vertical cell splitting (e.g., "upper--lower").
 * @param {string} line - The row line to parse
 * @return {Object} Object with cells array and homePlates array
 */
function parseRowWithHomePlates(line) {
	// Split by | but keep track of home plate positions
	const parts = line.split("|");
	const rawCells = [];
	const homePlates = [];

	// First pass: Handle home plate syntax (-|>) and collect raw cell text
	for (let i = 0; i < parts.length; i++) {
		const part = parts[i].trim();

		// Check for home plate syntax: current part ends with single - and next part starts with >
		// But NOT if it's part of -- vertical split syntax
		if (part.endsWith("-") && !part.endsWith("--") && i < parts.length - 1) {
			// Next part should start with > for complete -|> syntax
			const nextPart = parts[i + 1].trim();
			if (nextPart.startsWith(">")) {
				// This is a home plate position
				// Add the cell without the trailing -
				const cellText = part.slice(0, -1).trim();
				if (cellText) {
					rawCells.push(cellText);
				}

				// Record home plate position (after current cell)
				homePlates.push(rawCells.length);

				// Add the next cell without the leading >
				const nextCellText = nextPart.slice(1).trim();
				if (nextCellText) {
					rawCells.push(nextCellText);
				}

				// Skip the next part since we already processed it
				i++;
			} else {
				// Not a home plate, just a regular cell
				if (part) {
					rawCells.push(part);
				}
			}
		} else {
			// Regular cell
			if (part) {
				rawCells.push(part);
			}
		}
	}

	// Second pass: Keep raw cells as strings for now, defer vertical split processing
	const cells = rawCells;

	return {
		cells: cells.filter((cell) => cell !== ""),
		homePlates: homePlates,
	};
}

/**
 * Processes a cell for vertical splitting using -- syntax.
 * Examples: "upper--lower" creates 2 vertical sections (50%/50%)
 *          "top--middle--bottom" creates 3 sections (33%/33%/33%)
 * @param {string} cellText - The cell text to process
 * @return {Object|string} Either a string for normal cells or an object for split cells
 */
function processCellForVerticalSplit(cellText) {
	// Check if cell contains -- for vertical splitting
	if (cellText.includes("--")) {
		const segments = cellText
			.split("--")
			.map((segment) => segment.trim())
			.filter((segment) => segment !== "");

		// Only create vertical split if we have 2 or more valid segments
		if (segments.length >= 2) {
			return {
				isVerticalSplit: true,
				segments: segments,
				segmentCount: segments.length,
			};
		}
	}

	// Return as regular cell text if no splitting or insufficient segments
	return cellText;
}

/**
 * Processes cell text to extract main content and footer box text.
 * Detects (text) pattern for footer boxes.
 * @param {string} cellText - The original cell text
 * @return {Object} Object with hasFooter, mainText, and footerText properties
 */
function processFooterBoxText(cellText) {
	// Handle vertical split cells - apply footer processing to each segment
	if (typeof cellText === "object" && cellText.isVerticalSplit) {
		const processedSegments = cellText.segments.map((segment) => {
			const footerData = processFooterBoxTextForSegment(segment);
			return footerData;
		});

		return {
			isVerticalSplit: true,
			segments: processedSegments,
			segmentCount: cellText.segmentCount,
			hasFooter: processedSegments.some((seg) => seg.hasFooter),
		};
	}

	// Regular cell processing
	return processFooterBoxTextForSegment(cellText);
}

/**
 * Processes a single text segment for footer box extraction.
 * @param {string} segmentText - The text segment to process
 * @return {Object} Object with hasFooter, mainText, and footerText properties
 */
function processFooterBoxTextForSegment(segmentText) {
	// Check if text contains footer pattern (text)
	const footerRegex = /\(([^)]*)\)/;
	const match = segmentText.match(footerRegex);

	if (match) {
		const footerText = match[1]; // Text inside parentheses
		const mainText = segmentText.replace(footerRegex, "").trim(); // Text without parentheses

		return {
			hasFooter: true,
			mainText: mainText,
			footerText: footerText,
		};
	}

	return {
		hasFooter: false,
		mainText: segmentText,
		footerText: "",
	};
}

/**
 * Server-side core for the Grid Minter dialog.
 *
 * Turns arbitrary user "context" into a list of "units" — each unit being a
 * heading + subheading + paragraph — then lays those units out as styled cards
 * on a grid (e.g. 3×2) and inserts them onto the current slide via the Slides
 * API. Overflow units spill onto freshly appended slides.
 *
 * Mirrors the Table Minter pattern (src/util/table_minter.js):
 *  - AI generation reuses callGroq_() / hasUserApiKey() from src/util/aiKey.js.
 *  - Insertion batches every request into a single Slides.Presentations.batchUpdate.
 *  - Card colors come from getStyleDefinitions() (src/util/default_style.js).
 *
 * The unit markdown format (also documented in the dialog):
 *   # Title
 *   ## Subtitle
 *
 *   A paragraph of body text.
 *   ---
 *   # Next Title
 *   ...
 * Units are separated by a line containing only "---".
 */

/**
 * Builds the Groq system prompt for grid units. When `hasSubtitle` is true each
 * unit carries a '## ' subtitle line; otherwise the prompt explicitly tells the
 * model to omit subtitles (title + paragraph only).
 *
 * @param {boolean} hasSubtitle
 * @return {string}
 */
function buildGridSystemPrompt_(hasSubtitle) {
	const lines = [
		"You convert the user's content into a set of grid 'units' (key points).",
		"Output EXACTLY this and nothing else:",
	];
	if (hasSubtitle) {
		lines.push(
			"- For each key point, one unit made of, in this order:",
			"  1. A title line starting with '# ' (a short 1–4 word heading).",
			"  2. A subtitle line starting with '## ' (a short supporting phrase).",
			"  3. After a blank line, ONE concise paragraph (1–2 sentences).",
		);
	} else {
		lines.push(
			"- For each key point, one unit made of, in this order:",
			"  1. A title line starting with '# ' (a short 1–4 word heading).",
			"  2. After a blank line, ONE concise paragraph (1–2 sentences).",
			"- Do NOT include any '## ' subtitle lines.",
		);
	}
	lines.push(
		"- Separate consecutive units with a line that contains only '---'.",
		"Strict rules:",
		"- No explanation, no preamble, no closing remarks, no code fences.",
		"- The very first line MUST start with '# '.",
		"- Aim for between 2 and 9 units, grouping the content into logical key points.",
		"- Keep text concise; do not invent facts that aren't implied by the input.",
	);
	return lines.join("\n");
}

/**
 * Generates grid-unit Markdown from free-form context via Groq.
 * Called from the dialog through google.script.run.
 *
 * @param {string} context - Arbitrary text the user pasted.
 * @param {boolean} [hasSubtitle=true] - Whether units should include '## ' subtitles.
 * @return {{success: boolean, generatedText?: string, error?: string, needKey?: boolean}}
 */
function generateGridMarkdownFromContext(context, hasSubtitle) {
	const text = (context || "").trim();
	if (!text) {
		return { success: false, error: "No context provided." };
	}

	// Don't throw on a missing key — let the dialog show a friendly prompt to
	// run the explicit "🔑 設定 AI 金鑰 (Groq)" menu item.
	if (!hasUserApiKey()) {
		return {
			success: false,
			needKey: true,
			error:
				"No AI key set. Run 🖖 跨頁功能 → 🔑 設定 AI 金鑰 (Groq) first, then try again.",
		};
	}

	const wantSubtitle = hasSubtitle !== false; // default to including subtitles
	return callGroq_(buildGridSystemPrompt_(wantSubtitle), text, {
		maxTokens: 2500,
		temperature: 0.3,
	});
}

/**
 * Parses unit markdown into an array of {title, subtitle, body}.
 * Units are separated by a line containing only "---". Within a unit, the first
 * "# " line is the title, the first "## " line is the subtitle, and any
 * remaining non-heading text is the body paragraph.
 *
 * @param {string} markdown
 * @return {Array<{title: string, subtitle: string, body: string}>}
 */
function parseGridUnits_(markdown) {
	const text = (markdown || "").replace(/\r\n/g, "\n").trim();
	if (!text) return [];

	// Split on a line that is only dashes (---, ----, …), tolerating whitespace.
	const blocks = text
		.split(/\n\s*-{3,}\s*\n/)
		.map((b) => b.trim())
		.filter((b) => b.length);

	const units = [];
	for (const block of blocks) {
		const lines = block.split("\n");
		let title = "";
		let subtitle = "";
		const bodyLines = [];
		for (const raw of lines) {
			const line = raw.trim();
			if (!line) continue;
			const h2 = line.match(/^##\s+(.+)$/);
			const h1 = line.match(/^#\s+(.+)$/);
			if (h2) {
				if (!subtitle) subtitle = h2[1].trim();
			} else if (h1) {
				if (!title) title = h1[1].trim();
			} else {
				bodyLines.push(line);
			}
		}
		const body = bodyLines.join(" ").trim();
		if (title || subtitle || body) {
			units.push({ title: title, subtitle: subtitle, body: body });
		}
	}
	return units;
}

/**
 * Suggests a grid layout (rows × cols) for a given number of units. Keeps grids
 * roughly landscape (cols >= rows) to match 16:9 slides. Mirrors the client-side
 * suggestLayout() in the dialog scripts.
 *
 * @param {number} n - unit count
 * @return {{rows: number, cols: number}}
 */
function suggestGridLayout_(n) {
	const table = {
		1: { rows: 1, cols: 1 },
		2: { rows: 1, cols: 2 },
		3: { rows: 1, cols: 3 },
		4: { rows: 2, cols: 2 },
		5: { rows: 2, cols: 3 },
		6: { rows: 2, cols: 3 },
		7: { rows: 3, cols: 3 },
		8: { rows: 3, cols: 3 },
		9: { rows: 3, cols: 3 },
	};
	if (n <= 0) return { rows: 1, cols: 1 };
	if (table[n]) return table[n];
	// >9: keep 3 columns, grow rows.
	return { rows: Math.ceil(n / 3), cols: 3 };
}

/**
 * Computes card rectangles (in PT) for a rows×cols grid. Columns divide the
 * usable width evenly; rows are sized to their content via `opts.rowHeight`
 * (the tallest unit) rather than stretching to fill the slide. The grid starts
 * at `opts.top` (defaulting to 100, like the Table Minter) and `opts.left`.
 *
 * @param {number} rows
 * @param {number} cols
 * @param {number} pageW - page width in PT
 * @param {number} pageH - page height in PT
 * @param {{margin?: number, gap?: number, top?: number, left?: number, rowHeight?: number}} [opts]
 * @return {Array<{x: number, y: number, w: number, h: number}>} row-major order
 */
function computeGridPositions_(rows, cols, pageW, pageH, opts) {
	const o = opts || {};
	const margin = o.margin != null ? o.margin : 30;
	const gap = o.gap != null ? o.gap : 15;
	const left = o.left != null ? o.left : margin;
	const top = o.top != null ? o.top : 100; // start like the Table Minter

	const usableW = pageW - left - margin;
	const cellW = (usableW - (cols - 1) * gap) / cols;

	// Cards are as tall as the tallest unit's content (opts.rowHeight), NOT
	// stretched to fill the slide. Clamp so the grid still fits between `top`
	// and the bottom margin; keep a small floor so sparse cards stay usable.
	const maxRowH = (pageH - top - margin - (rows - 1) * gap) / rows;
	let cellH = o.rowHeight > 0 ? o.rowHeight : maxRowH;
	cellH = Math.max(70, Math.min(cellH, maxRowH));

	const positions = [];
	for (let r = 0; r < rows; r++) {
		for (let c = 0; c < cols; c++) {
			positions.push({
				x: left + c * (cellW + gap),
				y: top + r * (cellH + gap),
				w: cellW,
				h: cellH,
			});
		}
	}
	return positions;
}

/**
 * Base font sizes (title/subtitle/body) for a card. Fixed defaults — title 18,
 * subtitle 12, body 12 — that stay put unless a card has to shrink to fit, so
 * cards size to their text rather than text growing to fill an oversized card.
 *
 * @return {{title: number, subtitle: number, body: number}}
 */
function baseFontSizes_() {
	return { title: 18, subtitle: 12, body: 12 };
}

/**
 * Estimates the natural height (PT) a unit's content needs in a card of the
 * given width, at the base font sizes plus padding. Used to pick a uniform row
 * height equal to the tallest unit.
 *
 * @param {{title: string, subtitle: string, body: string}} unit
 * @param {number} cardW - card width in PT
 * @return {number}
 */
function naturalUnitHeight_(unit, cardW) {
	const pad = 8;
	const f = baseFontSizes_();
	const innerW = Math.max(20, cardW - 2 * pad);
	// Reserve the subtitle row even when blank so cards with/without a subtitle
	// take the same height.
	const sub = unit.subtitle || " ";
	return (
		estimateBlockHeight_(
			unit.title || "",
			sub,
			unit.body || "",
			f.title,
			f.subtitle,
			f.body,
			innerW,
		) +
		2 * pad
	);
}

/**
 * Picks font sizes that fit a unit's text into a card of the given width/height.
 * Starts from the base sizes and only shrinks (body → subtitle → title) when the
 * content would overflow, down to per-role minimums.
 *
 * @param {{title: string, subtitle: string, body: string}} unit
 * @param {number} cardW - card width in PT
 * @param {number} cardH - card height in PT
 * @return {{title: number, subtitle: number, body: number, pad: number}}
 */
function fitFontSizes_(unit, cardW, cardH) {
	const pad = 8;
	const f = baseFontSizes_();
	let titleSize = f.title;
	let subSize = f.subtitle;
	let bodySize = f.body;

	const innerW = Math.max(20, cardW - 2 * pad);
	const innerH = Math.max(20, cardH - 2 * pad);

	const titleText = unit.title || "";
	const subText = unit.subtitle || " "; // reserve the blank subtitle row
	const bodyText = unit.body || "";

	// Shrink body (then subtitle, then title) until it fits or we hit the floor.
	for (let i = 0; i < 14; i++) {
		const blockH = estimateBlockHeight_(
			titleText,
			subText,
			bodyText,
			titleSize,
			subSize,
			bodySize,
			innerW,
		);
		if (blockH <= innerH) break;
		if (bodySize > 8) {
			bodySize -= 1;
		} else if (subSize > 8) {
			subSize -= 1;
		} else if (titleSize > 10) {
			titleSize -= 1;
			subSize = Math.min(subSize, Math.max(8, Math.round(titleSize * 0.7)));
			bodySize = Math.min(bodySize, Math.max(8, Math.round(titleSize * 0.78)));
		} else {
			break; // already at the floor
		}
	}

	return { title: titleSize, subtitle: subSize, body: bodySize, pad: pad };
}

/**
 * Rough estimate of the total vertical space (PT) a title/subtitle/body block
 * occupies inside a card, given font sizes and available width.
 * @return {number}
 */
function estimateBlockHeight_(
	title,
	subtitle,
	body,
	titleSize,
	subSize,
	bodySize,
	innerW,
) {
	const lineH = 1.25;
	const charsPerLine = (size) =>
		Math.max(1, Math.floor(innerW / (size * 0.55)));
	const linesFor = (text, size) =>
		text ? Math.max(1, Math.ceil(text.length / charsPerLine(size))) : 0;

	let h = 0;
	if (title) h += linesFor(title, titleSize) * titleSize * lineH + 2;
	if (subtitle) h += linesFor(subtitle, subSize) * subSize * lineH + 2;
	if (body) h += linesFor(body, bodySize) * bodySize * lineH + 2;
	return h;
}

/**
 * Pushes the Slides API requests that render one unit as a styled card into the
 * shared requests array.
 *
 * @param {Array} requests - shared batch request array
 * @param {string} pageId - target slide objectId
 * @param {{x:number,y:number,w:number,h:number}} pos - card rect in PT
 * @param {{title:string,subtitle:string,body:string}} unit
 * @param {{fillColor:string,borderColor:string,textColor:string,borderWidth:number}} style
 */
function buildUnitCardRequests_(requests, pageId, pos, unit, style) {
	const shapeId = "gridminter" + Utilities.getUuid().replace(/-/g, "");
	const sizes = fitFontSizes_(unit, pos.w, pos.h);

	// 1) The card shape itself (text box so it can hold the unit's text).
	requests.push({
		createShape: {
			objectId: shapeId,
			shapeType: "TEXT_BOX",
			elementProperties: {
				pageObjectId: pageId,
				size: {
					width: { magnitude: pos.w, unit: "PT" },
					height: { magnitude: pos.h, unit: "PT" },
				},
				transform: {
					scaleX: 1,
					scaleY: 1,
					translateX: pos.x,
					translateY: pos.y,
					unit: "PT",
				},
			},
		},
	});

	// 2) Card fill + outline from the chosen default style.
	requests.push({
		updateShapeProperties: {
			objectId: shapeId,
			shapeProperties: {
				shapeBackgroundFill: {
					solidFill: { color: { rgbColor: hexToRgbColor_(style.fillColor) } },
				},
				outline: {
					outlineFill: {
						solidFill: {
							color: { rgbColor: hexToRgbColor_(style.borderColor) },
						},
					},
					weight: { magnitude: style.borderWidth || 1, unit: "PT" },
					dashStyle: "SOLID",
				},
				contentAlignment: "TOP",
			},
			fields:
				"shapeBackgroundFill.solidFill.color,outline.outlineFill.solidFill.color,outline.weight,outline.dashStyle,contentAlignment",
		},
	});

	// 3) Assemble the text and remember each segment's char range for styling.
	// Always emit three rows (title / subtitle / body) in order. The subtitle row
	// is kept even when empty so it renders as a blank line and cards with and
	// without a subtitle line up at the same heights.
	const rolesOrder = [
		{ text: unit.title || "", role: "title" },
		{ text: unit.subtitle || "", role: "subtitle" },
		{ text: unit.body || "", role: "body" },
	];
	const segments = [];
	let combined = "";
	for (let i = 0; i < rolesOrder.length; i++) {
		if (i > 0) combined += "\n";
		const start = combined.length;
		combined += rolesOrder[i].text;
		segments.push({
			start: start,
			end: combined.length,
			role: rolesOrder[i].role,
			text: rolesOrder[i].text,
		});
	}

	if (!combined.replace(/\n/g, "").length) return; // nothing real to insert

	requests.push({
		insertText: {
			objectId: shapeId,
			insertionIndex: 0,
			text: combined,
		},
	});

	// 4) Per-segment text styling. Title & subtitle: bold, no italic, style text
	// color. Body: regular weight, black. Blank reserved lines are skipped.
	for (const seg of segments) {
		if (!seg.text.length) continue;
		const isTitle = seg.role === "title";
		const isSub = seg.role === "subtitle";
		const isBody = seg.role === "body";
		const fontSize = isTitle
			? sizes.title
			: isSub
				? sizes.subtitle
				: sizes.body;
		requests.push({
			updateTextStyle: {
				objectId: shapeId,
				textRange: {
					type: "FIXED_RANGE",
					startIndex: seg.start,
					endIndex: seg.end,
				},
				style: {
					foregroundColor: {
						opaqueColor: {
							rgbColor: hexToRgbColor_(isBody ? "#000000" : style.textColor),
						},
					},
					bold: isTitle || isSub,
					italic: false,
					fontFamily: main_font_family,
					fontSize: { magnitude: fontSize, unit: "PT" },
				},
				fields: "foregroundColor,bold,italic,fontFamily,fontSize",
			},
		});

		// Give the title and subtitle a 1.5× line height (lineSpacing is a %).
		if (isTitle || isSub) {
			requests.push({
				updateParagraphStyle: {
					objectId: shapeId,
					textRange: {
						type: "FIXED_RANGE",
						startIndex: seg.start,
						endIndex: seg.end,
					},
					style: { lineSpacing: 150 },
					fields: "lineSpacing",
				},
			});
		}
	}

	// 5) Left-align the whole card.
	requests.push({
		updateParagraphStyle: {
			objectId: shapeId,
			textRange: { type: "ALL" },
			style: { alignment: "START" },
			fields: "alignment",
		},
	});
}

/**
 * Inserts grid-unit cards onto the current slide, spilling overflow onto newly
 * appended slides. Everything is sent in a single batchUpdate.
 *
 * @param {{units: Array<{title:string,subtitle:string,body:string}>, rows: number,
 *   cols: number, styleNumber: number, left?: number, top?: number}} payload
 * @return {{success: boolean, error?: string, warnings?: string[]}}
 */
function insertGridIntoSlide(payload) {
	try {
		const p = payload || {};
		const units = p.units || [];
		if (!units.length) {
			return { success: false, error: "No units to insert." };
		}

		let rows = p.rows > 0 ? Math.floor(p.rows) : 0;
		let cols = p.cols > 0 ? Math.floor(p.cols) : 0;
		if (!rows || !cols) {
			const sug = suggestGridLayout_(units.length);
			rows = rows || sug.rows;
			cols = cols || sug.cols;
		}
		const cap = rows * cols;

		const styleNumber = p.styleNumber > 0 ? p.styleNumber : 1;
		const styles = getStyleDefinitions();
		const style = styles[styleNumber] || styles[1];

		const presentation = SlidesApp.getActivePresentation();
		const pageW = presentation.getPageWidth();
		const pageH = presentation.getPageHeight();

		// Resolve the target slide (fall back to the first slide).
		let firstSlide = null;
		try {
			firstSlide = presentation.getSelection().getCurrentPage().asSlide();
		} catch (e) {
			firstSlide = presentation.getSlides()[0];
		}
		if (!firstSlide) return { success: false, error: "No slide available." };

		const positionOpts = {};
		if (p.left != null) positionOpts.left = p.left;
		if (p.top != null) positionOpts.top = p.top;

		// Row height = the tallest unit's natural content height (uniform cards),
		// so the grid hugs its content instead of stretching to the slide bottom.
		const margin = 30;
		const gap = 15;
		const left = p.left != null ? p.left : margin;
		const cellW = (pageW - left - margin - (cols - 1) * gap) / cols;
		let contentRowH = 0;
		for (const u of units) {
			const h = naturalUnitHeight_(u, cellW);
			if (h > contentRowH) contentRowH = h;
		}
		// Add vertical breathing room so cards aren't cramped to the text.
		positionOpts.rowHeight = contentRowH + 36;

		// Chunk units into pages of `cap`. The first chunk uses the current slide;
		// later chunks each get a freshly appended blank slide.
		const requests = [];
		const warnings = [];
		let extraSlides = 0;
		for (let offset = 0; offset < units.length; offset += cap) {
			const chunk = units.slice(offset, offset + cap);
			let slide;
			if (offset === 0) {
				slide = firstSlide;
			} else {
				slide = presentation.appendSlide(SlidesApp.PredefinedLayout.BLANK);
				extraSlides++;
			}
			const pageId = slide.getObjectId();
			const positions = computeGridPositions_(
				rows,
				cols,
				pageW,
				pageH,
				positionOpts,
			);
			chunk.forEach((unit, i) => {
				buildUnitCardRequests_(requests, pageId, positions[i], unit, style);
			});
		}

		if (extraSlides > 0) {
			warnings.push(
				extraSlides +
					" 張新投影片已新增以容納多餘的 unit（每頁 " +
					cap +
					" 格）。",
			);
		}

		if (requests.length) {
			try {
				Slides.Presentations.batchUpdate({ requests }, presentation.getId());
			} catch (batchErr) {
				return { success: false, error: batchErr.message };
			}
		}

		return { success: true, warnings: warnings };
	} catch (e) {
		console.error("Error inserting grid: " + e.message);
		return { success: false, error: e.message };
	}
}

/**
 * Includes an HTML file from the specified path and evaluates any script or style blocks.
 * This is the key function that enables HTML modularization in Google Apps Script.
 *
 * @param {string} filename - The name of the HTML file to include without the .html extension
 * @return {string} The evaluated HTML content
 */
function include(filename) {
	return HtmlService.createHtmlOutputFromFile(filename).getContent();
}

/**
 * Creates and returns an HTML template from the specified file.
 * This is a wrapper around the standard HtmlService.createTemplateFromFile
 * that makes it easier to work with modular HTML files.
 *
 * @param {string} filename - The name of the HTML file to create a template from
 * @return {HtmlTemplate} The HTML template
 */
function createModularHtmlTemplate(filename) {
	const template = HtmlService.createTemplateFromFile(filename);
	template.include = include; // Add the include function to the template
	return template;
}

