/**
 * Utility functions for applying Markdown-style formatting to text in Google Slides
 */

/**
 * Applies bold formatting to text enclosed in double asterisks (**text**)
 * in the selected text elements.
 *
 * @return {boolean} True if the operation was successful
 */
function applyMarkdownBoldFormatting() {
	const selection = SlidesApp.getActivePresentation().getSelection();
	const pageElementRange = selection.getPageElementRange();

	if (!pageElementRange) {
		Logger.log("No element selected.");
		return false;
	}

	const elements = pageElementRange.getPageElements();

	elements.forEach((element) => {
		if (element.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
			const shape = element.asShape();
			const textRange = shape.getText();
			const originalText = textRange.asString();

			// Find all **text** format matches
			const matches = [...originalText.matchAll(/\*\*(.+?)\*\*/g)];

			if (matches.length === 0) {
				return; // No markdown bold formatting found in this element
			}

			let newText = "";
			let lastIndex = 0;
			const formattingRanges = [];

			matches.forEach((match) => {
				const matchStart = match.index;
				const matchEnd = match.index + match[0].length;
				const content = match[1];

				// Add text before the match
				newText += originalText.substring(lastIndex, matchStart);

				// Record the position of formatted text in the new text
				const formatStart = newText.length;
				newText += content;
				const formatEnd = newText.length;

				// Store range (end is exclusive)
				formattingRanges.push({ start: formatStart, end: formatEnd });

				lastIndex = matchEnd;
			});

			// Add remaining original text
			newText += originalText.substring(lastIndex);

			// Replace text
			shape.getText().setText(newText);

			// Get updated textRange, as setText() resets it
			const updatedTextRange = shape.getText();

			// Apply formatting
			formattingRanges.forEach(({ start, end }) => {
				const range = updatedTextRange.getRange(start, end);
				range.getTextStyle().setBold(true);

				// Check if main_color is defined in the global scope
				try {
					if (typeof main_color !== "undefined") {
						range.getTextStyle().setForegroundColor(main_color);
					}
				} catch (e) {
					// If main_color is not defined, we just skip setting the color
					Logger.log("Note: main_color not defined, skipping color formatting");
				}
			});
		}
	});

	return true;
}

/**
 * Exposes the function for use in the menu
 */
function runApplyMarkdownBoldFormatting() {
	return applyMarkdownBoldFormatting();
}

/**
 * Calculates the optimal font size based on text length
 * Uses a formula to adjust font size to fit approximately 8 lines × 36 characters per line
 *
 * @param {string} text - The text to calculate font size for
 * @return {number} The calculated font size (between 8 and 18)
 */
function getFontSize(text) {
	const N = text.length; // 字數
	const baseFont = 18; // 基準字級
	const baseCapacity = 600; // Adjusted for better visual fit

	// Use a gentler reduction curve
	return Math.max(
		12,
		Math.min(baseFont, Math.floor(baseFont * Math.pow(baseCapacity / N, 0.3))),
	);
}

/**
 * Calculates the optimal title font size based on text length
 * Linear formula: 24pt at 27 chars to 20pt at 70 chars
 *
 * @param {string} text - The title text to calculate font size for
 * @return {number} The calculated font size (between 18 and 24)
 */
function getTitleFontSize(text) {
	const N = text.length; // Character count

	// Linear formula: y = mx + b
	// Point 1: (27, 24), Point 2: (70, 20)
	// Slope: m = (20 - 24) / (70 - 27) = -4 / 43 ≈ -0.093
	// y-intercept: b = 24 - (-0.093 * 27) = 24 + 2.51 ≈ 26.51

	const slope = -4 / 43;
	const yIntercept = 26.51;

	const calculatedSize = slope * N + yIntercept;

	// Clamp between reasonable bounds
	return Math.max(18, Math.min(24, Math.round(calculatedSize)));
}

// Global alpha value for overlay transparency
const OVERLAY_ALPHA = 0.8;

/**
 * Masks an image by highlighting specific areas defined by multiple shapes.
 * Creates semi-transparent white rectangles using a grid-based approach to prevent overlaps.
 * Requires selecting multiple shapes and one image.
 * @return {boolean} True if successful, false otherwise
 */
function maskImage() {
	try {
		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();
		const currentSlide = selection.getCurrentPage();

		// Get the selected elements
		const pageElementRange = selection.getPageElementRange();

		if (!pageElementRange) {
			SlidesApp.getUi().alert(
				"No selection found. Please select shapes and an image.",
			);
			return false;
		}

		const selectedElements = pageElementRange.getPageElements();

		if (!selectedElements || selectedElements.length < 2) {
			SlidesApp.getUi().alert(
				"Please select at least one shape and one image.",
			);
			return false;
		}

		// Find which elements are shapes and which is the image
		const shapeElements = [];
		let imageElement = null;

		for (const element of selectedElements) {
			if (element.getPageElementType() === SlidesApp.PageElementType.SHAPE) {
				shapeElements.push(element.asShape());
			} else if (
				element.getPageElementType() === SlidesApp.PageElementType.IMAGE
			) {
				if (imageElement !== null) {
					SlidesApp.getUi().alert("Please select only one image.");
					return false;
				}
				imageElement = element.asImage();
			}
		}

		if (shapeElements.length === 0 || !imageElement) {
			SlidesApp.getUi().alert(
				"Please select at least one shape and exactly one image.",
			);
			return false;
		}

		// Get image dimensions and position
		const imageLeft = imageElement.getLeft();
		const imageTop = imageElement.getTop();
		const imageWidth = imageElement.getWidth();
		const imageHeight = imageElement.getHeight();

		// Validate all shapes are at least partially within the image bounds
		for (let i = 0; i < shapeElements.length; i++) {
			const shape = shapeElements[i];
			const shapeLeft = shape.getLeft();
			const shapeTop = shape.getTop();
			const shapeWidth = shape.getWidth();
			const shapeHeight = shape.getHeight();

			if (
				shapeLeft > imageLeft + imageWidth ||
				shapeLeft + shapeWidth < imageLeft ||
				shapeTop > imageTop + imageHeight ||
				shapeTop + shapeHeight < imageTop
			) {
				SlidesApp.getUi().alert(
					`Shape ${i + 1} and the image don't overlap. Please adjust their positions.`,
				);
				return false;
			}
		}

		// Use grid-based masking approach to prevent overlaps
		const overlays = createGridBasedMask(
			currentSlide,
			imageElement,
			shapeElements,
		);

		// Create an array of all elements to group (overlays and original image, but not the shapes)
		const pageElements = [imageElement, ...overlays].filter(Boolean);

		// Group all elements together
		if (pageElements.length > 1) {
			currentSlide.group(pageElements);
		}

		// Delete all shapes as they're no longer needed
		for (const shape of shapeElements) {
			shape.remove();
		}

		return true;
	} catch (error) {
		SlidesApp.getUi().alert("Error: " + error.message);
		console.log("Error in maskImage: " + error.message);
		console.log(error.stack);
		return false;
	}
}

/**
 * Creates non-overlapping mask overlays for multiple shapes on an image.
 * Uses a grid-based approach to prevent duplicate overlapping masks.
 * @param {Object} currentSlide - The current slide
 * @param {Object} imageElement - The image element to mask
 * @param {Array} shapeElements - Array of shape elements to use as masks
 * @return {Array} Array of overlay shapes created
 */
function createGridBasedMask(currentSlide, imageElement, shapeElements) {
	const overlays = [];

	// Get image boundaries
	const imageLeft = imageElement.getLeft();
	const imageTop = imageElement.getTop();
	const imageWidth = imageElement.getWidth();
	const imageHeight = imageElement.getHeight();
	const imageRight = imageLeft + imageWidth;
	const imageBottom = imageTop + imageHeight;

	// Collect all unique X and Y coordinates to create a grid (force to integers)
	const xCoordinates = [Math.round(imageLeft), Math.round(imageRight)];
	const yCoordinates = [Math.round(imageTop), Math.round(imageBottom)];

	for (const shape of shapeElements) {
		const shapeLeft = Math.round(shape.getLeft());
		const shapeTop = Math.round(shape.getTop());
		const shapeRight = Math.round(shapeLeft + shape.getWidth());
		const shapeBottom = Math.round(shapeTop + shape.getHeight());

		// Add X coordinates within image bounds
		if (
			shapeLeft > Math.round(imageLeft) &&
			shapeLeft < Math.round(imageRight)
		) {
			xCoordinates.push(shapeLeft);
		}
		if (
			shapeRight > Math.round(imageLeft) &&
			shapeRight < Math.round(imageRight)
		) {
			xCoordinates.push(shapeRight);
		}

		// Add Y coordinates within image bounds
		if (shapeTop > Math.round(imageTop) && shapeTop < Math.round(imageBottom)) {
			yCoordinates.push(shapeTop);
		}
		if (
			shapeBottom > Math.round(imageTop) &&
			shapeBottom < Math.round(imageBottom)
		) {
			yCoordinates.push(shapeBottom);
		}
	}

	// Sort and remove duplicates
	const sortedXCoords = [...new Set(xCoordinates)].sort((a, b) => a - b);
	const sortedYCoords = [...new Set(yCoordinates)].sort((a, b) => a - b);

	// Process each grid cell
	for (let i = 0; i < sortedXCoords.length - 1; i++) {
		for (let j = 0; j < sortedYCoords.length - 1; j++) {
			const cellLeft = sortedXCoords[i];
			const cellRight = sortedXCoords[i + 1];
			const cellTop = sortedYCoords[j];
			const cellBottom = sortedYCoords[j + 1];
			const cellWidth = cellRight - cellLeft;
			const cellHeight = cellBottom - cellTop;

			// Check if any shape covers this cell
			let cellCoveredByShape = false;

			for (const shape of shapeElements) {
				const shapeLeft = Math.round(shape.getLeft());
				const shapeTop = Math.round(shape.getTop());
				const shapeRight = Math.round(shapeLeft + shape.getWidth());
				const shapeBottom = Math.round(shapeTop + shape.getHeight());

				// Check if shape completely covers this cell
				if (
					shapeLeft <= cellLeft &&
					shapeRight >= cellRight &&
					shapeTop <= cellTop &&
					shapeBottom >= cellBottom
				) {
					cellCoveredByShape = true;
					break;
				}
			}

			// If cell is not covered by any shape, create a mask
			if (!cellCoveredByShape) {
				const overlay = currentSlide.insertShape(
					SlidesApp.ShapeType.RECTANGLE,
					Math.round(cellLeft),
					Math.round(cellTop),
					Math.round(cellWidth),
					Math.round(cellHeight),
				);
				overlay.getFill().setSolidFill("#FFFFFF", OVERLAY_ALPHA);
				overlay.getBorder().setWeight(0.1);
				overlay.getBorder().getLineFill().setSolidFill("#FFFFFF", 0);
				overlays.push(overlay);
			}
		}
	}

	return overlays;
}

/**
 * Content Manager Module
 *
 * Handles adding titles, body content, and speaker notes to slides
 */

/**
 * Adds content to all created slides (titles, body content, speaker notes)
 * @param {Array} createdSlides - Array of created slide objects
 * @return {boolean} Success status
 */
function addContentToSlides(createdSlides) {
	try {
		for (let i = 0; i < createdSlides.length; i++) {
			const slideObj = createdSlides[i];
			const slide = slideObj.slide;
			const info = slideObj.info;

			// Add title to all slides
			addTitleToSlide(slide, info.title, info.layout);

			// Add parent title (H2) if this is an H3 slide
			if (info.parentTitle && info.parentTitle.length > 0) {
				addParentTitleToSlide(slide, info.parentTitle);
			}

			// Add body content if it exists for TITLE_AND_BODY slides
			if (
				info.layout === "TITLE_AND_BODY" &&
				info.bodyItems &&
				info.bodyItems.length > 0
			) {
				addBodyContentToSlide(slide, info.bodyItems);
			}

			// Add code blocks if they exist
			if (info.codeBlocks && info.codeBlocks.length > 0) {
				addCodeBlocksToSlide(slide, info.codeBlocks);
			}

			// Add speaker notes if they exist
			if (info.speakerNotes && info.speakerNotes.length > 0) {
				addSpeakerNotesToSlide(slide, info.speakerNotes);
			}

			// Add footer items if they exist
			if (info.footerItems && info.footerItems.length > 0) {
				addFooterItemsToSlide(slide, info.footerItems);
			}

			// Add images if they exist
			if (info.images && info.images.length > 0) {
				addImagesToSlide(slide, info.images);
			}
		}
		return true;
	} catch (error) {
		console.error(`Error adding content to slides: ${error.message}`);
		return false;
	}
}

/**
 * Adds title to a slide using multiple fallback approaches with font sizing
 * @param {Slide} slide - The slide to add title to
 * @param {string} title - The title text
 * @param {string} layout - The slide layout (SECTION_HEADER or TITLE_AND_BODY)
 * @return {boolean} Success status
 */
function addTitleToSlide(slide, title, layout) {
	const shapes = slide.getShapes();
	let titleAdded = false;
	let titleTextRange = null;

	// First pass: Look for TITLE placeholder
	for (let j = 0; j < shapes.length; j++) {
		const shape = shapes[j];
		try {
			if (shape.getPlaceholderType() === SlidesApp.PlaceholderType.TITLE) {
				titleTextRange = shape.getText();
				titleTextRange.setText(title);
				titleAdded = true;
				break;
			}
		} catch (e) {
			Logger.log(`Error checking placeholder type: ${e.message}`);
		}
	}

	// If title wasn't added, try another approach
	if (!titleAdded) {
		try {
			const titleShape = slide.getPlaceholder(SlidesApp.PlaceholderType.TITLE);
			if (titleShape) {
				titleTextRange = titleShape.getText();
				titleTextRange.setText(title);
				titleAdded = true;
			}
		} catch (e) {
			Logger.log(`Error getting title placeholder: ${e.message}`);
		}
	}

	// If title still wasn't added, use the first text box
	if (!titleAdded) {
		for (let j = 0; j < shapes.length; j++) {
			const shape = shapes[j];
			try {
				if (shape.getShapeType() === SlidesApp.ShapeType.TEXT_BOX) {
					titleTextRange = shape.getText();
					titleTextRange.setText(title);
					titleAdded = true;
					break;
				}
			} catch (e) {
				Logger.log(`Error using text box for title: ${e.message}`);
			}
		}
	}

	// Apply title font sizing if title was added successfully
	if (titleAdded && titleTextRange) {
		try {
			// Use 36pt for H1 (SECTION_HEADER), calculated size for H2/H3
			const fontSize =
				layout === "SECTION_HEADER" ? 36 : getTitleFontSize(title);
			titleTextRange.getTextStyle().setFontSize(fontSize);
		} catch (e) {
			Logger.log(`Error applying title font size: ${e.message}`);
		}
	}

	return titleAdded;
}

/**
 * Adds body content to a slide using multiple fallback approaches
 * @param {Slide} slide - The slide to add body content to
 * @param {Array} bodyItems - Array of body text items
 * @return {boolean} Success status
 */
function addBodyContentToSlide(slide, bodyItems) {
	const shapes = slide.getShapes();
	let bodyContentAdded = false;

	// Method 1: Look for BODY placeholder by iterating through shapes
	bodyContentAdded = tryAddContentToBodyPlaceholder(shapes, bodyItems);

	// Method 2: Try getPlaceholder approach
	if (!bodyContentAdded) {
		bodyContentAdded = tryAddContentUsingGetPlaceholder(slide, bodyItems);
	}

	// Method 3: Find existing text box that's not the title
	if (!bodyContentAdded) {
		bodyContentAdded = tryAddContentToExistingTextBox(slide, shapes, bodyItems);
	}

	// Method 4: Create new text box if all else fails
	if (!bodyContentAdded) {
		bodyContentAdded = tryAddContentToNewTextBox(slide, bodyItems);
	}

	return bodyContentAdded;
}

/**
 * Tries to add content to BODY placeholder by iterating through shapes
 * @param {Array} shapes - Array of slide shapes
 * @param {Array} bodyItems - Body content items
 * @return {boolean} Success status
 */
function tryAddContentToBodyPlaceholder(shapes, bodyItems) {
	for (let j = 0; j < shapes.length; j++) {
		const shape = shapes[j];
		try {
			if (shape.getPlaceholderType() === SlidesApp.PlaceholderType.BODY) {
				addTextWithFontSizing(shape.getText(), bodyItems);
				return true;
			}
		} catch (e) {
			Logger.log(`Error checking for BODY placeholder: ${e.message}`);
		}
	}
	return false;
}

/**
 * Tries to add content using getPlaceholder method
 * @param {Slide} slide - The slide
 * @param {Array} bodyItems - Body content items
 * @return {boolean} Success status
 */
function tryAddContentUsingGetPlaceholder(slide, bodyItems) {
	try {
		const bodyShape = slide.getPlaceholder(SlidesApp.PlaceholderType.BODY);
		if (bodyShape) {
			addTextWithFontSizing(bodyShape.getText(), bodyItems);
			return true;
		}
	} catch (e) {
		Logger.log(`Error getting body placeholder: ${e.message}`);
	}
	return false;
}

/**
 * Tries to add content to existing text box that's not the title
 * @param {Slide} slide - The slide
 * @param {Array} shapes - Array of slide shapes
 * @param {Array} bodyItems - Body content items
 * @return {boolean} Success status
 */
function tryAddContentToExistingTextBox(slide, shapes, bodyItems) {
	// Get title for comparison (assuming it's already set)
	const title = getTitleFromSlide(slide);

	for (let j = 0; j < shapes.length; j++) {
		const shape = shapes[j];
		try {
			if (
				shape.getShapeType() === SlidesApp.ShapeType.TEXT_BOX &&
				shape.getText().asString() !== title
			) {
				addTextWithFontSizing(shape.getText(), bodyItems);
				return true;
			}
		} catch (e) {
			Logger.log(`Error using text box for body: ${e.message}`);
		}
	}
	return false;
}

/**
 * Creates a new text box and adds content to it
 * @param {Slide} slide - The slide
 * @param {Array} bodyItems - Body content items
 * @return {boolean} Success status
 */
function tryAddContentToNewTextBox(slide, bodyItems) {
	try {
		const slideWidth = slide.getWidth();
		const slideHeight = slide.getHeight();

		const textBox = slide.insertTextBox(
			slideWidth * 0.1, // Left position
			slideHeight * 0.3, // Top position
			slideWidth * 0.8, // Width
			slideHeight * 0.6, // Height
		);

		addTextWithFontSizing(textBox.getText(), bodyItems);
		return true;
	} catch (e) {
		Logger.log(`Error creating new text box: ${e.message}`);
	}
	return false;
}

/**
 * Adds text content to a text range with automatic font sizing
 * @param {TextRange} textRange - The text range to add content to
 * @param {Array} bodyItems - Array of text items
 */
function addTextWithFontSizing(textRange, bodyItems) {
	textRange.clear();

	// Add each body item as a paragraph
	for (let k = 0; k < bodyItems.length; k++) {
		if (k === 0) {
			textRange.setText(bodyItems[k]);
		} else {
			textRange.appendParagraph(bodyItems[k]);
		}
	}

	// Calculate and apply optimal font size
	const allBodyText = bodyItems.join("\n");
	const fontSize = getFontSize(allBodyText);
	textRange.getTextStyle().setFontSize(fontSize);
}

/**
 * Gets the title text from a slide (for comparison purposes)
 * @param {Slide} slide - The slide to get title from
 * @return {string} The title text or empty string
 */
function getTitleFromSlide(slide) {
	try {
		const titleShape = slide.getPlaceholder(SlidesApp.PlaceholderType.TITLE);
		if (titleShape) {
			return titleShape.getText().asString();
		}
	} catch (e) {
		// Fallback: try to find title in shapes
		const shapes = slide.getShapes();
		for (let i = 0; i < shapes.length; i++) {
			try {
				if (
					shapes[i].getPlaceholderType() === SlidesApp.PlaceholderType.TITLE
				) {
					return shapes[i].getText().asString();
				}
			} catch (err) {
				// Skip this shape and continue to next one
			}
		}
	}
	return "";
}

/**
 * Adds code blocks to a slide as separate text shapes
 * @param {Slide} slide - The slide to add code blocks to
 * @param {Array} codeBlocks - Array of code block objects with language and content
 * @return {boolean} Success status
 */
function addCodeBlocksToSlide(slide, codeBlocks) {
	try {
		console.log(
			`addCodeBlocksToSlide called with ${codeBlocks.length} code blocks`,
		);

		// 計算佈局參數
		const maxWidth = 620; // 最大總寬度
		const gap = 10; // code blocks 之間的間距
		const numBlocks = codeBlocks.length;
		const totalGaps = (numBlocks - 1) * gap; // 總間距
		const blockWidth = (maxWidth - totalGaps) / numBlocks; // 每個 block 的寬度

		console.log(
			`Layout: ${numBlocks} blocks, total width: ${maxWidth}, gap: ${gap}, block width: ${blockWidth}`,
		);

		for (let i = 0; i < codeBlocks.length; i++) {
			const codeBlock = codeBlocks[i];
			console.log(
				`Processing code block ${i}: language=${codeBlock.language}, content="${codeBlock.content}"`,
			);

			// 計算行數和高度
			const lines = codeBlock.content.split("\n");
			const lineCount = lines.length;
			let height = 100; // 基礎高度（5行）
			if (lineCount > 5) {
				height += (lineCount - 5) * 30; // 每多一行加30
			}

			// 水平排列位置計算
			const x = 50 + i * (blockWidth + gap); // X位置：起始位置 + 索引 * (寬度 + 間距)
			const y = 250; // 所有 blocks 使用相同的 Y 位置（同一行）

			console.log(
				`Creating shape ${i}: x=${x}, y=${y}, width=${blockWidth}, height=${height}, lines=${lineCount}`,
			);

			// Create a rectangle shape for the code block
			const codeShape = slide.insertShape(
				SlidesApp.ShapeType.RECTANGLE,
				x,
				y,
				blockWidth,
				height,
			);

			console.log("Shape created successfully");

			// Set the code content first
			const textRange = codeShape.getText();
			textRange.setText(codeBlock.content);
			console.log("Text content set");

			// Apply basic formatting - 14號字，預設字體
			const textStyle = textRange.getTextStyle();
			textStyle.setFontSize(14); // 改為14號字
			textStyle.setForegroundColor("#000000");
			console.log("Text style applied - 14pt font");

			// 設定文字靠左對齊
			try {
				textRange
					.getParagraphStyle()
					.setParagraphAlignment(SlidesApp.ParagraphAlignment.START);
				console.log("Text alignment set to left");
			} catch (alignError) {
				console.log(`Text alignment error: ${alignError.message}`);
			}

			// 設定淺灰背景和白色邊框
			try {
				codeShape.getFill().setSolidFill("#f5f5f5"); // 淺灰色背景
				console.log("Light gray background applied");
			} catch (fillError) {
				console.log(`Fill error: ${fillError.message}`);
			}

			try {
				codeShape.getBorder().setWeight(1); // 細邊框
				codeShape.getBorder().getLineFill().setSolidFill("#FFFFFF"); // 白色邊框
				console.log("Gray background with white border applied");
			} catch (borderError) {
				console.log(`Border error: ${borderError.message}`);
			}

			// Set content alignment
			try {
				codeShape.setContentAlignment(SlidesApp.ContentAlignment.TOP);
				console.log("Content alignment set");
			} catch (alignError) {
				console.log(`Alignment error: ${alignError.message}`);
			}

			console.log(`Code block ${i} created successfully`);
		}

		console.log("All code blocks processed successfully");
		return true;
	} catch (e) {
		console.error(`Error adding code blocks to slide: ${e.message}`);
		console.error(`Error stack: ${e.stack}`);
		Logger.log(`Error adding code blocks to slide: ${e.message}`);
		return false;
	}
}

/**
 * Adds parent title (H2) to H3 slides in the style of insertStyledTitleBox
