/**
 * Adds footer items to a slide (in the bottom text area)
 * @param {Slide} slide - The slide to add footer items to
 * @param {Array} footerItems - Array of footer item strings
 * @return {boolean} Success status
 */
function addFooterItemsToSlide(slide, footerItems) {
	try {
		console.log(`Adding ${footerItems.length} footer items to slide`);

		// Try to find an existing footer placeholder first
		let footerAdded = false;

		// Method 1: Look for FOOTER placeholder
		footerAdded = tryAddFooterToPlaceholder(slide, footerItems);

		// Method 2: If no footer placeholder, try to find the bottom-most text box
		if (!footerAdded) {
			footerAdded = tryAddFooterToBottomTextBox(slide, footerItems);
		}

		// Method 3: If still no success, create a new text box at the bottom
		if (!footerAdded) {
			footerAdded = createFooterTextBox(slide, footerItems);
		}

		if (footerAdded) {
			console.log("Footer items added successfully");
		} else {
			console.log("Failed to add footer items");
		}

		return footerAdded;
	} catch (e) {
		Logger.log(`Error adding footer items to slide: ${e.message}`);
		console.error(`Error adding footer items: ${e.message}`);
		return false;
	}
}

/**
 * Tries to add footer items to a FOOTER placeholder
 * @param {Slide} slide - The slide
 * @param {Array} footerItems - Footer items to add
 * @return {boolean} Success status
 */
function tryAddFooterToPlaceholder(slide, footerItems) {
	try {
		const footerShape = slide.getPlaceholder(SlidesApp.PlaceholderType.FOOTER);
		if (footerShape?.asShape) {
			const textRange = footerShape.asShape().getText();
			const footerText = footerItems.join(" • ");
			textRange.setText(footerText);

			// Style the footer text
			textRange.getTextStyle().setFontSize(10);
			textRange.getTextStyle().setForegroundColor("#666666");

			console.log("Footer added to FOOTER placeholder");
			return true;
		}
	} catch (e) {
		console.log(`Error getting footer placeholder: ${e.message}`);
	}
	return false;
}

/**
 * Tries to add footer items to the bottom-most text box
 * @param {Slide} slide - The slide
 * @param {Array} footerItems - Footer items to add
 * @return {boolean} Success status
 */
function tryAddFooterToBottomTextBox(slide, footerItems) {
	try {
		const shapes = slide.getShapes();
		let bottomMostShape = null;
		let bottomMostY = 0;

		// Find the bottom-most text box (excluding title)
		const titleText = getTitleFromSlide(slide);

		for (let i = 0; i < shapes.length; i++) {
			const shape = shapes[i];
			try {
				if (shape.getShapeType() === SlidesApp.ShapeType.TEXT_BOX) {
					const shapeText = shape.getText().asString().trim();
					// Skip if this is the title or already contains footer content
					if (shapeText === titleText || shapeText.includes("•")) {
						continue;
					}

					const top = shape.getTop();
					if (top > bottomMostY) {
						bottomMostY = top;
						bottomMostShape = shape;
					}
				}
			} catch (e) {
				// Skip this shape if we can't get its properties
			}
		}

		if (bottomMostShape) {
			const textRange = bottomMostShape.getText();
			const existingText = textRange.asString().trim();
			const footerText = footerItems.join(" • ");

			// Append footer items to existing content
			if (existingText) {
				textRange.setText(`${existingText}\n\n${footerText}`);
			} else {
				textRange.setText(footerText);
			}

			console.log("Footer added to bottom text box");
			return true;
		}
	} catch (e) {
		console.log(`Error adding footer to bottom text box: ${e.message}`);
	}
	return false;
}

/**
 * Creates a new text box at the bottom for footer items
 * @param {Slide} slide - The slide
 * @param {Array} footerItems - Footer items to add
 * @return {boolean} Success status
 */
function createFooterTextBox(slide, footerItems) {
	try {
		const slideWidth = slide.getWidth();
		const slideHeight = slide.getHeight();

		// Create footer text box at the bottom of the slide
		const footerBox = slide.insertTextBox(
			slideWidth * 0.05, // Left margin (5%)
			slideHeight * 0.9, // Near bottom (90% down)
			slideWidth * 0.9, // Width (90% of slide)
			slideHeight * 0.08, // Height (8% of slide)
		);

		// Set footer content
		const footerText = footerItems.join(" • ");
		const textRange = footerBox.getText();
		textRange.setText(footerText);

		// Style the footer text
		textRange.getTextStyle().setFontSize(10);
		textRange.getTextStyle().setForegroundColor("#666666");

		// Set paragraph alignment to center
		try {
			textRange
				.getParagraphStyle()
				.setParagraphAlignment(SlidesApp.ParagraphAlignment.CENTER);
		} catch (alignError) {
			console.log(`Footer alignment error: ${alignError.message}`);
		}

		console.log("Footer text box created at bottom of slide");
		return true;
	} catch (e) {
		console.log(`Error creating footer text box: ${e.message}`);
		return false;
	}
}

/**
 * Adds images to a slide from URLs using ![alt](url) markdown syntax
 * @param {Slide} slide - The slide to add images to
 * @param {Array} images - Array of image objects with {alt, url}
 * @return {boolean} Success status
 */
function addImagesToSlide(slide, images) {
	try {
		console.log(`Adding ${images.length} images to slide`);

		// Default position and size configuration
		const defaultLeft = 360; // X position
		const defaultTop = 30; // Y position
		const maxWidth = 325; // Max width
		const maxHeight = 300; // Max height
		const imageGap = 10; // Gap between multiple images

		for (let i = 0; i < images.length; i++) {
			const imageData = images[i];
			const url = imageData.url;
			const alt = imageData.alt || "";

			console.log(`Inserting image ${i}: alt="${alt}", url="${url}"`);

			try {
				// Calculate position for multiple images (stack vertically)
				const left = defaultLeft;
				const top = defaultTop + i * (maxHeight + imageGap);

				// Insert image with position and size constraints
				const image = slide.insertImage(url, left, top, maxWidth, maxHeight);

				// Set alt text/title for the image
				if (alt) {
					image.setTitle(alt);
					image.setDescription(alt);
				}

				console.log(`Image ${i} inserted successfully at (${left}, ${top})`);
			} catch (imgError) {
				console.error(`Error inserting image ${i}: ${imgError.message}`);
				Logger.log(
					`Error inserting image from URL "${url}": ${imgError.message}`,
				);
			}
		}

		console.log("All images processed");
		return true;
	} catch (e) {
		console.error(`Error adding images to slide: ${e.message}`);
		Logger.log(`Error adding images to slide: ${e.message}`);
		return false;
	}
}

/**
 * List Formatting Module
 *
 * Handles list type detection and applying appropriate Google Slides list presets
 */

/**
 * Applies list formatting to all TITLE_AND_BODY slides
 * @param {Array} createdSlides - Array of created slide objects
 * @return {boolean} Success status
 */
function applyListFormattingToSlides(createdSlides) {
	try {
		for (let i = 0; i < createdSlides.length; i++) {
			const slideObj = createdSlides[i];

			if (
				slideObj.info.layout === "TITLE_AND_BODY" &&
				slideObj.info.bodyItems &&
				slideObj.info.bodyItems.length > 0
			) {
				applyListFormattingToSlide(slideObj);
			}
		}
		return true;
	} catch (error) {
		console.error(`Error applying list formatting to slides: ${error.message}`);
		return false;
	}
}

/**
 * Applies list formatting to a single slide
 * @param {Object} slideObj - Slide object with slide and info properties
 * @return {boolean} Success status
 */
function applyListFormattingToSlide(slideObj) {
	try {
		const shapes = slideObj.slide.getShapes();
		let bodyFormattingApplied = false;

		// Determine the appropriate list preset based on list type
		const listPreset = getListPresetFromType(slideObj.info.listType);

		// Method 1: Look for BODY placeholder by iterating through shapes
		bodyFormattingApplied = tryApplyListFormattingToBodyPlaceholder(
			shapes,
			listPreset,
		);

		// Method 2: Try getPlaceholder approach
		if (!bodyFormattingApplied) {
			bodyFormattingApplied = tryApplyListFormattingUsingGetPlaceholder(
				slideObj.slide,
				listPreset,
			);
		}

		// Method 3: Find text boxes that aren't the title
		if (!bodyFormattingApplied) {
			bodyFormattingApplied = tryApplyListFormattingToTextBoxes(
				shapes,
				slideObj.info.title,
				listPreset,
			);
		}

		// Method 4: Fallback - manually add list markers
		if (!bodyFormattingApplied) {
			bodyFormattingApplied = tryApplyManualListFormatting(
				shapes,
				slideObj.info.title,
				slideObj.info.listType,
			);
		}

		return bodyFormattingApplied;
	} catch (error) {
		Logger.log(`Error applying list formatting to slide: ${error.message}`);
		return false;
	}
}

/**
 * Gets the appropriate Google Slides list preset for a given list type
 * @param {string} listType - "numbered", "numbered_parens", "lettered", or "bullet"
 * @return {SlidesApp.ListPreset} The appropriate list preset
 */
function getListPresetFromType(listType) {
	switch (listType) {
		case "numbered":
			return SlidesApp.ListPreset.DIGIT_ALPHA_ROMAN;
		case "numbered_parens":
			return SlidesApp.ListPreset.DIGIT_ALPHA_ROMAN_PARENS;
		case "lettered":
			return SlidesApp.ListPreset.UPPERALPHA_ALPHA_ROMAN;
		default:
			return SlidesApp.ListPreset.DISC_CIRCLE_SQUARE;
	}
}

/**
 * Tries to apply list formatting to BODY placeholder by iterating through shapes
 * @param {Array} shapes - Array of slide shapes
 * @param {SlidesApp.ListPreset} listPreset - List preset to apply
 * @return {boolean} Success status
 */
function tryApplyListFormattingToBodyPlaceholder(shapes, listPreset) {
	for (let j = 0; j < shapes.length; j++) {
		const shape = shapes[j];
		try {
			if (shape.getPlaceholderType() === SlidesApp.PlaceholderType.BODY) {
				shape.getText().getListStyle().applyListPreset(listPreset);
				return true;
			}
		} catch (e) {
			Logger.log(
				`Error checking placeholder type for list formatting: ${e.message}`,
			);
		}
	}
	return false;
}

/**
 * Tries to apply list formatting using getPlaceholder method
 * @param {Slide} slide - The slide
 * @param {SlidesApp.ListPreset} listPreset - List preset to apply
 * @return {boolean} Success status
 */
function tryApplyListFormattingUsingGetPlaceholder(slide, listPreset) {
	try {
		const bodyShape = slide.getPlaceholder(SlidesApp.PlaceholderType.BODY);
		if (bodyShape) {
			bodyShape.getText().getListStyle().applyListPreset(listPreset);
			return true;
		}
	} catch (e) {
		Logger.log(
			`Error getting body placeholder for list formatting: ${e.message}`,
		);
	}
	return false;
}

/**
 * Tries to apply list formatting to text boxes that aren't the title
 * @param {Array} shapes - Array of slide shapes
 * @param {string} title - Slide title (to exclude from formatting)
 * @param {SlidesApp.ListPreset} listPreset - List preset to apply
 * @return {boolean} Success status
 */
function tryApplyListFormattingToTextBoxes(shapes, title, listPreset) {
	for (let j = 0; j < shapes.length; j++) {
		const shape = shapes[j];
		try {
			if (shape.getShapeType() === SlidesApp.ShapeType.TEXT_BOX) {
				const text = shape.getText().asString().trim();
				// Skip if this is the title text box
				if (text !== "" && text !== title) {
					shape.getText().getListStyle().applyListPreset(listPreset);
					return true;
				}
			}
		} catch (e) {
			Logger.log(`Error applying list formatting to text box: ${e.message}`);
		}
	}
	return false;
}

/**
 * Tries to apply manual list formatting by adding list markers
 * @param {Array} shapes - Array of slide shapes
 * @param {string} title - Slide title (to exclude from formatting)
 * @param {string} listType - Type of list ("numbered", "numbered_parens", "lettered", "bullet")
 * @return {boolean} Success status
 */
function tryApplyManualListFormatting(shapes, title, listType) {
	for (let j = 0; j < shapes.length; j++) {
		const shape = shapes[j];
		try {
			if (shape.getShapeType() === SlidesApp.ShapeType.TEXT_BOX) {
				const textRange = shape.getText();
				const text = textRange.asString().trim();

				// Skip if this is the title text box
				if (text !== "" && text !== title) {
					// Clear the text box
					textRange.clear();

					// Add each line with appropriate list marker
					const lines = text.split("\n");
					for (let k = 0; k < lines.length; k++) {
						const line = lines[k].trim();
						if (line !== "") {
							const marker = getListMarkerForIndex(k, listType);
							if (k === 0) {
								textRange.setText(`${marker} ${line}`);
							} else {
								textRange.appendParagraph(`${marker} ${line}`);
							}
						}
					}

					return true;
				}
			}
		} catch (e) {
			Logger.log(`Error applying manual list formatting: ${e.message}`);
		}
	}
	return false;
}

/**
 * Gets the appropriate list marker for a given index and list type
 * @param {number} index - Zero-based index of the list item
 * @param {string} listType - Type of list ("numbered", "numbered_parens", "lettered", "bullet")
 * @return {string} The list marker
 */
function getListMarkerForIndex(index, listType) {
	switch (listType) {
		case "numbered":
			return `${(index + 1).toString()}.`;
		case "numbered_parens":
			return `(${(index + 1).toString()})`;
		case "lettered":
			// Convert index to letter (0=A, 1=B, etc.)
			return `${String.fromCharCode(65 + (index % 26))}.`;
		default:
			return "•";
	}
}

/**
 * Validates list type and returns a safe default if invalid
 * @param {string} listType - The list type to validate
 * @return {string} Valid list type ("numbered", "numbered_parens", "lettered", or "bullet")
 */
function validateListType(listType) {
	const validTypes = ["numbered", "numbered_parens", "lettered", "bullet"];
	return validTypes.includes(listType) ? listType : "bullet";
}

/**
 * Markdown Parser Module
 *
 * Handles parsing markdown text into structured slide data
 */

/**
 * Parse markdown text into a structured slide format
 * @param {string} markdownText - The markdown text to parse
 * @return {Array} Array of slide objects with layout, title, bodyItems, speakerNotes, and listType
 */
function parseMarkdownToStructure(markdownText) {
	try {
		const lines = markdownText.split("\n");
		const slideStructure = [];
		let currentSlide = null;
		let inCodeBlock = false;
		let codeBlockContent = [];
		let codeBlockLanguage = "";
		let currentH2Title = ""; // Track the current H2 title for H3 slides

		for (let i = 0; i < lines.length; i++) {
			const line = lines[i];
			const trimmedLine = line.trim();

			// Check for code block markers
			if (trimmedLine.startsWith("```")) {
				if (!inCodeBlock) {
					// Starting a code block
					inCodeBlock = true;
					// Extract language if specified (e.g., ```python or ```r)
					codeBlockLanguage = trimmedLine.substring(3).trim();
					codeBlockContent = [];
				} else {
					// Ending a code block
					inCodeBlock = false;

					// Add the code block to the current slide if it exists
					if (currentSlide && codeBlockContent.length > 0) {
						if (!currentSlide.codeBlocks) {
							currentSlide.codeBlocks = [];
						}
						currentSlide.codeBlocks.push({
							language: codeBlockLanguage,
							content: codeBlockContent.join("\n"),
						});
					}

					// Reset code block variables
					codeBlockContent = [];
					codeBlockLanguage = "";
				}
				continue; // Skip the ``` line itself
			}

			// If we're inside a code block, collect the content
			if (inCodeBlock) {
				// Preserve original line without trimming for code formatting
				codeBlockContent.push(line);
				continue;
			}

			// Skip empty lines outside of code blocks
			if (trimmedLine === "") continue;

			// Check for horizontal rule (---) as slide separator
			if (trimmedLine === "---") {
				// Skip the separator line - don't add it to any slide content
				continue;
			}
			// Check for speaker notes (> content)
			if (trimmedLine.startsWith("> ")) {
				if (currentSlide) {
					const speakerNote = trimmedLine.substring(2).trim();
					if (!currentSlide.speakerNotes) {
						currentSlide.speakerNotes = [];
					}
					currentSlide.speakerNotes.push(speakerNote);
				}
			}
			// Check for footer items (@ content)
			else if (trimmedLine.startsWith("@ ")) {
				if (currentSlide) {
					const footerItem = trimmedLine.substring(2).trim();
					if (!currentSlide.footerItems) {
						currentSlide.footerItems = [];
					}
					currentSlide.footerItems.push(footerItem);
				}
			}
			// Check for image syntax ![alt](url)
			else if (/^!\[.*?\]\(.*?\)$/.test(trimmedLine)) {
				if (currentSlide) {
					const imageMatch = trimmedLine.match(/^!\[(.*?)\]\((.*?)\)$/);
					if (imageMatch) {
						const alt = imageMatch[1] || "";
						const url = imageMatch[2];
						if (!currentSlide.images) {
							currentSlide.images = [];
						}
						currentSlide.images.push({ alt: alt, url: url });
					}
				}
			}
			// Check for H1 heading (# Heading)
			else if (trimmedLine.startsWith("# ")) {
				// Extract title and remove page numbering pattern if present
				let title = trimmedLine.substring(2).trim();
				// Remove patterns like "Page 1:" or "Page 10:" from the title
				title = title.replace(/^Page\s+\d+:\s*/i, "");

				// Create a new SECTION_HEADER slide
				currentSlide = {
					layout: "SECTION_HEADER",
					title: title,
					bodyItems: [],
					speakerNotes: [],
					codeBlocks: [],
					footerItems: [], // For @ prefixed lines
					images: [], // For ![alt](url) image syntax
				};
				slideStructure.push(currentSlide);
			}
			// Check for H2 heading (## Heading)
			else if (trimmedLine.startsWith("## ")) {
				// Extract title and remove page numbering pattern if present
				let title = trimmedLine.substring(3).trim();
				// Remove patterns like "Page 1:" or "Page 10:" from the title
				title = title.replace(/^Page\s+\d+:\s*/i, "");

				// Track this H2 title for future H3 slides
				currentH2Title = title;

				// Create a new TITLE_AND_BODY slide
				currentSlide = {
					layout: "TITLE_AND_BODY",
					title: title,
					bodyItems: [],
					speakerNotes: [],
					listType: "bullet", // Default to bullet list
					codeBlocks: [],
					footerItems: [], // For @ prefixed lines
					images: [], // For ![alt](url) image syntax
				};
				slideStructure.push(currentSlide);
			}
			// Check for H3 heading (### Heading)
			else if (trimmedLine.startsWith("### ")) {
				// Extract title and remove page numbering pattern if present
				let title = trimmedLine.substring(4).trim();
				// Remove patterns like "Page 1:" or "Page 10:" from the title
				title = title.replace(/^Page\s+\d+:\s*/i, "");

				// Create a new TITLE_AND_BODY slide with parent H2 title
				currentSlide = {
					layout: "TITLE_AND_BODY",
					title: title,
					bodyItems: [],
					speakerNotes: [],
					listType: "bullet", // Default to bullet list
					codeBlocks: [],
					footerItems: [], // For @ prefixed lines
					images: [], // For ![alt](url) image syntax
					parentTitle: currentH2Title, // Store the parent H2 title
				};
				slideStructure.push(currentSlide);
			}
			// Add content to current slide if it's a TITLE_AND_BODY
			else if (currentSlide && currentSlide.layout === "TITLE_AND_BODY") {
				// Process list items and regular text
				let content = trimmedLine;

				// Detect and set list type based on the first list item encountered
				if (currentSlide.bodyItems.length === 0) {
					if (/^\(\d+\)\s/.test(trimmedLine)) {
						currentSlide.listType = "numbered_parens";
					} else if (/^\d+\.\s/.test(trimmedLine)) {
						currentSlide.listType = "numbered";
					} else if (/^[A-Z]\.\s/.test(trimmedLine)) {
						currentSlide.listType = "lettered";
					} else if (
						trimmedLine.startsWith("- ") ||
						trimmedLine.startsWith("* ")
					) {
						currentSlide.listType = "bullet";
					}
				}

				// Remove list markers if present
				if (trimmedLine.startsWith("- ")) {
					content = trimmedLine.substring(2).trim();
				} else if (trimmedLine.startsWith("* ")) {
					content = trimmedLine.substring(2).trim();
				} else if (/^\(\d+\)\s/.test(trimmedLine)) {
					content = trimmedLine.substring(trimmedLine.indexOf(")") + 1).trim();
				} else if (/^\d+\.\s/.test(trimmedLine)) {
					content = trimmedLine.substring(trimmedLine.indexOf(".") + 1).trim();
				} else if (/^[A-Z]\.\s/.test(trimmedLine)) {
					content = trimmedLine.substring(2).trim();
				}

				currentSlide.bodyItems.push(content);
			}
		}

		return slideStructure;
	} catch (error) {
		console.error(`Error parsing markdown: ${error.message}`);
		return [];
	}
}

/**
 * Detects the list type from a markdown line
 * @param {string} line - The line to analyze
 * @return {string} - "numbered", "lettered", "numbered_parens", "bullet", or "none"
 */
function detectListType(line) {
	if (/^\(\d+\)\s/.test(line)) {
		return "numbered_parens";
	}
	if (/^\d+\.\s/.test(line)) {
		return "numbered";
	}
	if (/^[A-Z]\.\s/.test(line)) {
		return "lettered";
	}
	if (line.startsWith("- ") || line.startsWith("* ")) {
		return "bullet";
	}
	return "none";
}

/**
 * Removes list markers from a line
 * @param {string} line - The line to process
 * @return {string} - The line with list markers removed
 */
function removeListMarkers(line) {
	if (line.startsWith("- ")) {
		return line.substring(2).trim();
	}
	if (line.startsWith("* ")) {
		return line.substring(2).trim();
	}
	if (/^\(\d+\)\s/.test(line)) {
		return line.substring(line.indexOf(")") + 1).trim();
	}
	if (/^\d+\.\s/.test(line)) {
		return line.substring(line.indexOf(".") + 1).trim();
	}
	if (/^[A-Z]\.\s/.test(line)) {
		return line.substring(2).trim();
	}
	return line;
}

/**
 * Slide Creator Module
 *
 * Handles creating slides in Google Slides based on structured data
 */

/**
 * Creates slides based on the parsed markdown structure
 * @param {Array} slideStructure - Array of slide objects from parser
 * @param {Presentation} presentation - The Google Slides presentation
 * @param {number} insertIndex - Where to insert the slides
 * @return {Array} Array of created slide objects with slide reference and info
 */
function createSlidesFromStructure(slideStructure, presentation, insertIndex) {
	const createdSlides = [];
	let currentIndex = insertIndex;

	for (let i = 0; i < slideStructure.length; i++) {
		const slideInfo = slideStructure[i];

		let slide;
		if (slideInfo.layout === "SECTION_HEADER") {
			slide = presentation.insertSlide(
				currentIndex,
				SlidesApp.PredefinedLayout.SECTION_HEADER,
			);
		} else if (slideInfo.layout === "TITLE_AND_BODY") {
			slide = presentation.insertSlide(
				currentIndex,
				SlidesApp.PredefinedLayout.TITLE_AND_BODY,
			);
		}

		createdSlides.push({
			slide: slide,
			info: slideInfo,
		});

		currentIndex++;
	}

	return createdSlides;
}

/**
 * Determines the index where new slides should be inserted
 * @param {Presentation} presentation - The active presentation
 * @return {number} - The index to insert slides at
 */
function getInsertIndex(presentation) {
	try {
		const selection = presentation.getSelection();

		if (selection) {
			const currentPage = selection.getCurrentPage();
			if (currentPage) {
				// Find the index of the current slide
				const slides = presentation.getSlides();
				for (let i = 0; i < slides.length; i++) {
					if (slides[i].getObjectId() === currentPage.getObjectId()) {
						// Insert after the current slide
						return i + 1;
					}
				}
			}
		}

		// Default to the end of the presentation if we can't determine the current slide
		return presentation.getSlides().length;
	} catch (error) {
		// Default to the end of the presentation
		return presentation.getSlides().length;
	}
}

/**
 * Creates a slide with a specific layout
 * @param {Presentation} presentation - The presentation to add to
 * @param {number} index - The index to insert at
 * @param {string} layout - The layout type ("SECTION_HEADER" or "TITLE_AND_BODY")
 * @return {Slide} The created slide
 */
function createSlideWithLayout(presentation, index, layout) {
	if (layout === "SECTION_HEADER") {
		return presentation.insertSlide(
			index,
			SlidesApp.PredefinedLayout.SECTION_HEADER,
		);
	}
	if (layout === "TITLE_AND_BODY") {
		return presentation.insertSlide(
			index,
			SlidesApp.PredefinedLayout.TITLE_AND_BODY,
		);
	}
	throw new Error(`Unknown layout type: ${layout}`);
}

/**
 * Text Formatting Module
 *
 * Handles markdown text formatting: **bold**, ~strikethrough~, _italic_
 */

/**
 * Applies all markdown text formatting to slides
 * @param {Array} slides - Array of slide objects
 * @return {boolean} Success status
 */
function applyMarkdownFormattingToSlides(slides) {
	try {
		for (let i = 0; i < slides.length; i++) {
			const slide = slides[i];
			applyMarkdownFormattingToSlide(slide);
		}
		return true;
	} catch (error) {
		Logger.log(
			`Error applying markdown formatting to slides: ${error.message}`,
		);
		return false;
	}
}

/**
 * Applies markdown text formatting to a single slide
 * @param {Slide} slide - The slide to format
 * @return {boolean} Success status
 */
function applyMarkdownFormattingToSlide(slide) {
	try {
		const shapes = slide.getShapes();

		// Process each shape in the slide
		for (let j = 0; j < shapes.length; j++) {
			const shape = shapes[j];

			try {
				// Only process text boxes and placeholders
				if (
					shape.getShapeType() === SlidesApp.ShapeType.TEXT_BOX ||
					shape.getPlaceholderType
				) {
					applyMarkdownFormattingToTextRange(shape.getText());
				}
			} catch (shapeError) {
				Logger.log(`Error processing shape: ${shapeError.message}`);
			}
		}
		return true;
	} catch (error) {
		Logger.log(`Error applying markdown formatting to slide: ${error.message}`);
		return false;
	}
}

/**
 * Applies markdown text formatting to a text range
 * @param {TextRange} textRange - The text range to format
 * @return {boolean} Success status
 */
function applyMarkdownFormattingToTextRange(textRange) {
	try {
		const originalText = textRange.asString();

		// Define markdown patterns
		const patterns = [
			{ regex: /\*\*(.+?)\*\*/g, style: "bold" }, // **bold**
			{ regex: /~(.+?)~/g, style: "strikethrough" }, // ~strikethrough~
			{ regex: /_(.+?)_/g, style: "italic" }, // _italic_
		];

		// Find all formatting matches
		const allMatches = [];
		for (const pattern of patterns) {
			const matches = [...originalText.matchAll(pattern.regex)];
			for (const match of matches) {
				allMatches.push({
					start: match.index,
					end: match.index + match[0].length,
					content: match[1],
					style: pattern.style,
				});
			}
		}

		// If no matches, nothing to format
		if (allMatches.length === 0) {
			return true;
		}

		// Sort matches by position
		allMatches.sort((a, b) => a.start - b.start);

		// Build new text and collect formatting ranges
		let newText = "";
		let lastIndex = 0;
		const formattingRanges = [];

		for (const match of allMatches) {
			// Add text before the match
			newText += originalText.substring(lastIndex, match.start);

			// Record the position of formatted text in the new text
			const formatStart = newText.length;
			newText += match.content;
			const formatEnd = newText.length;

			// Store range with style info (end is exclusive)
			formattingRanges.push({
				start: formatStart,
				end: formatEnd,
				style: match.style,
			});

			lastIndex = match.end;
		}

		// Add remaining original text
		newText += originalText.substring(lastIndex);

		// Replace text
		textRange.setText(newText);

		// Apply formatting
		for (const { start, end, style } of formattingRanges) {
			try {
				const range = textRange.getRange(start, end);
				const textStyle = range.getTextStyle();

				// Apply the appropriate style
				switch (style) {
					case "bold":
						textStyle.setBold(true);
						// Apply color if main_color is available
						try {
							if (typeof main_color !== "undefined") {
								textStyle.setForegroundColor(main_color);
							}
						} catch (e) {
							// Skip color formatting if main_color not available
						}
						break;
					case "italic":
						textStyle.setItalic(true);
						break;
					case "strikethrough":
						textStyle.setStrikethrough(true);
						break;
				}
			} catch (styleError) {
				Logger.log(`Error applying ${style} formatting: ${styleError.message}`);
			}
		}

		return true;
	} catch (error) {
		Logger.log(`Error in applyMarkdownFormattingToTextRange: ${error.message}`);
		return false;
	}
}

/**
 * Processes markdown formatting for a specific text string
 * @param {string} text - The text to process
 * @return {Object} Object with cleanText and formattingInfo
 */
function processMarkdownText(text) {
	try {
		const patterns = [
			{ regex: /\*\*(.+?)\*\*/g, style: "bold" },
			{ regex: /~(.+?)~/g, style: "strikethrough" },
			{ regex: /_(.+?)_/g, style: "italic" },
		];

		const allMatches = [];
		for (const pattern of patterns) {
			const matches = [...text.matchAll(pattern.regex)];
			for (const match of matches) {
				allMatches.push({
					start: match.index,
					end: match.index + match[0].length,
					content: match[1],
					style: pattern.style,
				});
			}
		}

		// If no matches, return original text
		if (allMatches.length === 0) {
			return { cleanText: text, formattingInfo: [] };
		}

		// Sort matches by position
		allMatches.sort((a, b) => a.start - b.start);

		// Build clean text and collect formatting info
		let cleanText = "";
		let lastIndex = 0;
		const formattingInfo = [];

		for (const match of allMatches) {
			// Add text before the match
			cleanText += text.substring(lastIndex, match.start);

			// Record the position of formatted text in clean text
			const formatStart = cleanText.length;
			cleanText += match.content;
			const formatEnd = cleanText.length;

			// Store formatting info
			formattingInfo.push({
				start: formatStart,
				end: formatEnd,
				style: match.style,
			});

			lastIndex = match.end;
		}

		// Add remaining text
		cleanText += text.substring(lastIndex);

		return { cleanText, formattingInfo };
	} catch (error) {
		Logger.log(`Error processing markdown text: ${error.message}`);
		return { cleanText: text, formattingInfo: [] };
	}
}

/**
 * Applies formatting info to a text range
 * @param {TextRange} textRange - The text range to format
 * @param {Array} formattingInfo - Array of formatting objects
 * @return {boolean} Success status
 */
function applyFormattingToTextRange(textRange, formattingInfo) {
	try {
		for (const { start, end, style } of formattingInfo) {
			try {
				const range = textRange.getRange(start, end);
				const textStyle = range.getTextStyle();

				switch (style) {
					case "bold":
						textStyle.setBold(true);
						try {
							if (typeof main_color !== "undefined") {
								textStyle.setForegroundColor(main_color);
							}
						} catch (e) {
							// Skip color formatting if main_color not available
						}
						break;
					case "italic":
						textStyle.setItalic(true);
						break;
					case "strikethrough":
						textStyle.setStrikethrough(true);
						break;
				}
			} catch (styleError) {
				Logger.log(`Error applying ${style} formatting: ${styleError.message}`);
			}
		}
		return true;
	} catch (error) {
		Logger.log(`Error applying formatting to text range: ${error.message}`);
		return false;
	}
}

/**
