function addNextNumberCircle() {
	const presentation = SlidesApp.getActivePresentation();
	const slide = presentation.getSelection().getCurrentPage(); // active slide

	const pageElements = slide.getPageElements();
	const numberElements = [];

	// Step 1: Collect all elements with title "NUMBER"
	for (let i = 0; i < pageElements.length; i++) {
		const el = pageElements[i];
		if (el.getTitle && el.getTitle() === "NUMBER") {
			numberElements.push(el);
		}
	}

	// Step 2: Extract numbers from text content
	const numbers = numberElements
		.map((el) => {
			try {
				const text = el.asShape().getText().asString().trim();
				return parseInt(text, 10);
			} catch (e) {
				return null;
			}
		})
		.filter((n) => !isNaN(n));

	const maxNum = numbers.length > 0 ? Math.max(...numbers) : 0;
	const newNumber = maxNum + 1;

	// Step 3: Insert circle
	const shape = slide.insertShape(SlidesApp.ShapeType.ELLIPSE, 25, 25, 36, 36);
	shape.getText().setText(newNumber.toString());

	// Step 4: Styling
	shape.getFill().setSolidFill(main_color); // blue
	shape.getText().getTextStyle().setForegroundColor(base_color); // white
	shape.getText().getTextStyle().setFontSize(18); // set font size to 18
	shape
		.getText()
		.getParagraphStyle()
		.setParagraphAlignment(SlidesApp.ParagraphAlignment.CENTER);
	shape.setContentAlignment(SlidesApp.ContentAlignment.MIDDLE);

	// Step 5: Set title
	shape.setTitle("NUMBER");
}

/**
 * Covers the selected element with a semi-transparent white rectangle.
 * Works with any element type including images, shapes, and textboxes.
 * @return {boolean} True if successful, false otherwise
 */
function coverImageWithWhite() {
  try {
    const presentation = SlidesApp.getActivePresentation();
    const selection = presentation.getSelection();
    const currentSlide = selection.getCurrentPage();

    // Get the selected element
    const pageElementRange = selection.getPageElementRange();

    if (!pageElementRange) {
      SlidesApp.getUi().alert("No selection found. Please select an element.");
      return false;
    }

    const selectedElements = pageElementRange.getPageElements();

    if (!selectedElements || selectedElements.length === 0) {
      SlidesApp.getUi().alert("Please select at least one element.");
      return false;
    }

    // Use the first selected element
    const element = selectedElements[0];

    // Get element dimensions and position
    const elementWidth = element.getWidth();
    const elementHeight = element.getHeight();
    const left = element.getLeft();
    const top = element.getTop();

    // Create a transparent white rectangle
    const shape = currentSlide.insertShape(
      SlidesApp.ShapeType.RECTANGLE,
      left,
      top,
      elementWidth,
      elementHeight
    );

    // Set the fill to white with 50% transparency
    const fill = shape.getFill();
    fill.setSolidFill("#FFFFFF", 0.5); // White color with alpha 0.5

    // Set the border to a minimal weight and make it transparent
    shape.getBorder().setWeight(0.1); // Minimum valid weight
    shape.getBorder().getLineFill().setSolidFill("#FFFFFF", 0.3); // Transparent border

    // Send the shape to back so it's behind the element
    shape.sendBackward();

    return true;
  } catch (error) {
    SlidesApp.getUi().alert("Error: " + error.message);
    return false;
  }
}

// Utility for pasting content in the same place in Google Slides
function duplicateImageInPlace() {
  const presentation = SlidesApp.getActivePresentation();
  const selection = presentation.getSelection();
  const currentSlide = selection.getCurrentPage();

  const imageElement = validateImage(selection);
  if (!imageElement) return;

  const imgWidth = imageElement.getWidth();
  const imgHeight = imageElement.getHeight();
  const left = imageElement.getLeft();
  const top = imageElement.getTop();

  // Create a transparent white rectangle (middle layer)
  const shape = currentSlide.insertShape(
    SlidesApp.ShapeType.RECTANGLE,
    left,
    top,
    imgWidth,
    imgHeight
  );

  // Set the fill to white with 50% transparency
  const fill = shape.getFill();
  fill.setSolidFill("#FFFFFF", 0.5); // White color with alpha 0.5

  // Set the border to the same color and transparency
  shape.getBorder().setWeight(1); // 1 point border weight
  shape.getBorder().getLineFill().setSolidFill("#FFFFFF", 0.5); // White border with alpha 0.5

  // Create a new image (top layer)
  const blob = imageElement.getBlob();
  const newImage = currentSlide.insertImage(blob);
  newImage.setLeft(left);
  newImage.setTop(top);
  newImage.setWidth(imgWidth);
  newImage.setHeight(imgHeight);
}

/**
 * Validates if the selection contains an image and returns it.
 * @param {Selection} selection - The current selection in the presentation
 * @return {Image|null} The selected image element or null if not found
 */
function validateImage(selection) {
  const pageElementRange = selection.getPageElementRange();

  if (!pageElementRange) {
    SlidesApp.getUi().alert("No selection found. Please select an image.");
    return null;
  }

  const selectedElements = pageElementRange.getPageElements();

  if (!selectedElements || selectedElements.length === 0) {
    SlidesApp.getUi().alert("Please select at least one image.");
    return null;
  }

  for (const element of selectedElements) {
    if (element.getPageElementType() === SlidesApp.PageElementType.IMAGE) {
      return element.asImage();
    }
  }

  SlidesApp.getUi().alert("Selection does not contain any images.");
  return null;
}

/**
 * Self-update for cloned decks — "🔄 更新腳本 (Fetch latest)".
 *
 * Each clone pulls the latest source from the canonical GitHub repo and
 * overwrites its OWN Apps Script content via the Apps Script API
 * (projects.updateContent). No central registry, no clasp, no local machine.
 *
 * Flow: a GitHub Action builds dist/bundle.json ({version, files:[{name,type,
 * source}]}) on every push to main. This script fetches it and PUTs it to
 * https://script.googleapis.com/v1/projects/{scriptId}/content authorized with
 * ScriptApp.getOAuthToken(). The new code applies on the NEXT reload (the
 * running execution keeps the old code).
 *
 * Requirements (one-time, per Google account):
 *   - Enable "Google Apps Script API" at script.google.com/home/usersettings.
 *   - Approve the OAuth consent (adds the script.projects scope on first update).
 *
 * Reads SCRIPT_VERSION from src/util/version.js (stamped at build time).
 */

/** Base URL of the published bundle on GitHub raw. */
var SELF_UPDATE_RAW_BASE =
	"https://raw.githubusercontent.com/htlin222/lizard-gslide-module/main/dist";

/** @return {string} the installed version (git short SHA, or "dev"). */
function getInstalledVersion_() {
	return (typeof SCRIPT_VERSION !== "undefined" && SCRIPT_VERSION) || "dev";
}

/**
 * Checks GitHub for a newer version (fetches the tiny dist/version.json).
 * @return {{ok: boolean, installed: string, latest?: string,
 *   updateAvailable?: boolean, error?: string}}
 */
function checkForUpdate() {
	var installed = getInstalledVersion_();
	try {
		var res = UrlFetchApp.fetch(SELF_UPDATE_RAW_BASE + "/version.json", {
			muteHttpExceptions: true,
		});
		if (res.getResponseCode() !== 200) {
			return {
				ok: false,
				installed: installed,
				error: "version.json HTTP " + res.getResponseCode(),
			};
		}
		var latest = JSON.parse(res.getContentText()).version;
		return {
			ok: true,
			installed: installed,
			latest: latest,
			updateAvailable: !!latest && latest !== installed,
		};
	} catch (e) {
		return { ok: false, installed: installed, error: e.message };
	}
}

/** Menu handler: report whether an update is available. */
function menuCheckForUpdate() {
	var ui = SlidesApp.getUi();
	var r = checkForUpdate();
	if (!r.ok) {
		ui.alert("無法檢查更新：" + r.error);
		return;
	}
	if (r.updateAvailable) {
		ui.alert(
			"有新版本",
			"目前版本：" +
				r.installed +
				"\n最新版本：" +
				r.latest +
				"\n\n用「🔄 更新腳本」即可更新。",
			ui.ButtonSet.OK,
		);
	} else {
		ui.alert("已是最新版本（" + r.installed + "）");
	}
}

/**
 * Validates a downloaded bundle before writing it (abort BEFORE the PUT so the
 * clone is never left half-written).
 * @param {{version?: string, files?: Array}} bundle
 * @param {string} [expectedVersion] - version.json's version, for a cross-check
 * @return {{ok: boolean, error?: string}}
 */
function validateBundle_(bundle, expectedVersion) {
	if (!bundle || !bundle.files || !bundle.files.length) {
		return { ok: false, error: "files 為空" };
	}
	var manifests = 0;
	for (var i = 0; i < bundle.files.length; i++) {
		var f = bundle.files[i];
		if (!f || !f.name || !f.type || typeof f.source !== "string") {
			return { ok: false, error: "檔案項目不完整" };
		}
		if (f.name === "appsscript" && f.type === "JSON") manifests++;
	}
	if (manifests !== 1) {
		return { ok: false, error: "manifest 數量異常 (" + manifests + ")" };
	}
	if (expectedVersion && bundle.version && bundle.version !== expectedVersion) {
		return {
			ok: false,
			error:
				"版本不一致 (bundle " + bundle.version + " vs " + expectedVersion + ")",
		};
	}
	return { ok: true };
}

/**
 * Menu handler: pull the latest bundle and overwrite this project's content.
 */
function fetchLatestScript() {
	var ui = SlidesApp.getUi();

	var chk = checkForUpdate();
	if (chk.ok && !chk.updateAvailable) {
		ui.alert("已是最新版本（" + chk.installed + "）");
		return;
	}

	var resp = ui.alert(
		"更新腳本",
		"將更新到最新版" +
			(chk.latest ? "（" + chk.latest + "）" : "") +
			"。\n更新後請重新整理此頁面以套用。\n\n要繼續嗎？",
		ui.ButtonSet.OK_CANCEL,
	);
	if (resp !== ui.Button.OK) return;

	// Download the full bundle.
	var bundle;
	try {
		var res = UrlFetchApp.fetch(SELF_UPDATE_RAW_BASE + "/bundle.json", {
			muteHttpExceptions: true,
		});
		if (res.getResponseCode() !== 200) {
			ui.alert("下載失敗：bundle.json HTTP " + res.getResponseCode());
			return;
		}
		bundle = JSON.parse(res.getContentText());
	} catch (e) {
		ui.alert("下載或解析 bundle 失敗：" + e.message);
		return;
	}

	var v = validateBundle_(bundle, chk.latest);
	if (!v.ok) {
		ui.alert(
			"Bundle 驗證失敗：" + v.error + "\n（可能是 CDN 快取更新中，稍後再試）",
		);
		return;
	}

	// Overwrite this project's own content via the Apps Script API.
	var scriptId = ScriptApp.getScriptId();
	try {
		var put = UrlFetchApp.fetch(
			"https://script.googleapis.com/v1/projects/" + scriptId + "/content",
			{
				method: "put",
				contentType: "application/json",
				headers: { Authorization: "Bearer " + ScriptApp.getOAuthToken() },
				payload: JSON.stringify({ files: bundle.files }),
				muteHttpExceptions: true,
			},
		);
		var code = put.getResponseCode();
		if (code === 200) {
			ui.alert(
				"✅ 已更新到 " +
					(bundle.version || "最新版") +
					"。\n請重新整理此頁面以套用新版本。",
			);
			return;
		}
		var body = put.getContentText();
		if (code === 403 && body.indexOf("Apps Script API") !== -1) {
			ui.alert(
				"需要啟用 Apps Script API",
				"請到 script.google.com/home/usersettings 把「Google Apps Script API」開成 ON，然後再試一次。",
				ui.ButtonSet.OK,
			);
			return;
		}
		ui.alert("更新失敗（HTTP " + code + "）：\n" + body);
	} catch (e) {
		ui.alert("更新時發生錯誤：" + e.message);
	}
}

/**
 * Menu handler: install an on-open trigger that checks for updates. Simple
 * onOpen() can't use UrlFetchApp, so this uses an installable trigger.
 */
function enableUpdateOnOpenTrigger() {
	var ui = SlidesApp.getUi();
	try {
		var existing = ScriptApp.getProjectTriggers();
		for (var i = 0; i < existing.length; i++) {
			if (existing[i].getHandlerFunction() === "onOpenUpdateCheck_") {
				ui.alert("已經啟用開啟時檢查更新了。");
				return;
			}
		}
		ScriptApp.newTrigger("onOpenUpdateCheck_")
			.forPresentation(SlidesApp.getActivePresentation())
			.onOpen()
			.create();
		ui.alert("已啟用：之後開啟此簡報會自動檢查是否有新版本。");
	} catch (e) {
		ui.alert("無法啟用自動檢查：" + e.message);
	}
}

/** Menu handler: remove the on-open update-check trigger. */
function disableUpdateOnOpenTrigger() {
	var ui = SlidesApp.getUi();
	var triggers = ScriptApp.getProjectTriggers();
	var n = 0;
	for (var i = 0; i < triggers.length; i++) {
		if (triggers[i].getHandlerFunction() === "onOpenUpdateCheck_") {
			ScriptApp.deleteTrigger(triggers[i]);
			n++;
		}
	}
	ui.alert(n ? "已關閉開啟時檢查更新。" : "目前沒有啟用開啟時檢查更新。");
}

/**
 * Installable on-open handler (runs with full auth, unlike simple onOpen).
 * Quietly checks for a newer version and nudges the user. Never blocks opening.
 */
function onOpenUpdateCheck_() {
	try {
		var r = checkForUpdate();
		if (r.ok && r.updateAvailable) {
			SlidesApp.getUi().alert(
				"有新版本 " +
					r.latest +
					"（目前 " +
					r.installed +
					"）\n用「⚙ 設定與批次 → 🔄 更新腳本」即可更新。",
			);
		}
	} catch (e) {
		// Never block presentation open.
	}
}

/**
 * Server-side core for the Steps Minter (步驟鑄造器) dialog.
 *
 * Turns a list of steps (one per line: `title | desc`) into a numbered process
 * diagram on the current slide: each step is a numbered circle (1, 2, 3…) plus
 * a text box with a bold title and an optional description, arranged evenly
 * across the page (horizontal) or stacked down it (vertical), with small arrow
 * connectors between consecutive steps. Everything is grouped on insert.
 *
 * Built with the SlidesApp service (like the Callout Minter) because it needs to
 * read page geometry and group the resulting pieces afterwards.
 *
 * Exposes exactly two server functions for the dialog:
 *   - getStepsTemplates()             → templates for client-side preview
 *   - insertStepsIntoSlide(payload)   → renders + groups the steps
 */

/**
 * Single source of truth for steps templates. Colors resolve from the global
 * palette (main_color / accent_color) so they track the configured theme.
 *
 * @return {Array<{id,name,fill,numberText,titleColor,descColor,connector}>}
 */
function buildStepsTemplates_() {
	const main = (typeof main_color !== "undefined" && main_color) || "#3D6869";
	const accent =
		(typeof accent_color !== "undefined" && accent_color) || "#f29424";
	const text =
		(typeof text_color !== "undefined" && text_color) || "#000000";
	// Description text must be a readable mid-gray (matches the dialog preview's
	// #666). Do NOT use sub1_color — that's a near-white background tint
	// (#E7EAE7) and renders almost invisible on a white slide.
	const sub = "#666666";
	return [
		{
			id: "main",
			name: "MAIN",
			fill: main,
			numberText: "#FFFFFF",
			titleColor: text,
			descColor: sub,
			// Connectors are a light gray regardless of theme (read by both the
			// preview and the slide insert).
			connector: "#CCCCCC",
		},
		{
			id: "accent",
			name: "ACCENT",
			fill: accent,
			numberText: "#FFFFFF",
			titleColor: text,
			descColor: sub,
			connector: "#CCCCCC",
		},
	];
}

/**
 * Returns the steps templates for client-side preview. Called from the dialog
 * through google.script.run.
 * @return {Array<Object>}
 */
function getStepsTemplates() {
	return buildStepsTemplates_();
}

/**
 * Groq system prompt for turning free-form context into step lines.
 * Output is ONLY step lines, one per line, in EXACTLY `title | desc` format
 * (desc optional) — no preamble, explanation, or code fences.
 */
const STEPS_AI_SYSTEM_PROMPT = [
	"You convert the user's content into a numbered list of process steps.",
	"Output ONLY step lines, one per line, in EXACTLY this format:",
	"title | desc",
	"The desc part is optional (a line may be just the title).",
	"Example:",
	"收案 | 篩選符合條件的病人",
	"隨機分組 | 1:1 分配至兩組",
	"追蹤 | 每月回診評估",
	"分析 | 主要終點統計",
	"Strict rules:",
	"- No preamble, no explanation, no closing remarks, no code fences.",
	"- Output between 3 and 6 step lines.",
	"- Keep titles short (2–6 characters or words).",
	"- Keep each desc to one short phrase.",
	"- Order the steps logically.",
].join("\n");

/**
 * Generates step lines from free-form context via Groq.
 * Called from the dialog through google.script.run.
 *
 * @param {string} context - Arbitrary text the user pasted.
 * @return {{success: boolean, generatedText?: string, error?: string, needKey?: boolean}}
 */
function generateStepsFromContext(context) {
	const text = (context || "").trim();
	if (!text) {
		return { success: false, error: "No context provided." };
	}

	// Don't throw on a missing key — let the dialog show a friendly prompt to
	// run the explicit "🔑 設定 AI 金鑰 (Groq)" menu item.
	if (!hasUserApiKey()) {
		return {
			success: false,
			needKey: true,
			error:
				"No AI key set. Run 🖖 跨頁功能 → 🔑 設定 AI 金鑰 (Groq) first, then try again.",
		};
	}

	return callGroq_(STEPS_AI_SYSTEM_PROMPT, text, {
		maxTokens: 1200,
		temperature: 0.3,
	});
}

/**
 * Parses the steps textarea (one step per line, `title | desc`) into an array of
 * {title, desc}. Blank lines are ignored; the description is optional.
 *
 * @param {string} text
 * @return {Array<{title: string, desc: string}>}
 */
function parseStepsInput_(text) {
	const raw = (text || "").replace(/\r\n/g, "\n");
	const steps = [];
	raw.split("\n").forEach((line) => {
		const trimmed = line.trim();
		if (!trimmed) return;
		const parts = trimmed.split("|");
		const title = (parts[0] || "").trim();
		const desc = parts.slice(1).join("|").trim();
		if (title || desc) steps.push({ title: title, desc: desc });
	});
	return steps;
}

/**
 * Inserts a numbered steps diagram on the current slide and groups it.
 *
 * @param {{steps: Array<{title:string,desc:string}>, templateId: string,
 *   orientation: string}} payload
 * @return {{success: boolean, error?: string}}
 */
function insertStepsIntoSlide(payload) {
	try {
		const p = payload || {};
		let steps = p.steps || [];
		// Tolerate a raw text payload too.
		if (!steps.length && typeof p.text === "string") {
			steps = parseStepsInput_(p.text);
		}
		if (!steps.length) {
			return { success: false, error: "No steps to insert." };
		}

		const templates = buildStepsTemplates_();
		let tpl = templates[0];
		for (let i = 0; i < templates.length; i++) {
			if (templates[i].id === p.templateId) tpl = templates[i];
		}
		const vertical = p.orientation === "vertical";
		const font =
			(typeof main_font_family !== "undefined" && main_font_family) ||
			"Source Sans Pro";

		const presentation = SlidesApp.getActivePresentation();
		const selection = presentation.getSelection();
		let slide = null;
		try {
			slide = selection.getCurrentPage().asSlide();
		} catch (e) {
			slide = presentation.getSlides()[0];
		}
		if (!slide) return { success: false, error: "No slide available." };

		const pageW = presentation.getPageWidth();
		const pageH = presentation.getPageHeight();
		const margin = 40;
		const n = steps.length;
		const circle = 36; // numbered-circle diameter in PT

		const group = [];

		if (!vertical) {
			// Horizontal: circles in a row near the top, title+desc below each.
			const usableW = pageW - 2 * margin;
			const slotW = usableW / n;
			const topY = Math.max((pageH - 150) / 2, margin);
			const textW = Math.min(slotW - 8, 180);
			const textH = 70;

			for (let i = 0; i < n; i++) {
				const slotX = margin + i * slotW;
				const cx = slotX + slotW / 2;
				const circleX = cx - circle / 2;

				_buildStepNumberCircle_(slide, group, tpl, font, i + 1, circleX, topY, circle);

				// Text block centered under the circle.
				const tx = cx - textW / 2;
				const ty = topY + circle + 8;
				_buildStepTextBox_(
					slide,
					group,
					tpl,
					font,
					steps[i],
					tx,
					ty,
					textW,
					textH,
					SlidesApp.ParagraphAlignment.CENTER,
				);

				// Arrow connector to the next circle, vertically centered on circles.
				if (i < n - 1) {
					const nextCx = margin + (i + 1) * slotW + slotW / 2;
					// Short arrow centered in the gap (not spanning circle-to-circle).
					const leftEdge = circleX + circle;
					const rightEdge = nextCx - circle / 2;
					const gapSpan = rightEdge - leftEdge;
					const aw = Math.max(Math.min(44, gapSpan * 0.55), 14);
					const ah = 11;
					const ax = leftEdge + (gapSpan - aw) / 2;
					const ay = topY + (circle - ah) / 2;
					_buildStepConnector_(slide, group, tpl, ax, ay, aw, ah, false);
				}
			}
		} else {
			// Vertical: circles stacked down the left, title+desc to the right.
			const slotH = Math.min((pageH - 2 * margin) / n, 90);
			const startX = margin;
			const startY = margin;
			const textX = startX + circle + 14;
			const textW = Math.min(pageW - margin - textX, 360);
			const textH = slotH - 8;

			for (let i = 0; i < n; i++) {
				const slotY = startY + i * slotH;
				const circleY = slotY + (slotH - circle) / 2;

				_buildStepNumberCircle_(
					slide,
					group,
					tpl,
					font,
					i + 1,
					startX,
					circleY,
					circle,
				);

				_buildStepTextBox_(
					slide,
					group,
					tpl,
					font,
					steps[i],
					textX,
					slotY + 4,
					textW,
					textH,
					SlidesApp.ParagraphAlignment.START,
				);

				// Downward arrow connector between circles.
				if (i < n - 1) {
					const nextCircleY = startY + (i + 1) * slotH + (slotH - circle) / 2;
					// Short arrow centered in the gap (not spanning circle-to-circle).
					const topEdge = circleY + circle;
					const gapSpan = nextCircleY - topEdge;
					const ah = Math.max(Math.min(28, gapSpan * 0.55), 12);
					const aw = 11;
					const ay = topEdge + (gapSpan - ah) / 2;
					const ax = startX + (circle - aw) / 2;
					_buildStepConnector_(slide, group, tpl, ax, ay, aw, ah, true);
				}
			}
		}

		if (group.length > 1) slide.group(group);

		return { success: true };
	} catch (e) {
		console.error("Error inserting steps: " + e.message);
		return { success: false, error: e.message };
	}
}

/**
 * Builds one numbered circle (ELLIPSE with a bold white index) and pushes it
 * into the group array.
 * @private
 */
function _buildStepNumberCircle_(slide, group, tpl, font, index, x, y, size) {
	const c = slide.insertShape(SlidesApp.ShapeType.ELLIPSE, x, y, size, size);
	c.getFill().setSolidFill(tpl.fill);
	c.getBorder().getLineFill().setSolidFill(tpl.fill);
	c.getText().setText(String(index));
	c.getText()
		.getTextStyle()
		.setForegroundColor(tpl.numberText)
		.setBold(true)
		.setFontSize(16)
		.setFontFamily(font);
	c.getText()
		.getParagraphStyle()
		.setParagraphAlignment(SlidesApp.ParagraphAlignment.CENTER);
	c.setContentAlignment(SlidesApp.ContentAlignment.MIDDLE);
	group.push(c);
}

/**
 * Builds the title (bold) + desc text box for a step and pushes it into the
 * group array.
 * @private
 */
function _buildStepTextBox_(slide, group, tpl, font, step, x, y, w, h, align) {
	const box = slide.insertShape(SlidesApp.ShapeType.TEXT_BOX, x, y, w, h);
	const title = step.title || "";
	const desc = step.desc || "";
	const combined = desc ? title + "\n" + desc : title;
	const t = box.getText();
	t.setText(combined || " ");

	const titleEnd = title.length;
	if (titleEnd > 0) {
		t.getRange(0, titleEnd)
			.getTextStyle()
			.setForegroundColor(tpl.titleColor)
			.setBold(true)
			.setFontSize(14)
			.setFontFamily(font);
		// 1.5x line height on the title paragraph.
		t.getRange(0, titleEnd).getParagraphStyle().setLineSpacing(150);
	}
	if (desc) {
		const descStart = titleEnd + 1;
		const descEnd = descStart + desc.length;
		t.getRange(descStart, descEnd)
			.getTextStyle()
			.setForegroundColor(tpl.descColor)
			.setBold(false)
			.setFontSize(11)
			.setFontFamily(font);
	}
	t.getParagraphStyle().setParagraphAlignment(align);
	box.setContentAlignment(SlidesApp.ContentAlignment.TOP);
	group.push(box);
}

/**
 * Builds a small arrow connector between two steps and pushes it into the group
 * array. `down` selects a downward (vertical) vs. rightward (horizontal) arrow.
 * @private
 */
function _buildStepConnector_(slide, group, tpl, x, y, w, h, down) {
	const type = down
		? SlidesApp.ShapeType.DOWN_ARROW
		: SlidesApp.ShapeType.RIGHT_ARROW;
	const arrow = slide.insertShape(type, x, y, w, h);
	arrow.getFill().setSolidFill(tpl.connector);
	arrow.getBorder().getLineFill().setSolidFill(tpl.connector);
	group.push(arrow);
}

/**
 * Quickly styles a selected table with alternating row colors and header styling
 * Works with either a table element selection or table cell selection
 */
function fastStyleSelectedTable() {
	const selection = SlidesApp.getActivePresentation().getSelection();
	let table = null;

	// Try to get table from cell selection first
	const tableCellRange = selection.getTableCellRange();
	if (tableCellRange) {
		table = tableCellRange.getTableCells()[0].getParentTable();
	} else {
		// If no cell selection, try to get table from page element selection
		const pageElementRange = selection.getPageElementRange();
		if (pageElementRange) {
			const pageElements = pageElementRange.getPageElements();
			if (pageElements.length > 0) {
				const element = pageElements[0];
				if (element.getPageElementType() === SlidesApp.PageElementType.TABLE) {
					table = element.asTable();
				}
			}
		}
	}

	// If we still don't have a table, show an error
	if (!table) {
		SlidesApp.getUi().alert("Please select a table or table cell.");
		return;
	}

	const numRows = table.getNumRows();
	const numCols = table.getNumColumns();

	const white = base_color;
	const blue = main_color;
	const gray = "#CCCCCC";
	const black = "#000000";
	// Default border settings
	const borderColor = main_color; // White border
	const borderWidth = 0.3; // 3pt width

	for (let r = 0; r < numRows; r++) {
		const isHeader = r === 0;
		const isEven = r % 2 === 0;

		for (let c = 0; c < numCols; c++) {
			const cell = table.getCell(r, c);
			if (!cell) continue;

			// Set background color based on row
			if (isHeader) {
				cell.getFill().setSolidFill(blue);
			} else if (isEven) {
				cell.getFill().setSolidFill(gray);
			} else {
				cell.getFill().setSolidFill(base_color);
			}

			// Always set content alignment regardless of content
			cell.setContentAlignment(SlidesApp.ContentAlignment.MIDDLE);

			// Handle text styling for all cells, adding a dot to empty cells
			try {
				const text = cell.getText();

				// Check if cell is empty and add a dot if needed
				if (text && text.asString().trim() === "") {
					text.setText(".");
				}

				// Now apply styling to all cells (they all have content now)
				const textStyle = text.getTextStyle();
				if (isHeader) {
					textStyle.setForegroundColor(base_color).setBold(true);
				} else {
					textStyle.setForegroundColor(black).setBold(false);
				}

				// Set paragraph alignment for horizontal centering
				try {
					const paragraphStyle = text.getParagraphStyle();
					paragraphStyle.setParagraphAlignment(
						SlidesApp.ParagraphAlignment.CENTER,
					);
				} catch (alignError) {
					// Silently continue if paragraph alignment fails
					// This is not critical and shouldn't stop the process
				}
			} catch (e) {
				// Continue silently if text styling fails
				console.log(
					"Error styling cell at row " + r + ", column " + c + ": " + e.message,
				);
			}
		}
	}

	// Apply borders using the Advanced Slides API - different border for header row
	applyTableBordersWithHeaderRow(table, base_color, borderColor, borderWidth);
}

/**
 * Applies borders to a table using the Slides Advanced Service API
 * @param {Table} table - The table to apply borders to
 * @param {string} borderColor - The border color in hex format (e.g., '#000000')
 * @param {number} borderWeight - The border weight in points
 */
function applyTableBorders(table, borderColor, borderWeight) {
	try {
		// Convert hex color to RGB components
		const r = parseInt(borderColor.substring(1, 3), 16) / 255;
		const g = parseInt(borderColor.substring(3, 5), 16) / 255;
		const b = parseInt(borderColor.substring(5, 7), 16) / 255;

		const presentationId = SlidesApp.getActivePresentation().getId();
		const tableId = table.getObjectId();

		// Create requests for different border positions
		const borderPositions = ["ALL"]; // Can also use 'INNER', 'OUTER', 'INNER_HORIZONTAL', 'INNER_VERTICAL'

		const requests = borderPositions.map((position) => ({
			updateTableBorderProperties: {
				objectId: tableId,
				borderPosition: position,
				tableBorderProperties: {
					tableBorderFill: {
						solidFill: {
							color: {
								rgbColor: {
									red: r,
									green: g,
									blue: b,
								},
							},
						},
					},
					weight: {
						magnitude: borderWeight,
						unit: "PT", // Points
					},
					dashStyle: "SOLID",
				},
				fields: "tableBorderFill,weight,dashStyle",
			},
		}));

		// Execute the batch update
		Slides.Presentations.batchUpdate({ requests: requests }, presentationId);
		console.log("Table borders applied successfully");
	} catch (e) {
		console.error("Error applying table borders: " + e.message);
	}
}

/**
 * Applies borders to a table with special styling for the header row
 * @param {Table} table - The table to apply borders to
 * @param {string} headerBorderColor - The border color for the header row in hex format
 * @param {string} bodyBorderColor - The border color for the body rows in hex format
 * @param {number} borderWeight - The border weight in points
 */
function applyTableBordersWithHeaderRow(
	table,
	headerBorderColor,
	bodyBorderColor,
	borderWeight,
) {
	try {
		const presentationId = SlidesApp.getActivePresentation().getId();
		const tableId = table.getObjectId();

		// Log the table ID to verify we're targeting the right table
		console.log("Applying borders to table ID: " + tableId);

		// Convert header border color to RGB
		const hr = parseInt(headerBorderColor.substring(1, 3), 16) / 255;
		const hg = parseInt(headerBorderColor.substring(3, 5), 16) / 255;
		const hb = parseInt(headerBorderColor.substring(5, 7), 16) / 255;

		// Convert body border color to RGB
		const br = parseInt(bodyBorderColor.substring(1, 3), 16) / 255;
		const bg = parseInt(bodyBorderColor.substring(3, 5), 16) / 255;
		const bb = parseInt(bodyBorderColor.substring(5, 7), 16) / 255;

		// Log the colors to verify conversion
		console.log("Header border RGB: " + hr + ", " + hg + ", " + hb);
		console.log("Body border RGB: " + br + ", " + bg + ", " + bb);

		// Try a simpler approach - just set all borders to the body color
		const requests = [
			{
				updateTableBorderProperties: {
					objectId: tableId,
					borderPosition: "ALL",
					tableBorderProperties: {
						tableBorderFill: {
							solidFill: {
								color: {
									rgbColor: {
										red: br,
										green: bg,
										blue: bb,
									},
								},
							},
						},
						weight: {
							magnitude: borderWeight,
							unit: "PT",
						},
						dashStyle: "SOLID",
					},
					fields: "tableBorderFill,weight,dashStyle",
				},
			},
		];

		// Execute the batch update
		const response = Slides.Presentations.batchUpdate(
			{ requests: requests },
			presentationId,
		);
		console.log("Table borders applied successfully");
		console.log("API Response: " + JSON.stringify(response));

		// Now try a second approach for the header row - using a different method
		// Instead of using tableRange which might not be working as expected,
		// we'll try to directly style the first row using a different approach

		// First, get the current slide
		const currentSlide = SlidesApp.getActivePresentation()
			.getSelection()
			.getCurrentPage();
		if (!currentSlide) {
			console.log("Could not get current slide");
			return;
		}

		// According to the API documentation, valid border positions are: ALL, BOTTOM, INNER, INNER_HORIZONTAL, INNER_VERTICAL, LEFT, OUTER, RIGHT, TOP
		try {
			// We only want to change the vertical borders of the header row to white
			// Since the API doesn't allow targeting specific row borders directly,
			// we'll use a simpler approach - just make the vertical borders white

			// Apply white color to all INNER_VERTICAL borders
			const verticalRequests = [
				{
					updateTableBorderProperties: {
						objectId: tableId,
						borderPosition: "INNER_VERTICAL", // This affects all vertical borders between columns
						tableBorderProperties: {
							tableBorderFill: {
								solidFill: {
									color: {
										rgbColor: {
											red: 1.0, // Pure white
											green: 1.0,
											blue: 1.0,
										},
									},
								},
							},
							weight: {
								magnitude: borderWeight * 1.5, // Slightly thicker for visibility
								unit: "PT",
							},
							dashStyle: "SOLID",
						},
						fields: "tableBorderFill,weight,dashStyle",
					},
				},
			];

			// Also apply white to LEFT and RIGHT borders for completeness
			const leftRightRequests = [
				{
					updateTableBorderProperties: {
						objectId: tableId,
						borderPosition: "LEFT",
						tableBorderProperties: {
							tableBorderFill: {
								solidFill: {
									color: {
										rgbColor: {
											red: 1.0,
											green: 1.0,
											blue: 1.0,
										},
									},
								},
							},
							weight: {
								magnitude: borderWeight * 1.5,
								unit: "PT",
							},
							dashStyle: "SOLID",
						},
						fields: "tableBorderFill,weight,dashStyle",
					},
				},
				{
					updateTableBorderProperties: {
						objectId: tableId,
						borderPosition: "RIGHT",
						tableBorderProperties: {
							tableBorderFill: {
								solidFill: {
									color: {
										rgbColor: {
											red: 1.0,
											green: 1.0,
											blue: 1.0,
										},
									},
								},
							},
							weight: {
								magnitude: borderWeight * 1.5,
								unit: "PT",
							},
							dashStyle: "SOLID",
						},
						fields: "tableBorderFill,weight,dashStyle",
					},
				},
			];

			// Execute the requests
			const verticalResponse = Slides.Presentations.batchUpdate(
				{ requests: verticalRequests },
				presentationId,
			);
			console.log("Vertical borders applied successfully");

			const leftRightResponse = Slides.Presentations.batchUpdate(
				{ requests: leftRightRequests },
				presentationId,
			);
			console.log("Left and right borders applied successfully");

			// Unfortunately, the API doesn't allow us to target just the vertical borders of the header row
			// This approach changes all vertical borders to white, which should at least make them visible
			// against the header background
		} catch (headerError) {
			console.error(
				"Error applying header row borders: " + headerError.message,
			);
		}
	} catch (e) {
		console.error(
			"Error applying table borders with header styling: " + e.message,
		);
		// Try a fallback approach
		try {
			// Simple fallback - just apply a single border style to the whole table
			applyTableBorders(table, bodyBorderColor, borderWeight);
		} catch (fallbackError) {
			console.error(
				"Fallback border styling also failed: " + fallbackError.message,
			);
		}
	}
}

/**
 * Applies a complete table styling with borders and custom colors
 */
function styleTableWithBorders() {
	const selection = SlidesApp.getActivePresentation().getSelection();
	const pageElementRange = selection.getPageElementRange();

	if (!pageElementRange) {
		SlidesApp.getUi().alert("Please select a table.");
		return;
	}

	const pageElements = pageElementRange.getPageElements();

	if (pageElements.length === 0) {
		SlidesApp.getUi().alert("No elements selected.");
		return;
	}

	const element = pageElements[0];
	if (element.getPageElementType() !== SlidesApp.PageElementType.TABLE) {
		SlidesApp.getUi().alert("Please select a table.");
		return;
	}

	const table = element.asTable();
	const numRows = table.getNumRows();
	const numCols = table.getNumColumns();

	// Define colors
	const headerBg = "#1E88E5"; // Blue
	const headerText = "#FFFFFF"; // White
	const evenRowBg = "#FFFFFF"; // White
	const oddRowBg = "#F5F5F5"; // Light gray
	const textColor = "#212121"; // Dark gray
	const borderColor = "#616161"; // Medium gray
	const borderWeight = 1; // 1pt

	// Style cells
	for (let r = 0; r < numRows; r++) {
		const isHeader = r === 0;
		const isEven = r % 2 === 0;

		for (let c = 0; c < numCols; c++) {
			const cell = table.getCell(r, c);
			const text = cell.getText();
			const textStyle = text.getTextStyle();

			if (isHeader) {
				cell.getFill().setSolidFill(headerBg);
				textStyle.setForegroundColor(headerText).setBold(true);
			} else if (isEven) {
				cell.getFill().setSolidFill(evenRowBg);
				textStyle.setForegroundColor(textColor).setBold(false);
			} else {
				cell.getFill().setSolidFill(oddRowBg);
				textStyle.setForegroundColor(textColor).setBold(false);
			}
		}
	}

	// Apply borders
	applyTableBorders(table, borderColor, borderWeight);
}

/**
 * Server-side AI helper for the Table Minter dialog.
 *
 * Turns arbitrary user "context" (notes, data, a paragraph, CSV, …) into a
 * clean Markdown table using Groq. The key never leaves the server: this calls
 * callGroq_() in aiKey.js, which reads the user's stored key server-side.
 *
 * The client (src/components/table-minter) is responsible for robustly
 * extracting just the table block from the returned text — LLMs sometimes wrap
 * it in prose like "Here is your markdown:" or code fences.
 */

const TABLE_MINTER_SYSTEM_PROMPT = [
	"You convert the user's content into a titled Markdown table.",
	"Output EXACTLY this, in order, and nothing else:",
	"1. One title line that starts with '# Table: ' followed by a short descriptive title.",
	"2. Then ONE GitHub-Flavored Markdown table (header row, separator row, data rows).",
	"Strict rules:",
	"- No explanation, no preamble, no closing remarks, no code fences.",
	"- The first line MUST start with '# Table: '.",
	"- The first character of the table MUST be a pipe '|'.",
	"- Put labels/categories in the first column when the data has that shape.",
	"- Keep cell text concise; do not invent data that isn't implied by the input.",
	"- Use a single space of padding inside cells.",
].join("\n");

/**
 * Generates a Markdown table from free-form context via Groq.
 * Called from the dialog through google.script.run.
 *
 * @param {string} context - Arbitrary text the user pasted.
 * @return {{success: boolean, generatedText?: string, error?: string, needKey?: boolean}}
 */
function generateTableMarkdownFromContext(context) {
	const text = (context || "").trim();
	if (!text) {
		return { success: false, error: "No context provided." };
	}

	// Don't throw on a missing key — let the dialog show a friendly prompt to
	// run the explicit "🔑 設定 AI 金鑰 (Groq)" menu item.
	if (!hasUserApiKey()) {
		return {
			success: false,
			needKey: true,
			error:
				"No AI key set. Run 🖖 跨頁功能 → 🔑 設定 AI 金鑰 (Groq) first, then try again.",
		};
	}

	return callGroq_(TABLE_MINTER_SYSTEM_PROMPT, text, {
		maxTokens: 2000,
		temperature: 0.2,
	});
}

/**
 * Converts "#RRGGBB" to an API rgbColor object (components in 0..1).
 * @param {string} hex
 * @return {{red: number, green: number, blue: number}}
 */
function hexToRgbColor_(hex) {
	const h = (hex || "#000000").replace("#", "");
	return {
		red: parseInt(h.substring(0, 2), 16) / 255,
		green: parseInt(h.substring(2, 4), 16) / 255,
		blue: parseInt(h.substring(4, 6), 16) / 255,
	};
}

/**
 * Builds one updateTableBorderProperties request.
 * @param {string} tableId
 * @param {Object|null} range - TableRange, or null for the whole table.
 * @param {string} position - ALL | INNER_HORIZONTAL | TOP | BOTTOM | ...
 * @param {string} hex - border color
 * @param {number} weight - PT
 * @param {number} alpha - 0..1 (0 hides the border)
 * @return {Object}
 */
function tableBorderRequest_(tableId, range, position, hex, weight, alpha) {
	const req = {
		updateTableBorderProperties: {
			objectId: tableId,
			borderPosition: position,
			tableBorderProperties: {
				tableBorderFill: {
					solidFill: { color: { rgbColor: hexToRgbColor_(hex) }, alpha: alpha },
				},
				weight: { magnitude: weight, unit: "PT" },
				dashStyle: "SOLID",
			},
			fields: "tableBorderFill,weight,dashStyle",
		},
	};
	if (range) req.updateTableBorderProperties.tableRange = range;
	return req;
}

/**
 * Inserts a styled table onto the current slide at an exact position via the
 * Slides API — the alternative to clipboard paste when position matters.
 *
 * Mirrors the clipboard look: transparent fill, left-aligned text, header in
 * the accent color with thick accent strokes top & bottom, thin gray lines
 * between/under body rows, all body text black.
 *
 * @param {{header: string[], body: string[][], theme: string, fontSize: number,
 *   widthPx: number, left: number, top: number, title: string}} payload
 * @return {{success: boolean, error?: string}}
 */
function insertTableIntoSlide(payload) {
	try {
		const p = payload || {};
		const header = p.header || [];
		const body = p.body || [];
		if (!header.length) {
			return { success: false, error: "No table to insert." };
		}

		const theme = p.theme || main_color;
		const fontSize = p.fontSize > 0 ? p.fontSize : 14;
		const leftPt = p.left != null ? p.left : 25;
		const topPt = p.top != null ? p.top : 100;
		// Pasted px widths are read by Slides at 96dpi; convert to points to match.
		const widthPt = p.widthPx > 0 ? p.widthPx * 0.75 : 636;
		const rowHeightPt = fontSize + 14;

		const numRows = body.length + 1;
		const numCols = header.length;
		const totalHeight = numRows * rowHeightPt;

		// Resolve the target slide (fall back to the first slide).
		const presentation = SlidesApp.getActivePresentation();
		let slide = null;
		try {
			slide = presentation.getSelection().getCurrentPage().asSlide();
		} catch (e) {
			slide = presentation.getSlides()[0];
		}
		if (!slide) return { success: false, error: "No slide available." };

		// Optional title text box above the table; the table is pushed down by
		// the title's height + a small gap so they don't overlap.
		const titleText = (p.title || "").trim();
		let tableTop = topPt;
		if (titleText) {
			const titleFontSize = fontSize;
			const titleHeight = Math.round(titleFontSize * 1.6) + 4;
			const gap = 8;
			const box = slide.insertTextBox(
				titleText,
				leftPt,
				topPt,
				widthPt,
				titleHeight,
			);
			try {
				box.setContentAlignment(SlidesApp.ContentAlignment.MIDDLE);
				const tt = box.getText();
				tt.getTextStyle()
					.setFontFamily(main_font_family)
					.setFontSize(titleFontSize)
					.setBold(true)
					.setForegroundColor("#000000");
				tt.getParagraphStyle().setParagraphAlignment(
					SlidesApp.ParagraphAlignment.START,
				);
			} catch (titleErr) {
				// Styling failure shouldn't block the table insert.
			}
			tableTop = topPt + titleHeight + gap;
		}

		// Build EVERYTHING — table, text, borders, column widths — into one
		// batchUpdate so it applies as a single instant change instead of
		// styling visibly step by step. (Created objects are available to later
		// requests within the same batch, so createTable can come first.)
		const pageId = slide.getObjectId();
		const tableId = "tblminter" + Utilities.getUuid().replace(/-/g, "");
		const headerRange = {
			location: { rowIndex: 0, columnIndex: 0 },
			rowSpan: 1,
			columnSpan: numCols,
		};
		const gray = "#CCCCCC";
		const rows = [header].concat(body);

		const requests = [
			{
				createTable: {
					objectId: tableId,
					elementProperties: {
						pageObjectId: pageId,
						size: {
							width: { magnitude: widthPt, unit: "PT" },
							height: { magnitude: totalHeight, unit: "PT" },
						},
						transform: {
							scaleX: 1,
							scaleY: 1,
							translateX: leftPt,
							translateY: tableTop,
							unit: "PT",
						},
					},
					rows: numRows,
					columns: numCols,
				},
			},
			{
				updateTableCellProperties: {
					objectId: tableId,
					tableRange: {
						location: { rowIndex: 0, columnIndex: 0 },
						rowSpan: numRows,
						columnSpan: numCols,
					},
					tableCellProperties: { contentAlignment: "MIDDLE" },
					fields: "contentAlignment",
				},
			},
		];

		// Cell text + per-cell styling.
		for (let r = 0; r < numRows; r++) {
			const isHeader = r === 0;
			for (let c = 0; c < numCols; c++) {
				const value = (rows[r] && rows[r][c]) || "";
				if (!value) continue;
				const cellLocation = { rowIndex: r, columnIndex: c };
				requests.push({
					insertText: {
						objectId: tableId,
						cellLocation: cellLocation,
						insertionIndex: 0,
						text: value,
					},
				});
				requests.push({
					updateTextStyle: {
						objectId: tableId,
						cellLocation: cellLocation,
						textRange: { type: "ALL" },
						style: {
							foregroundColor: {
								opaqueColor: {
									rgbColor: hexToRgbColor_(isHeader ? theme : "#000000"),
								},
							},
							bold: isHeader,
							fontFamily: main_font_family,
							fontSize: { magnitude: fontSize, unit: "PT" },
						},
						fields: "foregroundColor,bold,fontFamily,fontSize",
					},
				});
				requests.push({
					updateParagraphStyle: {
						objectId: tableId,
						cellLocation: cellLocation,
						textRange: { type: "ALL" },
						style: { alignment: "START" },
						fields: "alignment",
					},
				});
			}
		}

		// Borders: hide all, then thin gray row lines everywhere, and ONLY the
		// top of the header gets the thick accent stroke. The header's bottom
		// (2nd line) stays thin gray like every other row separator.
		requests.push(tableBorderRequest_(tableId, null, "ALL", "#FFFFFF", 1, 0));
		requests.push(
			tableBorderRequest_(tableId, null, "INNER_HORIZONTAL", gray, 0.75, 1),
		);
		requests.push(tableBorderRequest_(tableId, null, "BOTTOM", gray, 0.75, 1));
		requests.push(tableBorderRequest_(tableId, headerRange, "TOP", theme, 1.5, 1));

		// Proportional column widths summing to the requested total width.
		const weights = [];
		for (let c = 0; c < numCols; c++) {
			let max = 1;
			for (let r = 0; r < numRows; r++) {
				const len = ((rows[r] && rows[r][c]) || "").length;
				if (len > max) max = len;
			}
			weights.push(max);
		}
		const weightSum = weights.reduce((a, b) => a + b, 0);
		for (let c = 0; c < numCols; c++) {
			requests.push({
				updateTableColumnProperties: {
					objectId: tableId,
					columnIndices: [c],
					tableColumnProperties: {
						columnWidth: {
							magnitude: Math.max(40, (widthPt * weights[c]) / weightSum),
							unit: "PT",
						},
					},
					fields: "columnWidth",
				},
			});
		}

		try {
			Slides.Presentations.batchUpdate({ requests }, presentation.getId());
		} catch (batchErr) {
			return { success: false, error: batchErr.message };
		}

		return { success: true };
	} catch (e) {
		console.error("Error inserting table: " + e.message);
		return { success: false, error: e.message };
	}
}

/**
 * Server-side core for the Takeaways Minter dialog (重點摘要 / Key Takeaways 鑄造器).
 *
 * Turns a heading + a list of key points (one per line, `title | desc` with the
 * description optional) into a styled "key takeaways" block on the current
 * slide: a bold, larger heading in the theme color, followed by the points
 * rendered either as numbered cards (a grid of cards, each with a number badge +
 * title + description) or as a vertical checkmark list (✓ + title + description).
 *
 * Mirrors the Grid Minter pattern (src/util/grid_minter.js):
 *  - Card layout reuses grid-style positioning (computeGridPositions_-style math).
 *  - Insertion batches every request into a single Slides.Presentations.batchUpdate.
 *  - Colors resolve from the global palette (main_color / accent_color) so they
 *    track the configured theme.
 *
 * The point line format (also documented in the dialog):
 *   First takeaway | a short supporting description
 *   Second takeaway
 *   ...
 * One point per line; the description after the first "|" is optional.
 */

/**
 * Single source of truth for takeaways templates. Each template chooses a render
 * style (numbered cards vs. checkmark list) and a color theme (main / accent /
 * green) that drives the accent color, card fill/border, and the number/check
 * badge styling. Colors resolve from the global palette so they track the theme.
 *
 * style: 'numbered' = grid of cards with a number badge; 'checklist' = vertical
 * list with a ✓ marker per row.
 *
 * @return {Array<{id,name,style,accent,cardFill,cardBorder,badgeFill,badgeText,titleText,descText}>}
 */
function buildTakeawaysTemplates_() {
	const main = (typeof main_color !== "undefined" && main_color) || "#3D6869";
	const accent =
		(typeof accent_color !== "undefined" && accent_color) || "#f29424";
	const green = "#2E7D32";

	function theme(idBase, nameBase, style, color, cardFill, cardBorder) {
		return {
			id: idBase,
			name: nameBase,
			style: style,
			accent: color,
			cardFill: cardFill,
			cardBorder: cardBorder,
			badgeFill: color,
			badgeText: "#FFFFFF",
			titleText: color,
			descText: "#333333",
		};
	}

	return [
		// Numbered cards — three color themes.
		theme("numbered-main", "Numbered · Main", "numbered", main, "#FFFFFF", main),
		theme(
			"numbered-accent",
			"Numbered · Accent",
			"numbered",
			accent,
			"#FFFFFF",
			accent,
		),
		theme(
			"numbered-green",
			"Numbered · Green",
			"numbered",
			green,
			"#FFFFFF",
			green,
		),
		// Colored cards (filled background) — numbered, three themes.
		{
			id: "card-main",
			name: "Colored Card · Main",
			style: "numbered",
			accent: main,
			cardFill: "#E7EAE7",
			cardBorder: main,
			badgeFill: main,
			badgeText: "#FFFFFF",
			titleText: main,
			descText: "#333333",
		},
		{
			id: "card-accent",
			name: "Colored Card · Accent",
			style: "numbered",
			accent: accent,
			cardFill: "#FCEAD2",
			cardBorder: accent,
			badgeFill: accent,
			badgeText: "#FFFFFF",
			titleText: "#B26A00",
			descText: "#333333",
		},
		{
			id: "card-green",
			name: "Colored Card · Green",
			style: "numbered",
			accent: green,
			cardFill: "#E7F4EC",
			cardBorder: green,
			badgeFill: green,
			badgeText: "#FFFFFF",
			titleText: green,
			descText: "#333333",
		},
		// Checkmark list — three color themes.
		theme(
			"check-main",
			"Checklist · Main",
			"checklist",
			main,
			"#FFFFFF",
			main,
		),
		theme(
			"check-accent",
			"Checklist · Accent",
			"checklist",
			accent,
			"#FFFFFF",
			accent,
		),
		theme(
			"check-green",
			"Checklist · Green",
			"checklist",
			green,
			"#FFFFFF",
			green,
		),
	];
}

/**
 * Returns the takeaways templates for client-side preview. Called from the dialog
 * through google.script.run.
 * @return {Array<Object>}
 */
function getTakeawaysTemplates() {
	return buildTakeawaysTemplates_();
}

/**
 * Groq system prompt for turning free-form context into takeaway points.
 * Output is ONLY key-point lines, one per line, in the exact `title | desc`
 * format the points textarea expects (the description after "|" is optional).
 */
var TAKEAWAYS_AI_SYSTEM_PROMPT = [
	"You convert the user's content into a short list of key takeaways.",
	"Output ONLY the key-point lines and nothing else.",
	"Each line is ONE takeaway in the EXACT format: title | desc",
	"- 'title' is a short label (1–4 words).",
	"- ' | desc' is ONE concise supporting phrase; the description is optional.",
	"Example output:",
	"更快 | 交付時間從數週縮短到數天",
	"更穩 | 自動化檢查減少回歸錯誤",
	"可擴充 | 不需重寫即可承載十倍流量",
	"Strict rules:",
	"- No preamble, no explanation, no closing remarks, no code fences.",
	"- Produce between 3 and 5 takeaways.",
	"- Keep titles short; give each at most one concise description phrase.",
	"- Do not invent facts that aren't implied by the input.",
].join("\n");

/**
 * Generates takeaway point lines (`title | desc`, one per line) from free-form
 * context via Groq. Called from the dialog through google.script.run.
 *
 * @param {string} context - Arbitrary text the user pasted.
 * @return {{success: boolean, generatedText?: string, error?: string, needKey?: boolean}}
 */
function generateTakeawaysFromContext(context) {
	const text = (context || "").trim();
	if (!text) {
		return { success: false, error: "No context provided." };
	}

	// Don't throw on a missing key — let the dialog show a friendly prompt to
	// run the explicit "🔑 設定 AI 金鑰 (Groq)" menu item.
	if (!hasUserApiKey()) {
		return {
			success: false,
			needKey: true,
			error:
				"No AI key set. Run 🖖 跨頁功能 → 🔑 設定 AI 金鑰 (Groq) first, then try again.",
		};
	}

	return callGroq_(TAKEAWAYS_AI_SYSTEM_PROMPT, text, {
		maxTokens: 1500,
		temperature: 0.3,
	});
}

/**
 * Parses the points textarea into an array of {title, desc}. One point per line;
 * the title and an optional description are separated by the first "|".
 *
 * @param {string} text
 * @return {Array<{title: string, desc: string}>}
 */
function parseTakeawayPoints_(text) {
	const raw = (text || "").replace(/\r\n/g, "\n");
	const points = [];
	const lines = raw.split("\n");
	for (let i = 0; i < lines.length; i++) {
		const line = lines[i].trim();
		if (!line) continue;
		const idx = line.indexOf("|");
		let title;
		let desc;
		if (idx >= 0) {
			title = line.slice(0, idx).trim();
			desc = line.slice(idx + 1).trim();
		} else {
			title = line;
			desc = "";
		}
		if (title || desc) points.push({ title: title, desc: desc });
	}
	return points;
}

/**
 * Suggests a column count for numbered cards given a point count. Keeps grids
 * roughly landscape to match 16:9 slides.
 *
 * @param {number} n
 * @return {number} column count
 */
function suggestTakeawaysCols_(n) {
	if (n <= 1) return 1;
	if (n === 2) return 2;
	if (n === 4) return 2;
	if (n <= 9) return 3;
	return 3;
}

/**
 * Pushes the Slides API requests for the heading text box into the shared
 * requests array, and returns the heading's bottom Y (PT) so the points block
 * can start beneath it.
 *
 * @param {Array} requests - shared batch request array
 * @param {string} pageId
 * @param {string} heading
 * @param {Object} tpl - resolved template
 * @param {{left:number, top:number, width:number}} box
 * @return {number} the Y (PT) just below the heading
 */
function buildHeadingRequests_(requests, pageId, heading, tpl, box) {
	const font =
		(typeof main_font_family !== "undefined" && main_font_family) ||
		"Source Sans Pro";
	const headingH = 40;
	const shapeId = "takeawayhead" + Utilities.getUuid().replace(/-/g, "");

	requests.push({
		createShape: {
			objectId: shapeId,
			shapeType: "TEXT_BOX",
			elementProperties: {
				pageObjectId: pageId,
				size: {
					width: { magnitude: box.width, unit: "PT" },
					height: { magnitude: headingH, unit: "PT" },
				},
				transform: {
					scaleX: 1,
					scaleY: 1,
					translateX: box.left,
					translateY: box.top,
					unit: "PT",
				},
			},
		},
	});
	requests.push({
		insertText: { objectId: shapeId, insertionIndex: 0, text: heading },
	});
	requests.push({
		updateTextStyle: {
			objectId: shapeId,
			textRange: { type: "ALL" },
			style: {
				foregroundColor: {
					opaqueColor: { rgbColor: hexToRgbColor_(tpl.accent) },
				},
				bold: true,
				fontFamily: font,
				fontSize: { magnitude: 24, unit: "PT" },
			},
			fields: "foregroundColor,bold,fontFamily,fontSize",
		},
	});
	requests.push({
		updateParagraphStyle: {
			objectId: shapeId,
			textRange: { type: "ALL" },
			style: { alignment: "START" },
			fields: "alignment",
		},
	});

	return box.top + headingH + 12;
}

/**
 * Pushes the Slides API requests rendering one numbered card (number badge +
 * title + description) into the shared requests array.
 *
 * @param {Array} requests
 * @param {string} pageId
 * @param {{x:number,y:number,w:number,h:number}} pos
 * @param {number} number - 1-based card number
 * @param {{title:string,desc:string}} point
 * @param {Object} tpl - resolved template
 */
function buildNumberedCardRequests_(requests, pageId, pos, number, point, tpl) {
	const font =
		(typeof main_font_family !== "undefined" && main_font_family) ||
		"Source Sans Pro";
	const uid = Utilities.getUuid().replace(/-/g, "");
	const cardId = "takeawaycard" + uid;
	const badgeId = "takeawaybadge" + uid;

	// 1) Card shape (text box holding the title + description).
	requests.push({
		createShape: {
			objectId: cardId,
			shapeType: "TEXT_BOX",
			elementProperties: {
				pageObjectId: pageId,
				size: {
					width: { magnitude: pos.w, unit: "PT" },
					height: { magnitude: pos.h, unit: "PT" },
				},
				transform: {
					scaleX: 1,
					scaleY: 1,
					translateX: pos.x,
					translateY: pos.y,
					unit: "PT",
				},
			},
		},
	});
	requests.push({
		updateShapeProperties: {
			objectId: cardId,
			shapeProperties: {
				shapeBackgroundFill: {
					solidFill: { color: { rgbColor: hexToRgbColor_(tpl.cardFill) } },
				},
				outline: {
					outlineFill: {
						solidFill: { color: { rgbColor: hexToRgbColor_(tpl.cardBorder) } },
					},
					weight: { magnitude: 1, unit: "PT" },
					dashStyle: "SOLID",
				},
				contentAlignment: "TOP",
			},
			fields:
				"shapeBackgroundFill.solidFill.color,outline.outlineFill.solidFill.color,outline.weight,outline.dashStyle,contentAlignment",
		},
	});

	// Card text: title (bold, theme color) + description (regular). Leave room at
	// the top for the number badge that floats above-left of the card.
	const title = point.title || "";
	const desc = point.desc || "";
	let combined = title;
	const titleEnd = combined.length;
	if (desc) combined += "\n" + desc;

	if (combined.length) {
		requests.push({
			insertText: { objectId: cardId, insertionIndex: 0, text: combined },
		});
		if (titleEnd > 0) {
			requests.push({
				updateTextStyle: {
					objectId: cardId,
					textRange: { type: "FIXED_RANGE", startIndex: 0, endIndex: titleEnd },
					style: {
						foregroundColor: {
							opaqueColor: { rgbColor: hexToRgbColor_(tpl.titleText) },
						},
						bold: true,
						fontFamily: font,
						fontSize: { magnitude: 14, unit: "PT" },
					},
					fields: "foregroundColor,bold,fontFamily,fontSize",
				},
			});
		}
		if (desc) {
			requests.push({
				updateTextStyle: {
					objectId: cardId,
					textRange: {
						type: "FIXED_RANGE",
						startIndex: titleEnd + 1,
						endIndex: combined.length,
					},
					style: {
						foregroundColor: {
							opaqueColor: { rgbColor: hexToRgbColor_(tpl.descText) },
						},
						bold: false,
						fontFamily: font,
						fontSize: { magnitude: 11, unit: "PT" },
					},
					fields: "foregroundColor,bold,fontFamily,fontSize",
				},
			});
		}
		requests.push({
			updateParagraphStyle: {
				objectId: cardId,
				textRange: { type: "ALL" },
				style: { alignment: "START" },
				fields: "alignment",
			},
		});
	}

	// 2) Number badge — a small circle floating at the card's top-left corner.
	const badgeD = 24;
	requests.push({
		createShape: {
			objectId: badgeId,
			shapeType: "ELLIPSE",
			elementProperties: {
				pageObjectId: pageId,
				size: {
					width: { magnitude: badgeD, unit: "PT" },
					height: { magnitude: badgeD, unit: "PT" },
				},
				transform: {
					scaleX: 1,
					scaleY: 1,
					translateX: pos.x - badgeD / 2,
					translateY: pos.y - badgeD / 2,
					unit: "PT",
				},
			},
		},
	});
	requests.push({
		updateShapeProperties: {
			objectId: badgeId,
			shapeProperties: {
				shapeBackgroundFill: {
					solidFill: { color: { rgbColor: hexToRgbColor_(tpl.badgeFill) } },
				},
				outline: {
					outlineFill: {
						solidFill: { color: { rgbColor: hexToRgbColor_(tpl.badgeFill) } },
					},
					weight: { magnitude: 1, unit: "PT" },
					dashStyle: "SOLID",
				},
				contentAlignment: "MIDDLE",
			},
			fields:
				"shapeBackgroundFill.solidFill.color,outline.outlineFill.solidFill.color,outline.weight,outline.dashStyle,contentAlignment",
		},
	});
	requests.push({
		insertText: { objectId: badgeId, insertionIndex: 0, text: String(number) },
	});
	requests.push({
		updateTextStyle: {
			objectId: badgeId,
			textRange: { type: "ALL" },
			style: {
				foregroundColor: {
					opaqueColor: { rgbColor: hexToRgbColor_(tpl.badgeText) },
				},
				bold: true,
				fontFamily: font,
				fontSize: { magnitude: 12, unit: "PT" },
			},
			fields: "foregroundColor,bold,fontFamily,fontSize",
		},
	});
	requests.push({
		updateParagraphStyle: {
			objectId: badgeId,
			textRange: { type: "ALL" },
			style: { alignment: "CENTER" },
			fields: "alignment",
		},
	});

	return [cardId, badgeId];
}

/**
 * Pushes the Slides API requests rendering one checkmark list row (✓ + title +
 * description) into the shared requests array.
 *
 * @param {Array} requests
 * @param {string} pageId
 * @param {{x:number,y:number,w:number,h:number}} pos
 * @param {{title:string,desc:string}} point
 * @param {Object} tpl - resolved template
 */
function buildChecklistRowRequests_(requests, pageId, pos, point, tpl) {
	const font =
		(typeof main_font_family !== "undefined" && main_font_family) ||
		"Source Sans Pro";
	const uid = Utilities.getUuid().replace(/-/g, "");
	const checkId = "takeawaycheck" + uid;
	const textId = "takeawayrow" + uid;
	const checkW = 24;
	const gap = 8;

	// 1) Check marker (✓ in the accent color).
	requests.push({
		createShape: {
			objectId: checkId,
			shapeType: "TEXT_BOX",
			elementProperties: {
				pageObjectId: pageId,
				size: {
					width: { magnitude: checkW, unit: "PT" },
					height: { magnitude: pos.h, unit: "PT" },
				},
				transform: {
					scaleX: 1,
					scaleY: 1,
					translateX: pos.x,
					translateY: pos.y,
					unit: "PT",
				},
			},
		},
	});
	requests.push({
		insertText: { objectId: checkId, insertionIndex: 0, text: "✓" },
	});
	requests.push({
		updateTextStyle: {
			objectId: checkId,
			textRange: { type: "ALL" },
			style: {
				foregroundColor: {
					opaqueColor: { rgbColor: hexToRgbColor_(tpl.accent) },
				},
				bold: true,
				fontFamily: font,
				fontSize: { magnitude: 16, unit: "PT" },
			},
			fields: "foregroundColor,bold,fontFamily,fontSize",
		},
	});
	requests.push({
		updateParagraphStyle: {
			objectId: checkId,
			textRange: { type: "ALL" },
			style: { alignment: "START" },
			fields: "alignment",
		},
	});

	// 2) Title + description text box to the right of the check.
	const textX = pos.x + checkW + gap;
	const textW = Math.max(40, pos.w - checkW - gap);
	requests.push({
		createShape: {
			objectId: textId,
			shapeType: "TEXT_BOX",
			elementProperties: {
				pageObjectId: pageId,
				size: {
					width: { magnitude: textW, unit: "PT" },
					height: { magnitude: pos.h, unit: "PT" },
				},
				transform: {
					scaleX: 1,
					scaleY: 1,
					translateX: textX,
					translateY: pos.y,
					unit: "PT",
				},
			},
		},
	});

	const title = point.title || "";
	const desc = point.desc || "";
	let combined = title;
	const titleEnd = combined.length;
	if (desc) combined += "\n" + desc;

	if (combined.length) {
		requests.push({
			insertText: { objectId: textId, insertionIndex: 0, text: combined },
		});
		if (titleEnd > 0) {
			requests.push({
				updateTextStyle: {
					objectId: textId,
					textRange: { type: "FIXED_RANGE", startIndex: 0, endIndex: titleEnd },
					style: {
						foregroundColor: {
							opaqueColor: { rgbColor: hexToRgbColor_(tpl.titleText) },
						},
						bold: true,
						fontFamily: font,
						fontSize: { magnitude: 14, unit: "PT" },
					},
					fields: "foregroundColor,bold,fontFamily,fontSize",
				},
			});
		}
		if (desc) {
			requests.push({
				updateTextStyle: {
					objectId: textId,
					textRange: {
						type: "FIXED_RANGE",
						startIndex: titleEnd + 1,
						endIndex: combined.length,
					},
					style: {
						foregroundColor: {
							opaqueColor: { rgbColor: hexToRgbColor_(tpl.descText) },
						},
						bold: false,
						fontFamily: font,
						fontSize: { magnitude: 11, unit: "PT" },
					},
					fields: "foregroundColor,bold,fontFamily,fontSize",
				},
			});
		}
		requests.push({
			updateParagraphStyle: {
				objectId: textId,
				textRange: { type: "ALL" },
				style: { alignment: "START" },
				fields: "alignment",
			},
		});
	}

	return [checkId, textId];
}

/**
 * Inserts a "key takeaways" block (heading + points) onto the current slide.
 * Everything is sent in a single batchUpdate. The pieces are grouped per row /
 * card and the whole block (heading + points) is grouped together at the end.
 *
 * @param {{heading: string, points: Array<{title:string,desc:string}>,
 *   templateId: string}} payload
 * @return {{success: boolean, error?: string}}
 */
function insertTakeawaysIntoSlide(payload) {
	try {
		const p = payload || {};
		const points = (p.points || []).filter(function (pt) {
			return pt && (pt.title || pt.desc);
		});
		if (!points.length) {
			return { success: false, error: "No takeaway points to insert." };
		}

		const templates = buildTakeawaysTemplates_();
		let tpl = templates[0];
		for (let i = 0; i < templates.length; i++) {
			if (templates[i].id === p.templateId) tpl = templates[i];
		}

		const heading =
			(p.heading != null ? String(p.heading).trim() : "") || "Key Takeaways";

		const presentation = SlidesApp.getActivePresentation();
		const pageW = presentation.getPageWidth();

		// Resolve the target slide (fall back to the first slide).
		let slide = null;
		try {
			slide = presentation.getSelection().getCurrentPage().asSlide();
		} catch (e) {
			slide = presentation.getSlides()[0];
		}
		if (!slide) return { success: false, error: "No slide available." };
		const pageId = slide.getObjectId();

		const margin = 40;
		const top = 70;
		const blockLeft = margin;
		const blockWidth = pageW - 2 * margin;

		const requests = [];
		const allIds = [];

		// Heading.
		const pointsTop = buildHeadingRequests_(requests, pageId, heading, tpl, {
			left: blockLeft,
			top: top,
			width: blockWidth,
		});

		if (tpl.style === "checklist") {
			// Vertical list of rows.
			const rowH = 46;
			const rowGap = 8;
			points.forEach(function (point, i) {
				const pos = {
					x: blockLeft,
					y: pointsTop + i * (rowH + rowGap),
					w: blockWidth,
					h: rowH,
				};
				const ids = buildChecklistRowRequests_(
					requests,
					pageId,
					pos,
					point,
					tpl,
				);
				ids.forEach(function (id) {
					allIds.push(id);
				});
			});
		} else {
			// Numbered cards laid out on a grid (grid-style positioning).
			const cols = suggestTakeawaysCols_(points.length);
			const gap = 16;
			const cardW = (blockWidth - (cols - 1) * gap) / cols;
			const cardH = 90;
			points.forEach(function (point, i) {
				const r = Math.floor(i / cols);
				const c = i % cols;
				const pos = {
					x: blockLeft + c * (cardW + gap),
					y: pointsTop + 12 + r * (cardH + gap),
					w: cardW,
					h: cardH,
				};
				const ids = buildNumberedCardRequests_(
					requests,
					pageId,
					pos,
					i + 1,
					point,
					tpl,
				);
				ids.forEach(function (id) {
					allIds.push(id);
				});
			});
		}

		if (requests.length) {
			try {
				Slides.Presentations.batchUpdate({ requests }, presentation.getId());
			} catch (batchErr) {
				return { success: false, error: batchErr.message };
			}
		}

		return { success: true };
	} catch (e) {
		console.error("Error inserting takeaways: " + e.message);
		return { success: false, error: e.message };
	}
}

